        // 按使用次数排序操作
        function sortOperationsByUsage() {
            const operations = Object.entries(operationStats)
                .map(([id, count]) => ({ id, count }))
                .sort((a, b) => b.count - a.count);
            return operations;
        }
        
        // 更新常用操作列表
        function updateCommonOperationsList() {
            const sortedOperations = sortOperationsByUsage();
            const container = document.getElementById('commonOperationsList');
            if (container) {
                const operationNames = {
                    'project-hub': '项目中心',
                    'file-wizard': '项目管理',
                    'single-table-query': '单表查询',
                    'file-analysis': '文件分析',
                    'single-table-stats': '单表统计',
                    'worksheet-analysis': '工作表分析',
                    'multi-table-query': '多表查询',
                    'data-masking': '数据脱敏',
                    'dc-field': '字段格式清洗',
                    'dc-quality': '数据质量清洗',
                    'dc-verify': '业务规则验证',
                    'data-compare': '差异比对',
                    'batch-process': '批量处理'
                };
                
                container.innerHTML = sortedOperations.map(op => `
                    <div class="sidebar-item" data-operation="${op.id}" onclick="switchTab('${op.id}')">
                        <div class="sidebar-item-content">
                            <div class="sidebar-item-name">${operationNames[op.id] || op.id}</div>
                        </div>
                        <div class="sidebar-item-count">${op.count}</div>
                    </div>
                `).join('');
            }
        }
        
        // 向导步骤导航
        function nextStep(currentStep) {
            if (currentStep < wizardMaxSteps) {
                // 单表查询：切换步骤前缓存当前选择（避免字段列表刷新导致丢勾选）
                try {
                    const active = document.querySelector('.tab-content[style*="block"]')?.id || '';
                    if (active === 'single-table-query') window.__stqRuntimeSettings = collectStqSettingsAll();
                } catch (_) { }
                // 单表查询：进入 Step3 前更新“查询预览”
                if (currentStep === 2) {
                    try { updateSingleTableQueryPreview(); } catch (_) { }
                }
                const root = document.getElementById('single-table-query') || document;
                root.querySelector(`.step[data-step="${currentStep}"]`)?.classList.remove('active');
                root.querySelector(`.step[data-step="${currentStep}"]`)?.classList.add('completed');
                
                root.querySelector(`#step${currentStep}`)?.classList.remove('active');
                
                currentWizardStep = currentStep + 1;
                root.querySelector(`.step[data-step="${currentWizardStep}"]`)?.classList.add('active');
                root.querySelector(`#step${currentWizardStep}`)?.classList.add('active');
                try { updateStqBottomBar(); } catch (_) { }
            }
        }
        
        function prevStep(currentStep) {
            if (currentStep > 1) {
                try {
                    const active = document.querySelector('.tab-content[style*="block"]')?.id || '';
                    if (active === 'single-table-query') window.__stqRuntimeSettings = collectStqSettingsAll();
                } catch (_) { }
                const root = document.getElementById('single-table-query') || document;
                root.querySelector(`.step[data-step="${currentStep}"]`)?.classList.remove('active');
                
                root.querySelector(`#step${currentStep}`)?.classList.remove('active');
                
                currentWizardStep = currentStep - 1;
                root.querySelector(`.step[data-step="${currentWizardStep}"]`)?.classList.remove('completed');
                root.querySelector(`.step[data-step="${currentWizardStep}"]`)?.classList.add('active');
                root.querySelector(`#step${currentWizardStep}`)?.classList.add('active');
                try { updateStqBottomBar(); } catch (_) { }
            }
        }

        // 单表查询：跳转到指定步骤（用于“执行完自动进入查看结果”）
        function gotoStqStep(step) {
            const n = Number(step || 1);
            if (!n || n < 1) return;
            // 仅在单表查询页面可见时处理
            const stqTab = document.getElementById('single-table-query');
            if (!stqTab || stqTab.style.display !== 'block') return;

            // 最大步数按当前单表查询定义（4）
            const max = 4;
            const target = Math.max(1, Math.min(max, n));

            // step navigation
            for (let i = 1; i <= max; i++) {
                const stepEl = stqTab.querySelector(`.step[data-step="${i}"]`);
                const content = stqTab.querySelector(`#step${i}`);
                if (stepEl) {
                    stepEl.classList.toggle('active', i === target);
                    stepEl.classList.toggle('completed', i < target);
                }
                if (content) content.classList.toggle('active', i === target);
            }
            currentWizardStep = target;
            try { updateStqBottomBar(); } catch (_) { }
        }

        // ========= 向导重置：重新打开默认回到第一页 =========
        function resetWizardSteps(rootId, stepPrefix, contentPrefix, maxSteps, setStepValue) {
            const root = document.getElementById(rootId);
            if (!root) return;
            // 根据实际步数自动校正步骤条连线两端对齐
            try {
                const nav = root.querySelector('.step-navigation');
                if (nav) {
                    const n = nav.querySelectorAll('.step').length || maxSteps || 4;
                    nav.style.setProperty('--step-count', String(Math.max(2, n)));
                }
            } catch (_) { }
            try { if (typeof setStepValue === 'function') setStepValue(1); } catch (_) { }
            for (let i = 1; i <= maxSteps; i++) {
                const stepEl = root.querySelector(`[data-step="${stepPrefix}${i}"]`);
                const content = root.querySelector(`#${contentPrefix}${i}`);
                if (stepEl) {
                    stepEl.classList.toggle('active', i === 1);
                    stepEl.classList.toggle('completed', false);
                }
                if (content) content.classList.toggle('active', i === 1);
            }
        }

        function resetStqWizard() {
            const stq = document.getElementById('single-table-query');
            if (!stq) return;
            currentWizardStep = 1;
            // 复位步骤与内容
            try { gotoStqStep(1); } catch (_) { }
            // 隐藏结果卡片，避免再次打开时残留上次结果
            try {
                const card = stq.querySelector('#queryResultCard');
                if (card) card.style.display = 'none';
                const info = stq.querySelector('#queryResultInfo');
                if (info) info.innerHTML = '';
            } catch (_) { }
            try { updateStqBottomBar(); } catch (_) { }
        }
        
