        // 执行查询（通用：单表向导/执行SQL页/SQL编辑器页）
        function executeQuery() {
            // 1) 若处于“单表查询向导 Step3”，优先使用向导生成SQL
            const stqTab = document.getElementById('single-table-query');
            let sql = '';
            if (stqTab && stqTab.style.display === 'block' && (currentWizardStep || 1) >= 3) {
                try {
                    // 每次执行：自动覆盖保存【临时模板】
                    try { saveTempTemplate('stq', collectStqSettingsAll()); } catch (_) { }
                    updateSingleTableQueryPreview(false);
                    // 优先执行“脚本框”的当前内容（允许手工编辑）
                    const ta = document.getElementById('stqQuerySqlText');
                    sql = (ta && ta.value ? ta.value.trim() : (window.__stqSql || '')).trim();
                    window.__lastQueryTarget = 'stq';
                } catch (_) { }
            }

            // 2) 兼容：优先取“执行SQL界面”的编辑器，其次取“SQL编辑器页面”的编辑器
            if (!sql) {
                const gen = document.getElementById('sqlEditor');
                const adv = document.getElementById('sqlEditorTextarea');
                if (gen && gen.value && gen.value.trim()) {
                    sql = gen.value.trim();
                    window.__lastQueryTarget = 'sql-generator';
                } else if (adv && adv.value && adv.value.trim()) {
                    sql = adv.value.trim();
                    window.__lastQueryTarget = 'sql-editor';
                } else {
                    sql = '';
                }
            }

            if (!sql) {
                alert('请输入SQL语句');
                return;
            }

            // 仅允许 SELECT
            if (!isSelectOnlySql(sql)) {
                alert('当前仅允许执行 SELECT 查询（包含 WITH ... SELECT）。\n不允许多语句/写入/DDL。');
                return;
            }

            // SQL实验室：执行前写入历史（pending），并携带 requestId 便于回写状态
            let requestId = '';
            let source = '';
            try {
                const target = window.__lastQueryTarget || '';
                if (target === 'sql-generator') {
                    requestId = String(addSqlToHistory(sql));
                    window.__lastSqlGeneratorRequestId = requestId;
                    source = 'sql-generator';
                }
            } catch (_) { }

            if (!ensureSqliteMode('查询')) return;
            window.chrome.webview.postMessage({ action: 'executeQuery', sql: sql, dbType: 'sqlite', requestId, source });
        }

        // 从“单表查询/多表查询”复用 SQL → 跳转到分拆（SQL模式）
        function stqGoSplit() {
            const sql = (window.__stqSqlBase || buildSingleTableQuerySql?.() || '').trim();
            if (!sql) { alert('暂无可用SQL：请先在单表查询生成并锁定SQL'); return; }
            jumpToSplitBySql(sql, 'stspt');
        }
        function mtqGoSplit() {
            try { updateMtqPreview(); } catch (_) { }
            const sql = (window.__mtqSqlBase || '').trim();
            if (!sql) { alert('暂无可用SQL：请先在多表查询生成SQL'); return; }
            jumpToSplitBySql(sql, 'mtspt');
        }

        function stsGoSplit() {
            const sql = (window.__stsSqlBase || document.getElementById('stsQuerySqlText')?.value || '').trim();
            if (!sql) { alert('暂无可用SQL：请先在单表统计生成SQL'); return; }
            jumpToSplitBySql(sql, 'stspt');
        }

        function mtsGoSplit() {
            const sql = (window.__mtsSqlBase || document.getElementById('mtsQuerySqlText')?.value || '').trim();
            if (!sql) { alert('暂无可用SQL：请先在多表统计生成SQL'); return; }
            // 多表统计的 SQL 同样是结果集，可直接分拆
            jumpToSplitBySql(sql, 'stspt');
        }

        function sqlEditorGoSplit() {
            const sql = (window.__sqlEditor && typeof window.__sqlEditor.getValue === 'function')
                ? (window.__sqlEditor.getValue() || '').trim()
                : (document.getElementById('sqlEditorTextarea')?.value || '').trim();
            if (!sql) { alert('暂无可用SQL：请先输入 SQL'); return; }
            jumpToSplitBySql(sql, 'stspt');
        }

        function sqlGenGoSplit() {
            const sql = (document.getElementById('sqlEditor')?.value || '').trim();
            if (!sql) { alert('暂无可用SQL：请先输入 SQL'); return; }
            jumpToSplitBySql(sql, 'stspt');
        }
        function jumpToSplitBySql(sql, hintTarget) {
            // 统一跳转到“单表分拆”页（SQL结果集分拆），达到“合并两种分拆”的目标
            switchTab('single-table-split');
            // 选中 SQL 模式
            try {
                document.querySelectorAll('input[name="stsptSourceMode"]').forEach(r => { r.checked = (r.value === 'sql'); });
                const ta = document.getElementById('stsptSourceSql');
                if (ta) ta.value = sql;
                stsptOnSourceModeChanged();
                requestSplitPreview('stspt');
            } catch (_) { }
            try { setStatusMessage('已从查询向导带入SQL：请在分拆页选择“分拆字段”并执行'); } catch (_) { }
        }

        // 数据分拆页：如果当前就是 SQL 模式，则用当前 SQL 做预览统计
        function stsptUseCurrentSqlAndPreview() {
            try {
                document.querySelectorAll('input[name="stsptSourceMode"]').forEach(r => { r.checked = (r.value === 'sql'); });
                stsptOnSourceModeChanged();
                requestSplitPreview('stspt');
            } catch (_) { }
        }

        // “执行SQL”页：按钮兼容（原页面绑定的是 executeSql）
        function executeSql() {
            // 兼容：旧“执行SQL”页已合并到 SQL 实验室（SQL编辑器）
            try {
                const ta = document.getElementById('sqlEditor');
                const sql = (ta && ta.value ? ta.value : '').trim();
                if (!sql) { alert('请输入SQL语句'); return; }
                switchTab('sql-editor');
                // 填入 SQL 实验室并执行（带历史、分页、性能保护）
                try { sqlEditorSetText(sql); } catch (_) { }
                setTimeout(() => { try { executeSqlEditor(); } catch (_) { } }, 0);
            } catch (e) {
                alert('执行失败：' + (e?.message || e));
            }
        }
        
