        // 多表关联查询向导步骤导航
        function nextMultiTableQueryStep(currentStep) {
            if (currentStep < 6) {
                document.querySelector(`.step[data-step="mtq${currentStep}"]`).classList.remove('active');
                document.querySelector(`.step[data-step="mtq${currentStep}"]`).classList.add('completed');
                document.getElementById(`step-mtq${currentStep}`).classList.remove('active');
                
                const nextStep = currentStep + 1;
                document.querySelector(`.step[data-step="mtq${nextStep}"]`).classList.add('active');
                document.getElementById(`step-mtq${nextStep}`).classList.add('active');
            }
        }
        
        function prevMultiTableQueryStep(currentStep) {
            if (currentStep > 1) {
                document.querySelector(`.step[data-step="mtq${currentStep}"]`).classList.remove('active');
                document.getElementById(`step-mtq${currentStep}`).classList.remove('active');
                
                const prevStep = currentStep - 1;
                document.querySelector(`.step[data-step="mtq${prevStep}"]`).classList.remove('completed');
                document.querySelector(`.step[data-step="mtq${prevStep}"]`).classList.add('active');
                document.getElementById(`step-mtq${prevStep}`).classList.add('active');
            }
        }
        
        // 添加关联表
