        function dsReviewExportHtml() {
            const b = window.__dsReviewBundle || {};
            if (!b.coverage && !b.strength && !b.sample) { alert('暂无可导出的审查结果'); return; }
            const esc = (s) => String(s ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
            const now = new Date();
            const title = `脱敏审查报告（${now.toISOString().slice(0,19).replace('T',' ')}）`;
            const sec = (h, inner) => `<h2 style="margin:14px 0 8px 0; font-size:12pt;">${esc(h)}</h2>${inner}`;
            const kv = (k,v)=>`<div style="margin:2px 0;"><b>${esc(k)}：</b>${esc(v)}</div>`;
            const renderCoverage = () => {
                const c = b.coverage;
                if (!c) return `<div style="color:#6c757d;">（未执行覆盖审查）</div>`;
                const cols = Array.isArray(c.columns) ? c.columns : [];
                const miss = cols.filter(x => !x.matched);
                const hi = cols.filter(x => x.risk === 'high' && !x.matched);
                const rows = cols.map(x => `<tr>
                    <td>${esc(x.column)}</td><td>${x.matched?'<span style="color:#198754;">命中</span>':'<span style="color:#cf1322;">未命中</span>'}</td>
                    <td>${esc(x.risk||'')}</td><td>${esc(x.dataType||'')}</td><td>${esc(x.action||'')}</td>
                </tr>`).join('');
                return `
                  ${kv('表', c.table || '')}
                  ${kv('模板', c.templateId || '')}
                  ${kv('未命中列', miss.length)}
                  ${kv('高风险未命中列', hi.length)}
                  <table style="width:100%; border-collapse:collapse; font-size:9pt; margin-top:8px;">
                    <thead><tr style="background:#f5f5f5;">
                      <th style="border:1px solid #e1e4e8; padding:6px;">列名</th>
                      <th style="border:1px solid #e1e4e8; padding:6px;">覆盖</th>
                      <th style="border:1px solid #e1e4e8; padding:6px;">风险</th>
                      <th style="border:1px solid #e1e4e8; padding:6px;">类型</th>
                      <th style="border:1px solid #e1e4e8; padding:6px;">动作</th>
                    </tr></thead>
                    <tbody>${rows || ''}</tbody>
                  </table>
                `;
            };
            const renderStrength = () => {
                const s = b.strength;
                if (!s) return `<div style="color:#6c757d;">（未执行强度审查）</div>`;
                const issues = Array.isArray(s.issues) ? s.issues : [];
                const rows = issues.map(it => `<tr>
                    <td>${esc(it.level||'')}</td>
                    <td>${esc(it.message||'')}</td>
                    <td>${esc(it.rule?.columnName||'')}</td>
                    <td>${esc(it.rule?.dataType||'')}</td>
                    <td>${esc(it.rule?.action||'')}</td>
                </tr>`).join('');
                return `
                  ${kv('模板', s.templateId || '')}
                  ${kv('规则数', s.ruleCount || 0)}
                  ${kv('问题数', issues.length)}
                  <table style="width:100%; border-collapse:collapse; font-size:9pt; margin-top:8px;">
                    <thead><tr style="background:#f5f5f5;">
                      <th style="border:1px solid #e1e4e8; padding:6px;">等级</th>
                      <th style="border:1px solid #e1e4e8; padding:6px;">问题</th>
                      <th style="border:1px solid #e1e4e8; padding:6px;">列</th>
                      <th style="border:1px solid #e1e4e8; padding:6px;">类型</th>
                      <th style="border:1px solid #e1e4e8; padding:6px;">动作</th>
                    </tr></thead>
                    <tbody>${rows || '<tr><td colspan="5" style="border:1px solid #e1e4e8; padding:6px; color:#6c757d;">无</td></tr>'}</tbody>
                  </table>
                `;
            };
            const renderSample = () => {
                const s = b.sample;
                if (!s) return `<div style="color:#6c757d;">（未执行残留抽检）</div>`;
                const hits = s.hits || {};
                const rows = Object.keys(hits).map(k => `<tr><td>${esc(k)}</td><td>${esc(hits[k])}</td></tr>`).join('');
                return `
                  ${kv('抽检表', s.table || '')}
                  ${kv('抽样行数', s.sampledRows || 0)}
                  <table style="width:100%; border-collapse:collapse; font-size:9pt; margin-top:8px;">
                    <thead><tr style="background:#f5f5f5;">
                      <th style="border:1px solid #e1e4e8; padding:6px;">模式</th>
                      <th style="border:1px solid #e1e4e8; padding:6px;">命中次数</th>
                    </tr></thead>
                    <tbody>${rows || ''}</tbody>
                  </table>
                `;
            };

            const html = `<!doctype html><html><head><meta charset="utf-8"><title>${esc(title)}</title></head>
<body style="font-family:Microsoft YaHei, sans-serif; color:#333; padding:16px;">
<h1 style="margin:0 0 10px 0; font-size:14pt;">${esc(title)}</h1>
<div style="font-size:9pt; color:#6c757d; margin-bottom:10px;">提示：本报告为工具自动生成（非AI），仅供覆盖/强度/残留风险快速筛查。</div>
${sec('1) 覆盖审查', renderCoverage())}
${sec('2) 强度审查', renderStrength())}
${sec('3) 残留抽检', renderSample())}
<hr style="margin:16px 0; border:none; border-top:1px solid #e1e4e8;">
<pre style="white-space:pre-wrap; font-size:8pt; color:#6c757d;">RAW JSON:\n${esc(JSON.stringify(b, null, 2))}</pre>
</body></html>`;
            const blob = new Blob([html], { type: 'text/html' });
            const a = document.createElement('a');
            a.href = URL.createObjectURL(blob);
            a.download = `review-${now.toISOString().slice(0,10)}.html`;
            a.click();
            setTimeout(() => URL.revokeObjectURL(a.href), 1000);
        }

