        // ==================== 批量脱敏（多表） ====================
        function dsBatchMaskStart() {
            if (!window.__sqliteReady) { alert('SQLite 尚未导入'); return; }
            if (!dsIsExpert()) { alert('批量脱敏仅专家模式可用'); return; }
            const sel = document.getElementById('dsBatchTables');
            const tables = Array.from(sel?.selectedOptions || []).map(o => o.value).filter(Boolean);
            if (!tables.length) { alert('请选择至少一张表'); return; }
            const templateId = document.getElementById('dsBatchTemplateId')?.value || 'tpl_pii_basic_tokenize_v1';
            const overwrite = !!document.getElementById('dsBatchOverwrite')?.checked;
            const includeMasked = !!document.getElementById('dsBatchIncludeMasked')?.checked;
            const batchId = dsReqId('batch');
            // 注意：避免并发跑多张大表导致卡死，采用“串行队列”逐表执行
            window.__dsBatch = {
                batchId,
                total: tables.length,
                done: 0, ok: 0, fail: 0,
                items: [],
                queue: tables.slice(),
                cursor: 0,
                activeRid: ''
            };
            const hint = document.getElementById('dsBatchHint');
            if (hint) hint.textContent = `批量脱敏启动：${tables.length} 张表（串行执行）…`;
            dsBatchRunNext(templateId, overwrite, includeMasked);
        }

        function dsBatchRunNext(templateId, overwrite, includeMasked) {
            const b = window.__dsBatch || null;
            if (!b) return;
            const hint = document.getElementById('dsBatchHint');
            if (b.cursor >= (b.queue || []).length) {
                if (hint) hint.textContent = `批量脱敏已完成：${b.done}/${b.total}（成功 ${b.ok}，失败 ${b.fail}）`;
                return;
            }
            const t = b.queue[b.cursor];
            const rid = `${b.batchId}_${b.cursor}`;
            b.activeRid = rid;
            if (hint) hint.textContent = `批量脱敏执行中：${b.cursor + 1}/${b.total} —— ${t}`;
            try {
                window.chrome?.webview?.postMessage?.({
                    action: 'executeMaskJob',
                    requestId: rid,
                    expertMode: true,
                    payload: { sourceTable: t, templateId, overwrite, includeMasked }
                });
            } catch (e) {
                b.done++; b.fail++;
                b.items.push({ requestId: rid, ok: false, data: { sourceTable: t }, message: e?.message || String(e) });
                b.cursor++;
                dsBatchRunNext(templateId, overwrite, includeMasked);
            }
        }
        function dsBatchExport() {
            const b = window.__dsBatch || null;
            if (!b) { alert('暂无批量结果'); return; }
            try {
                const blob = new Blob([JSON.stringify(b, null, 2)], { type: 'application/json' });
                const a = document.createElement('a');
                a.href = URL.createObjectURL(blob);
                a.download = `batch-mask-${new Date().toISOString().slice(0,10)}.json`;
                a.click();
                setTimeout(() => URL.revokeObjectURL(a.href), 1000);
            } catch (e) { alert('导出失败：' + (e?.message || e)); }
        }

