        function enumReaderGotoRelationDetect() {
            if (!window.__sqliteReady) { alert('SQLite 尚未导入'); return; }
            const main = document.getElementById('enumReaderTable')?.value || (window.__sqliteMainTableName || 'Main');
            if (!main) { alert('请先选择表'); return; }
            try { switchTab('relation-check'); } catch (_) { }
            try { const sel = document.getElementById('relMode'); if (sel) sel.value = 'primary-first'; } catch (_) { }
            try { const sel2 = document.getElementById('relMainTable'); if (sel2) sel2.value = main; } catch (_) { }
            try { const c1 = document.getElementById('relUseName'); if (c1) c1.checked = true; } catch (_) { }
            try { const c2 = document.getElementById('relUseValues'); if (c2) c2.checked = true; } catch (_) { }
            try { const c3 = document.getElementById('relUseComposite'); if (c3) c3.checked = false; } catch (_) { }
            try { setStatusMessage('已从枚举解读联动：请补充参与表并点击“开始识别”'); } catch (_) { }
        }
        function enumReaderFillArchiveList(files) {
            const sel = document.getElementById('enumReaderSelect');
            if (!sel) return;
            const prev = sel.value || '';
            sel.innerHTML = '<option value="">（请选择存档）</option>';
            (files || []).forEach(f => {
                const opt = document.createElement('option');
                opt.value = f.name;
                opt.textContent = `${f.name} (${f.time || ''})`;
                sel.appendChild(opt);
            });
            if (prev && (files || []).some(x => x.name === prev)) sel.value = prev;
            const hint = document.getElementById('enumReaderHint');
            if (hint) hint.textContent = `存档：${(files || []).length} 个`;
        }
        function enumReaderLoad() {
            const fileName = document.getElementById('enumReaderSelect')?.value || '';
            if (!fileName) return;
            try { window.chrome?.webview?.postMessage?.({ action: 'dsEnumArchiveLoad', requestId: dsReqId('enumRLoad'), payload: { fileName } }); } catch (_) { }
        }
        function enumReaderExport() {
            if (!window.__enumReaderLast) { alert('暂无可导出的枚举存档'); return; }
            try {
                const blob = new Blob([JSON.stringify(window.__enumReaderLast, null, 2)], { type: 'application/json' });
                const a = document.createElement('a');
                a.href = URL.createObjectURL(blob);
                a.download = `enum-reader-${new Date().toISOString().slice(0,10)}.json`;
                a.click();
                setTimeout(() => URL.revokeObjectURL(a.href), 1000);
            } catch (e) { alert('导出失败：' + (e?.message || e)); }
        }

        // ==================== 审计日志（Vault.audit_log） ====================
        window.__dsAuditLogs = [];
        function dsAuditRefresh() {
            if (!dsIsExpert()) { alert('审计日志仅专家模式可用'); return; }
            try { window.chrome?.webview?.postMessage?.({ action: 'dsListAuditLogs', requestId: dsReqId('audit'), payload: { limit: 200 } }); } catch (_) { }
        }
        function dsAuditRender() {
            const body = document.getElementById('dsAuditBody');
            if (!body) return;
            const logs = Array.isArray(window.__dsAuditLogs) ? window.__dsAuditLogs : [];
            if (!logs.length) {
                body.innerHTML = `<tr><td colspan="8" style="color:#6c757d;">暂无审计记录</td></tr>`;
                const hint = document.getElementById('dsAuditHint'); if (hint) hint.textContent = '';
                return;
            }
            body.innerHTML = logs.map(l => `
                <tr>
                    <td>${escapeHtml(l.createdAt || l.created_at || '')}</td>
                    <td>${escapeHtml(l.action || '')}</td>
                    <td>${escapeHtml(l.status || '')}</td>
                    <td class="num">${escapeHtml(String(l.rowCount ?? l.row_count ?? ''))}</td>
                    <td>${escapeHtml(l.operator || l.operatorName || l.operator_ || '')}</td>
                    <td>${escapeHtml(l.reasonTicket || l.reason_ticket || '')}</td>
                    <td title="${escapeHtml(l.inputRef || '')}" style="max-width:260px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">${escapeHtml(l.inputRef || '')}</td>
                    <td title="${escapeHtml(l.outputRef || '')}" style="max-width:260px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">${escapeHtml(l.outputRef || '')}</td>
                </tr>
            `).join('');
            const hint = document.getElementById('dsAuditHint');
            if (hint) hint.textContent = `最近记录：${logs.length} 条（namespace = ${window.__dsTplCurrent.namespace || (window.__activeSchemeId || '') || '当前'}）`;
        }
        function dsAuditExport() {
            const logs = Array.isArray(window.__dsAuditLogs) ? window.__dsAuditLogs : [];
            if (!logs.length) { alert('暂无可导出的审计记录'); return; }
            try {
                const blob = new Blob([JSON.stringify({ exportedAt: new Date().toISOString(), logs }, null, 2)], { type: 'application/json' });
                const a = document.createElement('a');
                a.href = URL.createObjectURL(blob);
                a.download = `audit-log-${new Date().toISOString().slice(0,10)}.json`;
                a.click();
                setTimeout(() => URL.revokeObjectURL(a.href), 1000);
            } catch (e) { alert('导出失败：' + (e?.message || e)); }
        }

        // ==================== 派生视图（建模管理） ====================
        function dvForceVwPrefix(inputId) {
            const el = document.getElementById(inputId);
            if (!el) return;
            let v = String(el.value || '').trim();
            if (!v) return;
            if (!v.toLowerCase().startsWith('vw_')) v = 'vw_' + v.replace(/^_+/, '');
            el.value = v;
        }

        function dvEnsurePrefix() {
            const el = document.getElementById('dvName');
            if (!el) return;
            let v = String(el.value || '').trim();
            if (!v) return;
            if (!v.toLowerCase().startsWith('vw_')) v = 'vw_' + v.replace(/^_+/, '');
            el.value = v;
        }

        function dvNew() {
            window.__dvSelectedName = '';
            try { document.getElementById('dvName').value = 'vw_'; } catch (_) { }
            try { document.getElementById('dvSqlText').value = ''; } catch (_) { }
            try { document.getElementById('dvNote').value = ''; } catch (_) { }
            try { document.getElementById('dvVersion').value = '-'; } catch (_) { }
            try { document.getElementById('dvUpdatedAt').value = '-'; } catch (_) { }
            try { document.getElementById('dvDependsHint').textContent = '依赖：-'; } catch (_) { }
            try { initWizardSqlEditors(); } catch (_) { }
        }

        function dvRefresh() {
            // 复用项目中心的详情接口：默认取当前激活项目
            const id = window.__activeSchemeId || window.__selectedProjectId || '';
            if (!id) { alert('请先保存/加载一个项目'); return; }
            try { window.chrome?.webview?.postMessage?.({ action: 'getProjectDetail', schemeId: id }); } catch (_) { }
        }

        function dvRenderListFromMeta(meta) {
            const list = (meta && (meta.DerivedViews || meta.derivedViews)) ? (meta.DerivedViews || meta.derivedViews) : [];
            window.__derivedViews = Array.isArray(list) ? list : [];
            const tbody = document.getElementById('dvListBody');
            if (!tbody) return;
            if (!window.__derivedViews.length) {
                tbody.innerHTML = `<tr><td colspan="3" style="color:#6c757d;">（暂无派生视图）</td></tr>`;
                return;
            }
            const existing = new Set((Array.isArray(window.__sqliteTables) ? window.__sqliteTables : []).map(x => String(x)));
            tbody.innerHTML = window.__derivedViews.map(v => {
                const name = v.Name || v.name || '';
                const ver = v.Version ?? v.version ?? 1;
                const up = v.UpdatedAt || v.updatedAt || '';
                const active = (window.__dvSelectedName && window.__dvSelectedName === name) ? 'background:#e7f3ff;' : '';
                const deps = v.DependsOn || v.dependsOn || [];
                const missing = (Array.isArray(deps) ? deps : []).filter(d => d && !existing.has(String(d)));
                const bad = missing.length > 0;
                const warn = bad ? `缺失依赖：${missing.join('，')}` : '';
                return `<tr style="cursor:pointer; ${active} ${bad ? 'background:#fff3f0;' : ''}" onclick="dvSelect('${String(name).replace(/'/g, "\\'")}')">
                    <td style="font-family:Consolas,monospace;" title="${escapeHtml(warn)}">${escapeHtml(name)}${bad ? '（失效）' : ''}</td>
                    <td>${escapeHtml(String(ver))}</td>
                    <td style="color:#6c757d;">${escapeHtml(String(up))}</td>
                </tr>`;
            }).join('');
        }

        function dvSelect(name) {
            window.__dvSelectedName = name || '';
            const v = (window.__derivedViews || []).find(x => String((x.Name||x.name||'')).toLowerCase() === String(name).toLowerCase()) || null;
            if (!v) return;
            window.__dvSelectedView = v;
            try { document.getElementById('dvName').value = v.Name || v.name || ''; } catch (_) { }
            try { document.getElementById('dvSqlText').value = v.Sql || v.sql || ''; } catch (_) { }
            try { document.getElementById('dvNote').value = v.Note || v.note || ''; } catch (_) { }
            try { document.getElementById('dvVersion').value = String(v.Version ?? v.version ?? 1); } catch (_) { }
            try { document.getElementById('dvUpdatedAt').value = String(v.UpdatedAt || v.updatedAt || ''); } catch (_) { }
            try {
                const deps = v.DependsOn || v.dependsOn || [];
                const depList = (Array.isArray(deps) && deps.length) ? deps.map(x => String(x)) : [];
                const existing = new Set((Array.isArray(window.__sqliteTables) ? window.__sqliteTables : []).map(x => String(x)));
                const missing = depList.filter(d => d && !existing.has(String(d)));
                const hint = document.getElementById('dvDependsHint');
                if (hint) {
                    if (missing.length) {
                        hint.style.color = '#cf1322';
                        hint.textContent = '依赖：' + depList.join('，') + ' ；缺失：' + missing.join('，');
                    } else {
                        hint.style.color = '#6c757d';
                        hint.textContent = '依赖：' + (depList.length ? depList.join('，') : '-');
                    }
                }
                const fixBtn = document.getElementById('dvFixBtn');
                if (fixBtn) fixBtn.style.display = missing.length ? 'inline-block' : 'none';
            } catch (_) { }
            dvRenderListFromMeta({ DerivedViews: window.__derivedViews });
            try { initWizardSqlEditors(); } catch (_) { }
        }

        // 一键修复：把当前视图 SQL 送到 SQL 编辑器，并在顶部提示缺失依赖
        function dvOpenInSqlLab() {
            const v = window.__dvSelectedView || null;
            if (!v) { alert('请先选择一个派生视图'); return; }
            const sql = String(v.Sql || v.sql || '').trim();
            if (!sql) { alert('该视图没有 SQL 内容'); return; }
            const deps = (v.DependsOn || v.dependsOn || []).map(x => String(x));
            const existing = new Set((Array.isArray(window.__sqliteTables) ? window.__sqliteTables : []).map(x => String(x)));
            const missing = deps.filter(d => d && !existing.has(String(d)));
            const header = missing.length
                ? `-- 【视图失效】缺失依赖表：${missing.join(', ')}\n-- 建议：挂载基础库 / 重新导入缺失表 / 或修改 SQL 去除依赖。\n\n`
                : `-- 视图：${String(v.Name || v.name || '')}\n\n`;
            try {
                sqlEditorSetText(header + sql + (sql.endsWith(';') ? '' : ';'));
                switchTab('sql-editor');
                setStatusMessage('已送到 SQL 编辑器（请修复后回到建模管理保存视图）');
            } catch (_) { }
        }

        function dvSave() {
            const name = (document.getElementById('dvName')?.value || '').trim();
            const sql = (document.getElementById('dvSqlText')?.value || '').trim();
            const note = (document.getElementById('dvNote')?.value || '').trim();
            if (!name || name.toLowerCase() === 'vw_') { alert('请输入视图名称（vw_ 前缀）'); return; }
            if (!name.toLowerCase().startsWith('vw_')) { alert('视图名称必须以 vw_ 开头'); return; }
            if (!sql) { alert('请输入 SQL'); return; }
            try {
                window.chrome?.webview?.postMessage?.({ action: 'upsertDerivedView', name, sql, note });
                setStatusMessage('正在保存派生视图...');
            } catch (_) { }
        }

        // ==================== 关联引入（Relate）：复用 MTJ 锁定SQL，生成 vw_ 派生视图 ====================
        function relateCreateDerivedView() {
            const name = (document.getElementById('relateViewName')?.value || '').trim();
            if (!name) { alert('请输入视图名称（vw_ 前缀）'); return; }
            if (!name.toLowerCase().startsWith('vw_')) { alert('视图名称必须以 vw_ 开头'); return; }
            const s = window.__mtjSettings || null;
            const lockedSql = (s && s.lockedSql) ? String(s.lockedSql).trim() : '';
            if (!lockedSql) {
                if (confirm('当前没有“多表关联（MTJ）锁定SQL”。\n\n是否现在跳转到【多表关联】去配置并点击“锁定SQL”？')) {
                    try { openMultiTableJoin(); } catch (_) { }
                }
                return;
            }
            const tables = (s && Array.isArray(s.tables)) ? s.tables : [];
            const note = `关联引入（Relate）：${tables.map(x => x && x.alias && x.tableName ? `${x.alias}=${x.tableName}` : '').filter(Boolean).join('；')}`.slice(0, 500);
            try {
                window.chrome?.webview?.postMessage?.({ action: 'upsertDerivedView', name, sql: lockedSql, note });
                setStatusMessage('正在生成关联视图...');
            } catch (_) { }
        }

        function dvDelete() {
            const name = (document.getElementById('dvName')?.value || '').trim();
            if (!name) { alert('请先选择一个视图'); return; }
            if (!confirm(`确认删除派生视图【${name}】？`)) return;
            try {
                window.chrome?.webview?.postMessage?.({ action: 'deleteDerivedView', name });
                setStatusMessage('正在删除派生视图...');
            } catch (_) { }
        }

        function dvOpenPreview() {
            const name = (document.getElementById('dvName')?.value || '').trim();
            if (!name) { alert('请先选择一个视图'); return; }
            const sql = `SELECT * FROM ${sqlQuoteIdent(name)} LIMIT 200;`;
            try { switchTab('sql-editor'); } catch (_) { }
            try { sqlEditorSetText(sql); } catch (_) { }
            setStatusMessage('已打开 SQL 编辑器预览视图（LIMIT 200）');
        }

        function formatBytes(n) {
            const v = Number(n || 0);
            if (!isFinite(v) || v <= 0) return '0 B';
            const units = ['B','KB','MB','GB','TB'];
            let i = 0, x = v;
            while (x >= 1024 && i < units.length - 1) { x /= 1024; i++; }
            return `${x.toFixed(i === 0 ? 0 : 2)} ${units[i]}`;
        }

        function filterProjectList() {
            const kw = (document.getElementById('projectSearchInput')?.value || '').trim().toLowerCase();
            const list = Array.isArray(window.__projectList) ? window.__projectList : [];
            if (!kw) { renderProjectList(list); return; }
            renderProjectList(list.filter(p =>
                String(p.name || '').toLowerCase().includes(kw)
                || String(p.id || '').toLowerCase().includes(kw)
                || String(p.mainSource || '').toLowerCase().includes(kw)
                || String(p.mainTable || '').toLowerCase().includes(kw)
            ));
        }

        function renderProjectList(projects) {
            window.__projectList = Array.isArray(projects) ? projects : [];
            const tbody = document.getElementById('projectListBody');
            if (!tbody) return;
            const list = window.__projectList;
            if (!list.length) {
                tbody.innerHTML = `<tr><td colspan="10" style="color:#6c757d;">暂无项目</td></tr>`;
                return;
            }
            tbody.innerHTML = list.map(p => {
                const id = String(p.id || '');
                const active = (window.__selectedProjectId && window.__selectedProjectId === id) ? 'background:#e7f3ff;' : '';
                const status = p.status || 'ok';
                const stLabel = status === 'ok' ? '正常' : (status === 'db_missing' ? '库缺失' : '配置缺失');
                const stColor = status === 'ok' ? '#52c41a' : '#faad14';
                const dbName = (p.dbPath || '').split(/[\\/]/).pop() || '';
                const iniName = (p.iniPath || '').split(/[\\/]/).pop() || '';
                const diff = (p.tableDiffRate !== undefined && p.tableDiffRate !== null) ? `${Math.round(Number(p.tableDiffRate) * 100)}%` : '-';
                return `
                    <tr style="cursor:pointer; ${active}" onclick="selectProject('${id.replace(/'/g, "\\'")}')">
                        <td><div style="font-weight:700; color:#333;">${escapeHtml(p.name || id)}</div></td>
                        <td style="color:#6c757d;">${escapeHtml(dbName || '-')}</td>
                        <td style="color:#6c757d;">${escapeHtml(iniName || '-')}</td>
                        <td style="color:#6c757d;">${escapeHtml(formatBytes(p.dbSizeBytes || 0))}</td>
                        <td style="color:#6c757d; max-width:180px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;" title="${escapeHtml(p.mainSource || '')}">${escapeHtml((p.mainSource||'').split('/').pop() || '-')}</td>
                        <td style="color:#6c757d;">${escapeHtml(p.mainTable || '-')}</td>
                        <td style="color:#6c757d;">${escapeHtml(String(p.openCount ?? 0))}</td>
                        <td style="color:#6c757d;">${escapeHtml(p.createdAt || '-')}</td>
                        <td style="color:#6c757d;">${escapeHtml(p.updatedAt || '-')} <span style="color:#999;">(${escapeHtml(diff)})</span> <span style="color:${stColor}; font-weight:700; margin-left:6px;">${stLabel}</span></td>
                        <td>
                            <button class="btn btn-success" style="padding:2px 8px; font-size:8pt;" onclick="try{event.stopPropagation();}catch(_){} openRecentScheme('${id.replace(/'/g, "\\'")}')">访问</button>
                            <button class="btn btn-danger" style="padding:2px 8px; font-size:8pt;" onclick="try{event.stopPropagation();}catch(_){} deleteProject('${id.replace(/'/g, "\\'")}')">删除</button>
                        </td>
                    </tr>
                `;
            }).join('');
        }

        function selectProject(schemeId) {
            if (!schemeId) return;
            window.__selectedProjectId = schemeId;
            filterProjectList();
            try { window.chrome?.webview?.postMessage?.({ action: 'getProjectDetail', schemeId }); } catch (_) { }
        }

        function openSelectedProject() {
            const id = window.__selectedProjectId;
            if (!id) { alert('请先选择一个项目'); return; }
            openRecentScheme(id);
            // 日常打开/加载应留在项目中心（避免“打开=跳到项目管理”造成心智混乱）
            try { switchTab('project-hub'); } catch (_) { }
            try { setProjectHubView('active'); } catch (_) { }
        }

        function deleteProject(id) {
            if (!id) return;
            if (!confirm(`确认删除项目【${id}】？\n\n将删除：配置文件 ini、业务库 db、project.json。\n（不允许删除当前正在使用的项目）`)) return;
            try { window.chrome?.webview?.postMessage?.({ action: 'deleteScheme', schemeId: id }); } catch (_) { }
        }

        function exportProjectOverview() {
            const list = Array.isArray(window.__projectList) ? window.__projectList : [];
            const rows = list.map(p => `
                <tr>
                  ${reportTd(p.name||p.id||'')}
                  ${reportTd((p.dbPath||'').split(/[\\\\/]/).pop()||'')}
                  ${reportTd((p.iniPath||'').split(/[\\\\/]/).pop()||'')}
                  ${reportTd(formatBytes(p.dbSizeBytes||0))}
                  ${reportTd(p.mainSource||'')}
                  ${reportTd(p.mainTable||'')}
                  ${reportTd(String(p.openCount??0))}
                  ${reportTd(p.createdAt||'')}
                  ${reportTd(p.updatedAt||'')}
                </tr>`).join('');
            const html = `<!doctype html><html><head><meta charset="utf-8"><title>项目中心-总项目概况</title>
              <style>${reportCss('h1{font-size:13pt;} th{background:#f8f9fa;color:#212529;}')}</style>
              </head><body><h1>项目中心-总项目概况（导出时间：${new Date().toLocaleString()}）</h1>
              <table><thead><tr><th>项目名称</th><th>数据库名称</th><th>配置文件</th><th>数据大小</th><th>源文件基表</th><th>数据表基表</th><th>使用频次</th><th>创建时间</th><th>修改时间</th></tr></thead><tbody>${rows}</tbody></table>
              </body></html>`;
            try { window.chrome?.webview?.postMessage?.({ action:'saveHtmlReport', reportName:'project-hub-overview', fileName:'project-hub-overview.html', html, openAfterSave:true }); } catch (_) { }
        }

        function exportProjectDetail() {
            const id = window.__selectedProjectId;
            if (!id || !window.__selectedProjectMeta) { alert('请先选择一个项目'); return; }
            const m = window.__selectedProjectMeta;
            const sources = (m.Sources || m.sources || []);
            const srcRows = Array.isArray(sources) ? sources.map(s => `<tr>${reportTd(s.FilePath||s.filePath||'')}${reportTd(formatBytes(s.FileSizeBytes||s.fileSizeBytes||0))}${reportTd(String(s.IsMain||s.isMain||false))}${reportTd((s.Sheets||s.sheets||[]).join('，'))}</tr>`).join('') : '';
            const tables = (m.DbTables || m.dbTables || []);
            const tbRows = Array.isArray(tables) ? tables.map(t => `<tr>${reportTd(t)}</tr>`).join('') : '';
            const dvs = (m.DerivedViews || m.derivedViews || []);
            const dvRows = Array.isArray(dvs) ? dvs.map(v => {
                const name = v.Name || v.name || '';
                const ver = v.Version ?? v.version ?? 1;
                const deps = v.DependsOn || v.dependsOn || [];
                const up = v.UpdatedAt || v.updatedAt || '';
                return `<tr>${reportTd(name)}${reportTd(String(ver))}${reportTd(Array.isArray(deps)?deps.join('，'):'')}${reportTd(String(up))}</tr>`;
            }).join('') : '';
            const html = `<!doctype html><html><head><meta charset="utf-8"><title>项目中心-详单-${id}</title>
              <style>${reportCss('h1{font-size:13pt;} th{background:#f8f9fa;color:#212529;}')}</style>
              </head><body>
              <h1>项目中心-文件列表详单：${escapeHtml(m.DisplayName||m.displayName||id)}</h1>
              <div>项目ID：${escapeHtml(id)}｜业务库：${escapeHtml(m.DbPath||m.dbPath||'')}｜配置：${escapeHtml(m.IniPath||m.iniPath||'')}</div>
              <div>创建：${escapeHtml(String(m.CreatedAt||m.createdAt||''))}｜修改：${escapeHtml(String(m.UpdatedAt||m.updatedAt||''))}｜使用频次：${escapeHtml(String(m.OpenCount||m.openCount||0))}</div>
              <h2>源文件表清单</h2>
              <table><thead><tr><th>源文件路径</th><th>大小</th><th>是否主表</th><th>工作表</th></tr></thead><tbody>${srcRows || '<tr><td colspan=4>无</td></tr>'}</tbody></table>
              <h2>数据表库清单</h2>
              <table><thead><tr><th>表/视图名</th></tr></thead><tbody>${tbRows || '<tr><td>无</td></tr>'}</tbody></table>
              <h2>派生视图清单（vw_）</h2>
              <table><thead><tr><th>视图名称</th><th>版本</th><th>依赖</th><th>更新时间</th></tr></thead><tbody>${dvRows || '<tr><td colspan=4>无</td></tr>'}</tbody></table>
              </body></html>`;
            try { window.chrome?.webview?.postMessage?.({ action:'saveHtmlReport', reportName:'project-hub-detail', fileName:`project-hub-detail-${id}.html`, html, openAfterSave:true }); } catch (_) { }
        }

        function closeProjectDetailModal() {
            const mask = document.getElementById('projectDetailMask');
            if (mask) mask.style.display = 'none';
        }

        function createRevisionPoint(type, note) {
            if (!window.__activeSchemeId) { alert('请先在项目中心打开一个项目'); return; }
            try {
                window.chrome?.webview?.postMessage?.({
                    action: 'createRevisionPoint',
                    type: type || 'manual',
                    note: note || '手动修订点',
                    enableBackup: true
                });
                setStatusMessage('正在创建修订点...');
            } catch (_) { }
        }

        function restoreRevisionPoint(revisionId) {
            const meta = window.__selectedProjectMeta || null;
            const schemeId = (meta && (meta.Id || meta.id)) ? (meta.Id || meta.id) : (window.__activeSchemeId || '');
            if (!schemeId || !revisionId) return;
            if (!confirm(`确认恢复修订点？\n\n项目：${schemeId}\n修订点：${revisionId}\n\n提示：该操作会覆盖当前业务库并重新载入。`)) return;
            try {
                window.chrome?.webview?.postMessage?.({ action: 'restoreRevisionPoint', schemeId, revisionId });
                setStatusMessage('正在恢复修订点并重载数据库...');
            } catch (_) { }
        }

        function openProjectDetailModal() {
            const m = window.__selectedProjectMeta || null;
            if (!m) { alert('请先选择一个项目'); return; }
            const mask = document.getElementById('projectDetailMask');
            const body = document.getElementById('projectDetailModalBody');
            if (!mask || !body) return;

            const schemeName = m.DisplayName || m.displayName || m.Id || m.id || '';
            const updatedAt = m.UpdatedAt || m.updatedAt || '';
            const diffRate = m.TableDiffRate ?? m.tableDiffRate;
            const diffText = (diffRate === undefined || diffRate === null) ? '-' : `${Math.round(Number(diffRate) * 100)}%`;
            const sources = (m.Sources || m.sources || []);
            const dbTables = (m.DbTables || m.dbTables || []);
            const tableSet = new Set((Array.isArray(dbTables) ? dbTables : []).map(x => String(x)));
            const dvs = (m.DerivedViews || m.derivedViews || []);

            const rows = [];
            (Array.isArray(sources) ? sources : []).forEach(s => {
                const fp = s.FilePath || s.filePath || '';
                const fileName = (fp.split('/').pop() || fp);
                const ticks = s.LastWriteUtcTicks ?? s.lastWriteUtcTicks ?? 0;
                const lastMod = ticks ? new Date(Number(ticks)/10000 - 62135596800000).toLocaleString() : '';
                const sheets = (s.Sheets || s.sheets || []);
                const tnMap = s.TableNameMap || s.tableNameMap || {};
                const taMap = s.TableAliasMap || s.tableAliasMap || {};
                (Array.isArray(sheets) ? sheets : []).forEach(sh => {
                    const base = fileName.replace(/\.[^.]+$/, '');
                    const physical = (tnMap && tnMap[sh]) ? String(tnMap[sh]) : `${base}|${sh}`;
                    const alias = (taMap && taMap[sh]) ? String(taMap[sh]) : physical;
                    const show = (alias && alias !== physical) ? `${alias}（${physical}）` : physical;
                    const exists = tableSet.has(physical);
                    rows.push({
                        schemeName,
                        fileName,
                        filePath: fp,
                        sheet: sh,
                        table: show,
                        exists,
                        version: 'v1',
                        diffRate: diffText,
                        lastMod: lastMod || updatedAt || '-'
                    });
                });
            });

            const baseDb = m.BaseDbPath || m.baseDbPath || '';
            const baseTables = (m.BaseDbTables || m.baseDbTables || []);

            const head = `<div style="margin-bottom:10px;">
                <div style="font-weight:700; color:#333;">项目：${escapeHtml(schemeName)}</div>
                <div style="font-size:8pt; color:#6c757d; margin-top:4px;">修改时间：${escapeHtml(String(updatedAt||'-'))}｜信息差异率（粗略）：${escapeHtml(diffText)}｜表/视图数：${escapeHtml(String((Array.isArray(dbTables)?dbTables.length:0)))}</div>
            </div>`;

            const tabBar = `
                <div style="display:flex; gap:8px; flex-wrap:wrap; margin-bottom:10px;">
                    <button class="btn btn-secondary" style="padding:4px 10px; font-size:9pt;" onclick="phTab('overview')">概况</button>
                    <button class="btn btn-secondary" style="padding:4px 10px; font-size:9pt;" onclick="phTab('mapping')">映射</button>
                    <button class="btn btn-secondary" style="padding:4px 10px; font-size:9pt;" onclick="phTab('views')">视图</button>
                    <button class="btn btn-secondary" style="padding:4px 10px; font-size:9pt;" onclick="phTab('policy')">策略</button>
                    <button class="btn btn-secondary" style="padding:4px 10px; font-size:9pt;" onclick="phTab('audit')">审计</button>
                </div>
            `;

            const overviewHtml = `
                <div id="phTab_overview">
                    <div class="result-info" style="background:#f8f9fa; border-left:4px solid #0078d4;">
                        <div><b>项目ID：</b>${escapeHtml(String(m.Id||m.id||''))}</div>
                        <div><b>业务库：</b>${escapeHtml(String(m.DbPath||m.dbPath||''))}</div>
                        <div><b>配置：</b>${escapeHtml(String(m.IniPath||m.iniPath||''))}</div>
                        <div style="margin-top:6px; color:#6c757d; font-size:8pt;">建议：下游模块统一面向 vw_ 视图与 clean__* 表；raw__* 仅作为保真快照与可归档层。</div>
                    </div>
                </div>
            `;

            const mappingHtml = `
                <div id="phTab_mapping" style="display:none;">
                    <table class="table" style="font-size:9pt;">
                        <thead>
                            <tr>
                                <th>项目名称</th>
                                <th>源文件名称</th>
                                <th>源文件路径</th>
                                <th>源工作表</th>
                                <th>数据表（对应）</th>
                                <th>存在</th>
                                <th>版本号</th>
                                <th>信息差异率</th>
                                <th>最近一次修改时间</th>
                            </tr>
                        </thead>
                        <tbody>
                            ${rows.length ? rows.map(r => `
                                <tr>
                                    <td>${escapeHtml(r.schemeName)}</td>
                                    <td>${escapeHtml(r.fileName)}</td>
                                    <td style="max-width:260px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;" title="${escapeHtml(r.filePath)}">${escapeHtml(r.filePath)}</td>
                                    <td>${escapeHtml(r.sheet)}</td>
                                    <td style="font-family:Consolas,monospace; font-size:8.5pt;">${escapeHtml(r.table)}</td>
                                    <td>${r.exists ? '<span style="color:#52c41a;font-weight:700;">✔</span>' : '<span style="color:#faad14;font-weight:700;">✗</span>'}</td>
                                    <td>${escapeHtml(r.version)}</td>
                                    <td>${escapeHtml(r.diffRate)}</td>
                                    <td>${escapeHtml(r.lastMod)}</td>
                                </tr>
                            `).join('') : `<tr><td colspan="9" style="color:#6c757d;">（无明细）</td></tr>`}
                        </tbody>
                    </table>
                </div>
            `;

            const viewsHtml = (() => {
                const inner = (!Array.isArray(dvs) || !dvs.length)
                    ? `<div style="margin-top:10px; color:#6c757d;">（暂无派生视图）</div>`
                    : `
                        <table class="table" style="font-size:9pt; margin-top:8px;">
                            <thead><tr><th>视图名称</th><th style="width:70px;">版本</th><th>依赖</th><th style="width:140px;">更新时间</th></tr></thead>
                            <tbody>
                                ${dvs.map(v => {
                                    const name = v.Name || v.name || '';
                                    const ver = v.Version ?? v.version ?? 1;
                                    const deps = v.DependsOn || v.dependsOn || [];
                                    const up = v.UpdatedAt || v.updatedAt || '';
                                    return `<tr>
                                        <td style="font-family:Consolas,monospace;">${escapeHtml(name)}</td>
                                        <td>${escapeHtml(String(ver))}</td>
                                        <td style="color:#6c757d;">${escapeHtml(Array.isArray(deps)?deps.join('，'):'')}</td>
                                        <td style="color:#6c757d;">${escapeHtml(String(up))}</td>
                                    </tr>`;
                                }).join('')}
                            </tbody>
                        </table>
                    `;
                return `<div id="phTab_views" style="display:none;">${inner}</div>`;
            })();

            const policyHtml = `
                <div id="phTab_policy" style="display:none;">
                    <div class="result-info" style="background:#f8f9fa; border-left:4px solid #adb5bd;">
                        <div><b>数据分层：</b>${escapeHtml(String((m.RawCleanPolicy?.Mode||m.rawCleanPolicy?.mode||'raw+clean')))}</div>
                        <div style="margin-top:6px;"><b>基础库：</b>${escapeHtml(baseDb ? (baseDb.split('/').pop()||baseDb) : '（未挂载）')} <span style="color:#6c757d;">（${Array.isArray(baseTables)?baseTables.length:0} 表/视图）</span></div>
                        <div style="margin-top:8px; display:flex; gap:8px; flex-wrap:wrap;">
                            <button class="btn btn-secondary" style="padding:2px 8px; font-size:8pt;" onclick="selectBaseDb()">挂载/更换基础库</button>
                            <button class="btn btn-secondary" style="padding:2px 8px; font-size:8pt;" onclick="detachBaseDb()">解除基础库</button>
                        </div>
                        ${Array.isArray(baseTables) && baseTables.length ? `
                            <div style="margin-top:10px; font-weight:700; color:#333;">基础库表/视图（前 50）</div>
                            <div style="margin-top:6px; font-family:Consolas,monospace; font-size:8.5pt; color:#495057; white-space:pre-wrap; max-height:180px; overflow:auto; border:1px solid #e1e4e8; border-radius:4px; padding:8px; background:#fff;">
                                ${escapeHtml(baseTables.slice(0,50).join('\\n'))}${baseTables.length>50?escapeHtml('\\n...'):''}
                            </div>
                        ` : `<div style="margin-top:10px; color:#6c757d; font-size:8pt;">（未挂载基础库或基础库无对象）</div>`}
                    </div>
                </div>
            `;

            const auditHtml = (() => {
                const logs = (m.AuditLogs || m.auditLogs || []);
                if (!Array.isArray(logs) || !logs.length) return `<div id="phTab_audit" style="display:none; color:#6c757d;">（暂无审计记录）</div>`;
                const rows = logs.slice(0, 80).map(l => {
                    const tm = l.Time || l.time || '';
                    const t = l.Type || l.type || '';
                    const note = l.Note || l.note || '';
                    const rp = l.RevisionPointId || l.revisionPointId || '';
                    const rps = (l.RevisionPointIds || l.revisionPointIds || []);
                    const rpx = rp ? rp : (Array.isArray(rps) && rps.length ? `${rps.length}个` : '');
                    const reports = (l.ReportPaths || l.reportPaths || []);
                    const repText = Array.isArray(reports) ? reports.map(p => (String(p).split(/[\\\\/]/).pop() || p)).join('；') : '';
                    const timeText = tm ? String(tm).replace('T',' ').replace('Z','') : '-';
                    return `<tr>
                        <td style="width:160px; color:#6c757d;">${escapeHtml(timeText)}</td>
                        <td style="width:140px; font-family:Consolas,monospace;">${escapeHtml(String(t))}</td>
                        <td>${escapeHtml(String(note||''))}</td>
                        <td style="width:140px; font-family:Consolas,monospace; color:#6c757d;">${escapeHtml(String(rpx||''))}</td>
                        <td style="width:220px; color:#6c757d;">${escapeHtml(repText||'')}</td>
                    </tr>`;
                }).join('');
                return `
                    <div id="phTab_audit" style="display:none;">
                        <div style="font-size:8pt; color:#6c757d; margin-bottom:8px;">提示：审计记录保存在 project.json（最多 500 条）。报告文件保存在程序 reports 目录。</div>
                        <table class="table" style="font-size:9pt;">
                            <thead><tr><th style="width:160px;">时间</th><th style="width:140px;">类型</th><th>说明</th><th style="width:140px;">修订点</th><th style="width:220px;">报告</th></tr></thead>
                            <tbody>${rows}</tbody>
                        </table>
                    </div>
                `;
            })();

            body.innerHTML = head + tabBar + overviewHtml + mappingHtml + viewsHtml + policyHtml + auditHtml;
            try { phTab('overview'); } catch (_) { }
            mask.style.display = 'flex';
        }

        function phTab(key) {
            ['overview','mapping','views','policy','audit'].forEach(k => {
                const el = document.getElementById(`phTab_${k}`);
                if (el) el.style.display = (k === key) ? 'block' : 'none';
            });
        }

        function renderProjectDetail(meta) {
            const cards = document.getElementById('projectDetailCards');
            const more = document.getElementById('projectDetailMore');
            const title = document.getElementById('projectDetailTitle');
            if (title) title.textContent = `项目详情：${meta?.DisplayName || meta?.displayName || meta?.Id || ''}`;
            if (!cards || !more) return;

            window.__selectedProjectMeta = meta || null;
            const id = meta?.Id || meta?.id || '';
            const dbPath = meta?.DbPath || meta?.dbPath || '';
            const iniPath = meta?.IniPath || meta?.iniPath || '';
            const dbSize = meta?.DbSizeBytes ?? meta?.dbSizeBytes ?? 0;
            const updatedAt = meta?.UpdatedAt || meta?.updatedAt || '';
            const lastOpenAt = meta?.LastOpenAt || meta?.lastOpenAt || '';
            const sources = meta?.Sources || meta?.sources || [];
            const rawClean = meta?.RawCleanPolicy || meta?.rawCleanPolicy || {};
            const revPol = meta?.RevisionPolicy || meta?.revisionPolicy || {};
            const lastImport = meta?.LastImport || meta?.lastImport || null;
            const dbTables = meta?.DbTables || meta?.dbTables || [];

            const card = (label, value, hint) => `
                <div class="result-info" style="margin:0; background:#ffffff; border:1px solid #e1e4e8; border-left:4px solid #0078d4;">
                    <div style="font-size:8pt; color:#6c757d; margin-bottom:4px;">${escapeHtml(label)}</div>
                    <div style="font-size:9pt; color:#333; font-weight:600; word-break:break-all;">${escapeHtml(value || '-')}</div>
                    ${hint ? `<div style="font-size:8pt; color:#6c757d; margin-top:4px;">${escapeHtml(hint)}</div>` : ''}
                </div>
            `;

            const createdAt = meta?.CreatedAt || meta?.createdAt || '';
            const openCount = meta?.OpenCount ?? meta?.openCount ?? 0;
            const mainSrc = meta?.MainSourceFile || meta?.mainSourceFile || '';
            const mainTbl = meta?.MainTableName || meta?.mainTableName || '';
            const diffRate = meta?.TableDiffRate ?? meta?.tableDiffRate;
            const diffText = (diffRate === undefined || diffRate === null) ? '-' : `${Math.round(Number(diffRate) * 100)}%`;
            cards.innerHTML = [
                card('项目ID', id, ''),
                card('项目名称', meta?.DisplayName || meta?.displayName || '-', ''),
                card('使用频次', String(openCount), ''),
                card('业务库（SQLite）', dbPath, `大小：${formatBytes(dbSize)}`),
                card('配置文件（INI）', iniPath, ''),
                card('创建时间', String(createdAt || '-'), ''),
                card('修改时间', String(updatedAt || '-'), `表差异率：${diffText}`),
                card('源文件基表', mainSrc ? (mainSrc.split('/').pop() || mainSrc) : '-', ''),
                card('数据表基表', mainTbl || '-', '')
            ].join('');

            const renderSources = () => {
                if (!Array.isArray(sources) || !sources.length) return `<div style="color:#6c757d;">（暂无源文件记录）</div>`;
                return `
                    <div style="display:flex; flex-direction:column; gap:8px;">
                        ${sources.map(s => {
                            const fp = s.FilePath || s.filePath || '';
                            const sz = s.FileSizeBytes ?? s.fileSizeBytes ?? 0;
                            const ticks = s.LastWriteUtcTicks ?? s.lastWriteUtcTicks ?? 0;
                            const dt = ticks ? new Date(Number(ticks)/10000 - 62135596800000).toLocaleString() : '';
                            const isMain = !!(s.IsMain ?? s.isMain);
                            const sheets = s.Sheets || s.sheets || [];
                            return `
                                <div style="border:1px solid #e1e4e8; border-radius:4px; padding:10px; background:#fff;">
                                    <div style="display:flex; align-items:center; justify-content:space-between; gap:10px;">
                                        <div style="font-weight:600; color:#333;">${escapeHtml(fp.split('/').pop() || fp)}${isMain ? ' <span style="color:#0078d4;">（主）</span>' : ''}</div>
                                        <div style="font-size:8pt; color:#6c757d;">${formatBytes(sz)}</div>
                                    </div>
                                    <div style="font-size:8pt; color:#6c757d; margin-top:4px; word-break:break-all;">${escapeHtml(fp)}</div>
                                    <div style="font-size:8pt; color:#6c757d; margin-top:4px;">最后修改：${escapeHtml(dt || '-')}</div>
                                    ${Array.isArray(sheets) && sheets.length ? `<div style="font-size:8pt; color:#6c757d; margin-top:4px;">工作表：${escapeHtml(sheets.slice(0,8).join('，'))}${sheets.length>8?'…':''}</div>` : ''}
                                </div>
                            `;
                        }).join('')}
                    </div>
                `;
            };

            const renderMapping = () => {
                const exp = [];
                try {
                    (Array.isArray(sources) ? sources : []).forEach(s => {
                        const fp = (s.FilePath || s.filePath || '');
                        const base = (fp.split('/').pop() || '').replace(/\.(xlsx|xls|csv|tsv)$/i, '');
                        const sheets = (s.Sheets || s.sheets || []);
                        const tnMap = s.TableNameMap || s.tableNameMap || {};
                        const taMap = s.TableAliasMap || s.tableAliasMap || {};
                        (Array.isArray(sheets) ? sheets : []).forEach(sh => {
                            if (!sh) return;
                            const physical = (tnMap && tnMap[sh]) ? String(tnMap[sh]) : `${base}|${sh}`;
                            const alias = (taMap && taMap[sh]) ? String(taMap[sh]) : physical;
                            const show = (alias && alias !== physical) ? `${alias}（${physical}）` : physical;
                            exp.push({
                                file: fp,
                                sheet: sh,
                                table: physical,
                                show: show
                            });
                        });
                    });
                } catch (_) { }
                const actual = new Set((Array.isArray(dbTables) ? dbTables : []).map(x => String(x)));
                const rows = exp.map(r => {
                    const ok = actual.has(r.table);
                    return `<tr>
                        <td style="max-width:220px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;" title="${escapeHtml(r.file)}">${escapeHtml((r.file||'').split('/').pop()||r.file)}</td>
                        <td>${escapeHtml(r.sheet)}</td>
                        <td style="font-family:Consolas,monospace; font-size:8.5pt;" title="${escapeHtml(r.table)}">${escapeHtml(r.show || r.table)}</td>
                        <td>${ok ? '<span style="color:#52c41a;font-weight:700;">✔</span>' : '<span style="color:#faad14;font-weight:700;">✗</span>'}</td>
                        <td style="color:#6c757d;">v1</td>
                        <td style="color:#6c757d;">-</td>
                    </tr>`;
                }).join('');
                if (!exp.length) return '';
                return `
                    <div style="margin-top:10px; border:1px solid #e1e4e8; border-radius:4px; background:#fff; padding:10px;">
                        <div style="font-weight:700; color:#333; margin-bottom:6px;">源文件表清单 ↔ 数据表库清单（对应关系）</div>
                        <div style="font-size:8pt; color:#6c757d; margin-bottom:8px;">说明：期望表名按“{文件名}|{工作表}”生成；差异率为粗略口径（后续接入行数/字段比对后会更准）。</div>
                        <table class="table" style="font-size:9pt;">
                            <thead><tr><th>源文件</th><th>工作表</th><th>对应表名</th><th>存在</th><th>版本号</th><th>信息差异率</th></tr></thead>
                            <tbody>${rows}</tbody>
                        </table>
                    </div>
                `;
            };

            const renderPolicy = () => {
                const mode = rawClean.Mode || rawClean.mode || 'raw+clean';
                const arch = (rawClean.AllowArchiveRaw ?? rawClean.allowArchiveRaw) ? '支持归档 raw' : '不归档 raw';
                const bk = (revPol.EnableSqliteBackup ?? revPol.enableSqliteBackup) ? '启用备份' : '不备份';
                const keep = revPol.KeepLastN ?? revPol.keepLastN ?? '-';
                const maxB = revPol.MaxTotalBytes ?? revPol.maxTotalBytes ?? 0;
                const baseDb = meta?.BaseDbPath || meta?.baseDbPath || '';
                const baseCnt = (meta?.BaseDbTables || meta?.baseDbTables || []).length || 0;
                const rps = (meta?.RevisionPoints || meta?.revisionPoints || []);
                const rpRows = (Array.isArray(rps) ? rps : []).slice(0, 30).map(rp => {
                    const id = rp.Id || rp.id || '';
                    const tm = rp.Time || rp.time || '';
                    const note = rp.Note || rp.note || '';
                    const bytes = rp.DbBackupBytes ?? rp.dbBackupBytes ?? 0;
                    const bkPath = rp.DbBackupPath || rp.dbBackupPath || '';
                    const timeText = tm ? String(tm).replace('T',' ').replace('Z','') : '-';
                    return `<tr>
                        <td style="font-family:Consolas,monospace; font-size:8.5pt;">${escapeHtml(String(id).slice(0,12))}</td>
                        <td style="color:#6c757d;">${escapeHtml(timeText)}</td>
                        <td style="color:#495057; max-width:260px; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;" title="${escapeHtml(note)}">${escapeHtml(note||'-')}</td>
                        <td style="color:#6c757d;">${escapeHtml(formatBytes(Number(bytes)||0))}</td>
                        <td style="text-align:right;">
                          <button class="btn btn-danger" style="padding:2px 8px; font-size:8pt;" onclick="restoreRevisionPoint('${escapeHtml(id)}')">恢复</button>
                        </td>
                    </tr>`;
                }).join('');
                return `
                    <div style="border:1px solid #e1e4e8; border-radius:4px; padding:10px; background:#fff; margin-bottom:10px;">
                        <div style="font-weight:600; color:#333; margin-bottom:6px;">策略</div>
                        <div style="font-size:9pt; color:#495057;">数据分层：<b>${escapeHtml(mode)}</b>（${escapeHtml(arch)}）</div>
                        <div style="font-size:9pt; color:#495057; margin-top:4px;">修订点：<b>${escapeHtml(bk)}</b>，保留最近 <b>${escapeHtml(String(keep))}</b> 份，最大总大小 <b>${escapeHtml(formatBytes(maxB))}</b></div>
                        <div style="font-size:9pt; color:#495057; margin-top:6px;">
                          基础库：<b>${escapeHtml(baseDb ? (baseDb.split('/').pop() || baseDb) : '（未挂载）')}</b>
                          <span style="color:#6c757d;">（${baseDb ? `${baseCnt} 表/视图` : '0'}）</span>
                          <span style="margin-left:10px; display:inline-flex; gap:6px;">
                            <button class="btn btn-secondary" style="padding:2px 8px; font-size:8pt;" onclick="selectBaseDb()">挂载/更换</button>
                            <button class="btn btn-secondary" style="padding:2px 8px; font-size:8pt;" onclick="detachBaseDb()">解除</button>
                          </span>
                        </div>
                    </div>
                    <div style="border:1px solid #e1e4e8; border-radius:4px; padding:10px; background:#fff;">
                        <div style="display:flex; align-items:center; justify-content:space-between; gap:10px;">
                          <div style="font-weight:600; color:#333;">修订点（最近 30）</div>
                          <button class="btn btn-secondary" style="padding:2px 8px; font-size:8pt;" onclick="createRevisionPoint('manual','项目中心手动创建')">手动创建</button>
                        </div>
                        <div style="font-size:8pt; color:#6c757d; margin-top:4px;">提示：重命名/删除数据库对象会自动创建修订点；恢复会覆盖当前业务库并重新载入。</div>
                        <table class="table" style="font-size:9pt; margin-top:8px;">
                          <thead><tr><th style="width:90px;">ID</th><th style="width:160px;">时间</th><th>备注</th><th style="width:90px;">大小</th><th style="width:80px; text-align:right;">操作</th></tr></thead>
                          <tbody>${rpRows || '<tr><td colspan=5 style=\"color:#6c757d;\">（暂无修订点）</td></tr>'}</tbody>
                        </table>
                    </div>
                `;
            };

            const renderLastImport = () => {
                if (!lastImport) return '';
                const bid = lastImport.BatchId || lastImport.batchId || '';
                const tm = lastImport.Time || lastImport.time || '';
                const im = lastImport.ImportMode || lastImport.importMode || '';
                const clr = (lastImport.ClearedBeforeImport ?? lastImport.clearedBeforeImport) ? '清空后导入' : '不清空';
                const cnt = lastImport.ImportedTables ?? lastImport.importedTables ?? 0;
                return `
                    <div style="border:1px solid #e1e4e8; border-radius:4px; padding:10px; background:#fff; margin-bottom:10px;">
                        <div style="font-weight:600; color:#333; margin-bottom:6px;">最近导入批次</div>
                        <div style="font-size:9pt; color:#495057;">批次：<b>${escapeHtml(bid || '-')}</b>｜模式：<b>${escapeHtml(im || '-')}</b>｜${escapeHtml(clr)}｜表数：<b>${escapeHtml(String(cnt))}</b></div>
                        <div style="font-size:8pt; color:#6c757d; margin-top:4px;">时间：${escapeHtml(String(tm || '-'))}</div>
                    </div>
                `;
            };

            more.innerHTML = renderPolicy() + renderLastImport() + renderSources() + renderMapping();

            // 当前活动项目视图：左侧“当前激活项目”盒子
            try {
                const actBox = document.getElementById('activeProjectBox');
                const activeId = window.__activeSchemeId || '';
                if (actBox) {
                    actBox.innerHTML = `
                        <div style="border:1px solid #e1e4e8; border-radius:4px; padding:10px; background:#fff;">
                          <div style="font-weight:700; color:#333;">${escapeHtml(activeId || '（无）')}</div>
                          <div style="font-size:8pt; color:#6c757d; margin-top:4px;">当前激活：${activeId ? '是' : '否'}</div>
                          <div style="font-size:8pt; color:#6c757d; margin-top:4px;">表/视图数：${escapeHtml(String(Array.isArray(dbTables)?dbTables.length:0))}</div>
                          <div style="margin-top:8px; display:flex; gap:8px; flex-wrap:wrap;">
                            <button class="btn btn-success" style="padding:2px 8px; font-size:8pt;" onclick="openSelectedProject()">加载/打开</button>
                            <button class="btn btn-primary" style="padding:2px 8px; font-size:8pt;" onclick="(function(){switchTab('file-wizard'); try{fwPage('sources');}catch(_){}})()">编辑项目（源文件关系）</button>
                            <button class="btn btn-secondary" style="padding:2px 8px; font-size:8pt;" onclick="(function(){switchTab('file-wizard'); try{fwPage('import');}catch(_){}})()">导入/重导数据库</button>
                            <button class="btn btn-secondary" style="padding:2px 8px; font-size:8pt;" onclick="switchTab('model-management')">建模管理</button>
                            <button class="btn btn-secondary" style="padding:2px 8px; font-size:8pt;" onclick="switchTab('sql-editor')">SQL实验室</button>
                          </div>
                        </div>
                    `;
                }
            } catch (_) { }

            // 配置视图：快照
            try {
                const snap = document.getElementById('projectConfigSnapshot');
                if (snap) {
                    const tList = Array.isArray(dbTables) ? dbTables.slice(0, 50) : [];
                    snap.innerHTML = `
                        <div style="border:1px solid #e1e4e8; border-radius:4px; padding:10px; background:#fff;">
                          <div style="font-weight:700; color:#333; margin-bottom:6px;">核心定位</div>
                          <div>源文件基表：<b>${escapeHtml((meta.MainSourceFile||meta.mainSourceFile||'-'))}</b></div>
                          <div>数据表基表：<b>${escapeHtml((meta.MainTableName||meta.mainTableName||'-'))}</b></div>
                          <div style="margin-top:10px; font-weight:700; color:#333;">表/视图清单（前 50）</div>
                          <div style="margin-top:6px; font-family:Consolas,monospace; font-size:8.5pt; color:#495057; white-space:pre-wrap;">${escapeHtml(tList.join('\\n') || '（无）')}</div>
                        </div>
                    `;
                }
            } catch (_) { }
        }

        function ensureSchemeNameAuto() {
            const input = document.getElementById('schemeNameInput');
            if (!input) return '';
            const v = (input.value || '').trim();
            if (v) return v;
            // 智能生成：主表文件名 + 主表工作表
            const m = window.__fileWizardMain || null;
            const base = m?.filePath ? (m.filePath.split('/').pop().split('\\\\').pop()) : '项目';
            const sheet = m?.sheetName ? m.sheetName : '';
            const name = sheet ? `${base} - ${sheet}` : `${base}`;
            input.value = name;
            return name;
        }

