        function updateSchemeDbPathHint() {
            const el = document.getElementById('schemeDbPathHint');
            if (!el) return;
            const id = window.__activeSchemeId || '';
            const db = window.__activeSchemeDbPath || '';
            const dc = window.__dataConfigDir || '';
            if (!id) {
                el.textContent = '临时数据库：未绑定（请先保存/加载项目）';
                return;
            }
            if (db) {
                el.textContent = `临时数据库：${db}`;
                return;
            }
            if (dc) {
                el.textContent = `临时数据库：${dc.replace(/\/+$/,'')}/db/${id}.db`;
                return;
            }
            el.textContent = `临时数据库：${id}.db`;
        }
        
