        // ==================== 批量处理功能 ====================
        let batchCurrentStep = 1;
        const batchMaxSteps = 3;
        
        // 批量处理：下一步
        function nextBatchStep(step) {
            if (step < batchMaxSteps) {
                document.querySelector(`.step[data-step="bp${step}"]`).classList.remove('active');
                document.querySelector(`.step[data-step="bp${step}"]`).classList.add('completed');
                document.getElementById(`step-bp${step}`).classList.remove('active');
                
                batchCurrentStep = step + 1;
                document.querySelector(`.step[data-step="bp${batchCurrentStep}"]`).classList.add('active');
                document.getElementById(`step-bp${batchCurrentStep}`).classList.add('active');
            }
        }
        
        // 批量处理：上一步
        function prevBatchStep(step) {
            if (step > 1) {
                document.querySelector(`.step[data-step="bp${step}"]`).classList.remove('active');
                document.getElementById(`step-bp${step}`).classList.remove('active');
                
                batchCurrentStep = step - 1;
                document.querySelector(`.step[data-step="bp${batchCurrentStep}"]`).classList.remove('completed');
                document.querySelector(`.step[data-step="bp${batchCurrentStep}"]`).classList.add('active');
                document.getElementById(`step-bp${batchCurrentStep}`).classList.add('active');
            }
        }
        
