        // 批量处理：应用作业模板
        function applyBatchJobTemplate(templateName) {
            if (!templateName) return;
            
            const templates = {
                'monthly-report': {
                    taskType: 'multi-task',
                    steps: ['dc-field', 'data-validation', 'data-export'],
                    outputType: 'folder'
                },
                'data-sync': {
                    taskType: 'dc-field',
                    template: 'standard',
                    outputType: 'new'
                },
                'quality-check': {
                    taskType: 'file-analysis',
                    outputType: 'new'
                },
                'format-standard': {
                    taskType: 'format-convert',
                    outputType: 'overwrite'
                }
            };
            
            const config = templates[templateName];
            if (config) {
                document.getElementById('batchTaskType').value = config.taskType;
                updateBatchTaskConfig(config.taskType);
                
                if (config.steps && config.steps.length > 0) {
                    // 清空并重新添加步骤
                    const container = document.getElementById('batchTaskFlowList');
                    container.innerHTML = '';
                    config.steps.forEach((step, index) => {
                        const stepNames = {
                            'dc-field': '字段格式清洗',
                            'dc-quality': '数据质量清洗',
                            'dc-verify': '业务规则验证',
                            'data-validation': '数据验证',
                            'data-export': '数据导出'
                        };
                        const newStep = document.createElement('div');
                        newStep.className = 'batch-flow-item';
                        newStep.style.cssText = 'display: flex; align-items: center; gap: 8px; padding: 8px; background: white; border: 1px solid #d9d9d9; border-radius: 4px; cursor: move;';
                        newStep.innerHTML = `
                            <span style="color: #1890ff; font-weight: bold;">${index + 1}</span>
                            <span style="flex: 1;">${stepNames[step] || step}</span>
                            <button class="btn btn-danger" style="padding: 2px 6px; font-size: 8pt;" onclick="this.parentElement.remove(); updateFlowNumbers();">删除</button>
                        `;
                        container.appendChild(newStep);
                    });
                }
                
                alert(`已应用 "${templateName}" 作业模板`);
            }
        }
        
