        function stripSqlComments(s) {
            return String(s || '')
                .replace(/--.*$/gm, '')
                .replace(/\/\*[\s\S]*?\*\//g, '');
        }
        function classifyDangerousSql(sql) {
            const s = stripSqlComments(sql).trim().toLowerCase();
            if (!s) return { kind: 'none' };
            if (/\\b(drop|alter)\\b/.test(s)) return { kind: 'ddlDanger' };
            if (/\\bdelete\\b/.test(s) && !/\\bwhere\\b/.test(s)) return { kind: 'dmlNoWhere', verb: 'DELETE' };
            if (/\\bupdate\\b/.test(s) && !/\\bwhere\\b/.test(s)) return { kind: 'dmlNoWhere', verb: 'UPDATE' };
            return { kind: 'none' };
        }

        function sqlLabCommit() {
            if (!window.__sqlLabTxnOpen) return;
            const ok = confirm('确认提交当前未提交的变更吗？（提交后将不可一键回滚）');
            if (!ok) return;
            window.__sqlLabLastTxnAction = 'commit';
            try { window.chrome.webview.postMessage({ action: 'sqlLabCommit' }); } catch (_) { }
        }
        function sqlLabRollback() {
            if (!window.__sqlLabTxnOpen) return;
            const ok = confirm('确认回滚当前未提交的变更吗？');
            if (!ok) return;
            window.__sqlLabLastTxnAction = 'rollback';
            try { window.chrome.webview.postMessage({ action: 'sqlLabRollback' }); } catch (_) { }
        }

        // 事务自动回滚：避免用户长时间忘记提交/回滚
        function sqlLabArmTxnTimeout() {
            try {
                if (window.__sqlLabTxnTimeoutHandle) clearTimeout(window.__sqlLabTxnTimeoutHandle);
            } catch (_) { }
            if (!window.__sqlLabTxnOpen) return;
            const ms = 10 * 60 * 1000; // 10分钟
            window.__sqlLabTxnTimeoutHandle = setTimeout(() => {
                if (window.__sqlLabTxnOpen) {
                    alert('检测到未提交事务已超过 10 分钟：系统将自动回滚以避免误操作。');
                    try { sqlLabRollback(); } catch (_) { }
                }
            }, ms);
        }
        
        // 格式化SQL
        function formatSql() {
            let sql = sqlEditorGetText();
            
            // 轻量 SQL 格式化（不引入外部库，尽量“可读但不破坏语义”）
            const raw = sql;
            sql = sql.replace(/\r\n/g, '\n');
            sql = sql.replace(/[ \t]+/g, ' ');
            sql = sql.replace(/\s*,\s*/g, ', ');
            sql = sql.replace(/\s*\(\s*/g, '(');
            sql = sql.replace(/\s*\)\s*/g, ')');

            // 关键字大写（保守：只处理常见关键字）
            const kw = [
                'select','from','where','group by','having','order by','limit','offset',
                'inner join','left join','right join','full join','join','on',
                'and','or','union','union all','distinct'
            ];
            // 先处理长关键字
            kw.sort((a,b)=>b.length-a.length).forEach(k=>{
                const r = new RegExp('\\b' + k.replace(' ', '\\s+') + '\\b', 'gi');
                sql = sql.replace(r, k.toUpperCase());
            });

            // 换行规则（尽量不动字符串常量：这里只做简单启发式）
            const breakBefore = [
                'SELECT','FROM','WHERE','GROUP BY','HAVING','ORDER BY','LIMIT','OFFSET',
                'INNER JOIN','LEFT JOIN','RIGHT JOIN','FULL JOIN','JOIN'
            ];
            breakBefore.forEach(k=>{
                const r = new RegExp('\\s+' + k + '\\b', 'g');
                sql = sql.replace(r, '\n' + k);
            });
            // ON/AND/OR 换行并缩进
            sql = sql.replace(/\s+ON\b/g, '\n  ON');
            sql = sql.replace(/\s+AND\b/g, '\n  AND');
            sql = sql.replace(/\s+OR\b/g, '\n  OR');

            // 逗号后按列换行（仅在 SELECT 段落做启发式处理）
            try {
                const m = sql.match(/SELECT[\s\S]*?FROM\b/);
                if (m && m[0]) {
                    const seg = m[0];
                    const body = seg.replace(/^SELECT\s*/,'').replace(/\s*FROM\b/,'');
                    const cols = body.split(',').map(s=>s.trim()).filter(Boolean);
                    if (cols.length >= 4) {
                        const rebuilt = 'SELECT\n  ' + cols.join(',\n  ') + '\nFROM';
                        sql = sql.replace(seg, rebuilt);
                    }
                }
            } catch (_) { }

            sql = sql.replace(/\n{3,}/g, '\n\n').trim() + '\n';
            
            sqlEditorSetText(sql);
        }

        // ===== SQL编辑器：表结构树 & 结果复制 =====
        // SQLite 标识符引用：支持 schema.table（例如 base.Customer），分别用 [] 包裹每一段
        function sqlQuoteIdent(name) {
            const raw = String(name || '').trim();
            if (!raw) return '[_]';
            // 已包含 [] 的情况按原样引用（避免重复包裹）
            if (raw.includes('[') || raw.includes(']')) return raw;
            if (raw.includes('.')) {
                return raw.split('.')
                    .filter(Boolean)
                    .map(p => `[${String(p).replace(/]/g, ']]')}]`)
                    .join('.');
            }
            return `[${raw.replace(/]/g, ']]')}]`;
        }

        function sqlEditorInsertText(text) {
            const ins = String(text || '');
            const cm = window.__cmSqlEditor || null;
            if (cm) {
                const cur = cm.getCursor();
                cm.replaceRange(ins, cur, cur, '+input');
                cm.focus();
                try { updateSqlEditorCursor(); } catch (_) { }
                return;
            }
            const ta = document.getElementById('sqlEditorTextarea');
            if (!ta) return;
            const v = ta.value || '';
            const start = ta.selectionStart || 0;
            const end = ta.selectionEnd || 0;
            ta.value = v.slice(0, start) + ins + v.slice(end);
            const pos = start + ins.length;
            ta.selectionStart = ta.selectionEnd = pos;
            ta.focus();
            try { updateSqlEditorCursor(); } catch (_) { }
        }

        // ===== SQL编辑器：自动补全（Ctrl+Space） =====
        const __sqlKeywords = [
            'SELECT','FROM','WHERE','GROUP BY','HAVING','ORDER BY','LIMIT','OFFSET',
            'JOIN','INNER JOIN','LEFT JOIN','RIGHT JOIN','FULL JOIN','ON',
            'AND','OR','NOT','IN','LIKE','IS NULL','IS NOT NULL','DISTINCT',
            'COUNT','SUM','AVG','MIN','MAX',
            'UPDATE','DELETE','INSERT INTO','VALUES','CREATE TABLE','DROP TABLE','ALTER TABLE'
        ];

        function sqlGetTokenBeforeCursor(text, pos) {
            const left = text.slice(0, pos);
            // 支持中文/字母/数字/_/. 和 []
            const m = left.match(/([A-Za-z0-9_\u4e00-\u9fa5\.\[\]]+)$/);
            return m ? m[1] : '';
        }

        function sqlGetSuggestList(prefix) {
            // 兼容旧调用：无上下文时按默认上下文
            return sqlGetSuggestListWithContext(prefix, null);
        }

        function sqlParseAliasMap(sql) {
            // 轻量解析：抓 FROM/JOIN 后的表名与别名（支持 [表名] / "表名" / `表名` / 普通 token）
            const map = {};
            const s = stripSqlComments(sql || '');
            const rx = /\b(from|join)\s+(\[[^\]]+\]|"[^"]+"|`[^`]+`|[A-Za-z0-9_\u4e00-\u9fa5\$]+)(?:\s+(?:as\s+)?([A-Za-z][A-Za-z0-9_]*))?/gi;
            let m;
            while ((m = rx.exec(s)) !== null) {
                let table = (m[2] || '').trim();
                let alias = (m[3] || '').trim();
                if (table.startsWith('[') && table.endsWith(']')) table = table.slice(1, -1).replace(']]', ']');
                else if (table.startsWith('"') && table.endsWith('"')) table = table.slice(1, -1).replace('""', '"');
                else if (table.startsWith('`') && table.endsWith('`')) table = table.slice(1, -1);
                if (!table) continue;
                if (!alias) alias = table; // 无别名时用表名占位
                map[alias] = table;
            }
            return map;
        }

        function sqlDetectContext(sql, pos) {
            const left = String(sql || '').slice(0, pos);
            const clean = stripSqlComments(left).toLowerCase();
            const token = sqlGetTokenBeforeCursor(sql, pos);

            // 识别 A.xxx 的情况
            const dotIdx = token.lastIndexOf('.');
            if (dotIdx > 0) {
                return { type: 'qualified', qualifier: token.slice(0, dotIdx), prefix: token.slice(dotIdx + 1) };
            }

            // 找最近关键字（简单启发式）
            const m = clean.match(/\b(from|join|where|on|update|into)\b(?![\s\S]*\b(from|join|where|on|update|into)\b)/i);
            const lastKw = m ? String(m[1]).toUpperCase() : '';
            if (lastKw === 'FROM' || lastKw === 'JOIN' || lastKw === 'UPDATE' || lastKw === 'INTO') return { type: 'tables', prefix: token };
            if (lastKw === 'WHERE' || lastKw === 'ON') return { type: 'fields', prefix: token };
            return { type: 'general', prefix: token };
        }

        function sqlGetSuggestListWithContext(prefix, ctx) {
            const p = (prefix || '').toLowerCase();
            const out = [];
            const tables = Array.isArray(window.__sqliteTables) ? window.__sqliteTables : [];
            const schemas = window.__sqliteTableSchemas || {};
            const aliasMap = ctx?.aliasMap || {};

            const pushKeywords = () => __sqlKeywords.forEach(k => out.push({ label: k, insert: k, kind: 'kw' }));
            const pushTables = () => tables.forEach(t => out.push({ label: t, insert: sqlQuoteIdent(t), kind: 'table' }));

            const pushFieldsForTable = (qualifier, tableName, qualifierIsAlias) => {
                const sc = Array.isArray(schemas[tableName]) ? schemas[tableName] : null;
                if (!sc) return;
                sc.forEach(c => {
                    const nm = c.name || c.ColumnName || '';
                    if (!nm) return;
                    const left = qualifierIsAlias ? qualifier : sqlQuoteIdent(tableName);
                    out.push({
                        label: `${qualifier}.${nm}`,
                        insert: `${left}.${sqlQuoteIdent(nm)}`,
                        kind: 'field'
                    });
                });
            };

            if (ctx?.type === 'qualified') {
                const q = ctx.qualifier;
                const fPrefix = (ctx.prefix || '').toLowerCase();
                // qualifier 可能是别名或表名
                const table = aliasMap[q] || tables.find(t => t === q) || '';
                if (table) {
                    pushFieldsForTable(q, table, !!aliasMap[q]);
                } else {
                    // fallback：所有字段
                    tables.forEach(t => pushFieldsForTable(t, t, false));
                }
                // 过滤用 prefixAfterDot
                return out
                    .filter(x => !fPrefix || (x.label || '').toLowerCase().includes(fPrefix))
                    .slice(0, 40);
            }

            if (ctx?.type === 'tables') {
                pushTables();
            } else if (ctx?.type === 'fields') {
                // 优先：已解析到的别名表字段；否则所有表字段
                const usedTables = Array.from(new Set(Object.values(aliasMap)));
                const baseTables = usedTables.length ? usedTables : tables;
                baseTables.forEach(t => pushFieldsForTable(t, t, false));
                pushKeywords();
            } else {
                // general
                pushKeywords();
                pushTables();
                const usedTables = Array.from(new Set(Object.values(aliasMap)));
                const baseTables = usedTables.length ? usedTables : tables;
                baseTables.forEach(t => pushFieldsForTable(t, t, false));
            }

            const filtered = p ? out.filter(x => (x.label || '').toLowerCase().includes(p)) : out;
            // 去重
            const seen = new Set();
            const uniq = [];
            filtered.forEach(x => {
                const key = x.kind + '|' + x.label;
                if (seen.has(key)) return;
                seen.add(key);
                uniq.push(x);
            });
            // 排序：前缀匹配优先
            uniq.sort((a, b) => {
                const al = (a.label || '').toLowerCase();
                const bl = (b.label || '').toLowerCase();
                const as = p && al.startsWith(p) ? 0 : 1;
                const bs = p && bl.startsWith(p) ? 0 : 1;
                if (as !== bs) return as - bs;
                return al.localeCompare(bl);
            });
            return uniq.slice(0, 40);
        }

        function sqlShowAutocompleteAtCaret() {
            const box = document.getElementById('sqlAutoComplete');
            if (!box) return;

            const cm = window.__cmSqlEditor || null;
            const ta = document.getElementById('sqlEditorTextarea');
            const text = cm ? (cm.getValue() || '') : (ta?.value || '');
            if (!text) { sqlHideAutocomplete(); return; }

            let token = '';
            let pos = 0;
            if (cm) {
                const cur = cm.getCursor();
                const line = cm.getLine(cur.line) || '';
                const prefix = line.slice(0, cur.ch);
                token = (prefix.match(/([A-Za-z0-9_\u4e00-\u9fa5\.\[\]]+)$/) || [])[1] || '';
                // pos 仅用于兼容字段，不再严格依赖
                pos = cur.ch;
            } else {
                pos = ta?.selectionStart || 0;
                token = sqlGetTokenBeforeCursor(text, pos);
            }

            const aliasMap = sqlParseAliasMap(text);
            const ctx = sqlDetectContext(text, cm ? (cm.indexFromPos(cm.getCursor()) || 0) : pos);
            ctx.aliasMap = aliasMap;
            const list = sqlGetSuggestListWithContext(token, ctx);
            if (!list.length) { sqlHideAutocomplete(); return; }

            window.__sqlAc = { list, idx: 0, token, pos, isCm: !!cm };

            box.innerHTML = list.map((x, i) => `
                <div class="sql-ac-item" data-idx="${i}" style="padding:8px 10px; cursor:pointer; display:flex; gap:10px; align-items:center; ${i===0?'background:#e7f3ff;':''}"
                     onmouseenter="sqlAcHighlight(${i})"
                     onclick="sqlAcPick(${i})">
                    <span style="display:inline-block; width:52px; font-size:8pt; color:#6c757d;">${x.kind}</span>
                    <span style="flex:1; font-family:Consolas,Monaco,monospace; font-size:9pt;">${escapeHtml(x.label)}</span>
                </div>
            `).join('');
            box.style.display = 'block';
            // 定位到光标附近
            try {
                const host = box.parentElement; // 绝对定位容器
                const hostRect = host.getBoundingClientRect();
                let left = 12, top = 12;
                if (cm) {
                    const cc = cm.cursorCoords(null, 'page');
                    left = (cc.left - hostRect.left) + 0;
                    top = (cc.bottom - hostRect.top) + 6;
                } else {
                    const co = sqlGetTextareaCaretPos(ta, pos);
                    const taRect = ta.getBoundingClientRect();
                    left = (taRect.left - hostRect.left) + co.left;
                    top = (taRect.top - hostRect.top) + co.top + co.height + 6;
                }
                // 防止溢出
                const maxLeft = (host.clientWidth || 500) - 380;
                left = Math.max(8, Math.min(left, maxLeft));
                const maxTop = (host.clientHeight || 300) - 260;
                top = Math.max(8, Math.min(top, maxTop));
                box.style.left = `${left}px`;
                box.style.top = `${top}px`;
            } catch (_) {
                box.style.left = '12px';
                box.style.top = '12px';
            }
        }

        // 计算 textarea 光标坐标（相对 textarea 内容区）
        function sqlGetTextareaCaretPos(ta, pos) {
            const div = document.createElement('div');
            const style = window.getComputedStyle(ta);
            const props = [
                'boxSizing', 'width', 'height',
                'overflowX', 'overflowY',
                'borderTopWidth','borderRightWidth','borderBottomWidth','borderLeftWidth',
                'paddingTop','paddingRight','paddingBottom','paddingLeft',
                'fontStyle','fontVariant','fontWeight','fontStretch','fontSize','fontSizeAdjust','lineHeight',
                'fontFamily','textAlign','textTransform','textIndent','textDecoration',
                'letterSpacing','wordSpacing','tabSize','MozTabSize'
            ];
            div.style.position = 'absolute';
            div.style.visibility = 'hidden';
            div.style.whiteSpace = 'pre-wrap';
            div.style.wordWrap = 'break-word';
            props.forEach(p => { div.style[p] = style[p]; });
            div.style.left = '-9999px';
            div.style.top = '0';
            div.textContent = (ta.value || '').substring(0, pos);
            const span = document.createElement('span');
            span.textContent = (ta.value || '').substring(pos) || '.';
            div.appendChild(span);
            document.body.appendChild(div);
            // 考虑滚动
            const left = span.offsetLeft - ta.scrollLeft;
            const top = span.offsetTop - ta.scrollTop;
            const height = span.offsetHeight || parseFloat(style.lineHeight) || 16;
            document.body.removeChild(div);
            return { left, top, height };
        }

        function sqlHideAutocomplete() {
            const box = document.getElementById('sqlAutoComplete');
            if (box) box.style.display = 'none';
            window.__sqlAc = null;
        }

        function sqlAcHighlight(i) {
            const box = document.getElementById('sqlAutoComplete');
            if (!box || !window.__sqlAc) return;
            window.__sqlAc.idx = i;
            box.querySelectorAll('.sql-ac-item').forEach(el => {
                el.style.background = (Number(el.dataset.idx) === i) ? '#e7f3ff' : '#fff';
            });
        }

        function sqlAcPick(i) {
            if (!window.__sqlAc) return;
            const cm = window.__cmSqlEditor || null;
            const ta = document.getElementById('sqlEditorTextarea');
            const item = window.__sqlAc.list[i];
            if (!item) return;
            const ins = item.insert;
            if (cm) {
                const cur = cm.getCursor();
                const token = window.__sqlAc.token || '';
                const start = { line: cur.line, ch: Math.max(0, cur.ch - token.length) };
                cm.replaceRange(ins, start, cur, '+input');
                cm.focus();
            } else {
                if (!ta) return;
                const pos = ta.selectionStart || 0;
                const token = sqlGetTokenBeforeCursor(ta.value || '', pos);
                const start = pos - token.length;
                const v = ta.value || '';
                ta.value = v.slice(0, start) + ins + v.slice(pos);
                const newPos = start + ins.length;
                ta.selectionStart = ta.selectionEnd = newPos;
                ta.focus();
            }
            try { updateSqlEditorCursor(); } catch (_) { }
            sqlHideAutocomplete();
        }

        function bindSqlEditorAutocomplete() {
            // textarea fallback：无 CodeMirror 时使用
            const ta = document.getElementById('sqlEditorTextarea');
            if (!ta) return;
            ta.addEventListener('keydown', (e) => {
                if (e.ctrlKey && e.code === 'Space') {
                    e.preventDefault();
                    sqlShowAutocompleteAtCaret();
                    return;
                }
                if (window.__sqlAc) {
                    if (e.key === 'Escape') { e.preventDefault(); sqlHideAutocomplete(); return; }
                    if (e.key === 'ArrowDown') { e.preventDefault(); sqlAcHighlight(Math.min(window.__sqlAc.idx + 1, window.__sqlAc.list.length - 1)); return; }
                    if (e.key === 'ArrowUp') { e.preventDefault(); sqlAcHighlight(Math.max(window.__sqlAc.idx - 1, 0)); return; }
                    if (e.key === 'Enter' || e.key === 'Tab') { e.preventDefault(); sqlAcPick(window.__sqlAc.idx); return; }
                }
            });
            ta.addEventListener('blur', () => { setTimeout(() => sqlHideAutocomplete(), 150); });
        }

        // ===== SQL编辑器：CodeMirror 初始化与统一读写 =====
        function sqlEditorGetText() {
            const cm = window.__cmSqlEditor || null;
            if (cm) return cm.getValue() || '';
            return document.getElementById('sqlEditorTextarea')?.value || '';
        }
        function sqlEditorSetText(text) {
            const cm = window.__cmSqlEditor || null;
            const v = String(text || '');
            const ta = document.getElementById('sqlEditorTextarea');
            if (ta) ta.value = v;
            if (cm) cm.setValue(v);
        }

        function initSqlCodeEditor() {
            const ta = document.getElementById('sqlEditorTextarea');
            if (!ta) return;
            // 若 CodeMirror 未加载，退化为原 textarea
            if (!window.CodeMirror) {
                try { bindSqlEditorAutocomplete(); } catch (_) { }
                ta.addEventListener('keyup', () => { try { updateSqlEditorCursor(); } catch (_) { } });
                ta.addEventListener('click', () => { try { updateSqlEditorCursor(); } catch (_) { } });
                // 拖放：从表结构/字段拖到编辑区
                try { sqlEditorEnableDropOnElement(ta, false); } catch (_) { }
                return;
            }
            // 已初始化则跳过
            if (window.__cmSqlEditor) return;
            const cm = window.CodeMirror.fromTextArea(ta, {
                mode: 'text/x-sql',
                lineNumbers: true,
                indentUnit: 2,
                tabSize: 2,
                smartIndent: true,
                matchBrackets: true,
                autoCloseBrackets: true,
                lineWrapping: true,
                extraKeys: {
                    'Ctrl-Enter': () => { try { executeSqlEditor(); } catch (_) { } },
                    'Ctrl-Space': () => { try { sqlShowAutocompleteAtCaret(); } catch (_) { } },
                    'Esc': () => { try { sqlHideAutocomplete(); } catch (_) { } },
                    'Ctrl-F': 'findPersistent',
                    'Ctrl-H': 'replace',
                }
            });
            window.__cmSqlEditor = cm;
            cm.on('cursorActivity', () => { try { updateSqlEditorCursor(); } catch (_) { } });
            cm.on('change', () => { try { updateSqlEditorCursor(); } catch (_) { } });
            // 拖放：从表结构/字段拖到编辑区（支持按投放位置插入）
            try { sqlEditorEnableDropOnElement(cm.getWrapperElement(), true); } catch (_) { }
            // 保持右侧提示文案一致
            try { updateSqlEditorCursor(); } catch (_) { }
        }

        // ===== 向导/模块内的 SQL 区域：统一使用 CodeMirror 高亮 =====
        function initWizardSqlEditors() {
            const ids = ['stqQuerySqlText', 'mtqQuerySqlText', 'mtqlQuerySqlText', 'mtslQuerySqlText', 'stsQuerySqlText', 'mtsQuerySqlText'];
            if (!window.CodeMirror) return;
            window.__cmWizardEditors = window.__cmWizardEditors || {};
            ids.forEach(id => {
                const ta = document.getElementById(id);
                if (!ta) return;
                if (window.__cmWizardEditors[id]) {
                    try { window.__cmWizardEditors[id].refresh(); } catch (_) { }
                    return;
                }
                try {
                    const cm = window.CodeMirror.fromTextArea(ta, {
                        mode: 'text/x-sql',
                        lineNumbers: false,
                        lineWrapping: true,
                        matchBrackets: true,
                        autoCloseBrackets: true,
                    });
                    // 保证现有逻辑继续读取 textarea.value（cm.save 会同步回 textarea）
                    // 同时：让原有 oninput="xxxMarkSqlDirty()" 生效（CodeMirror 变更不会触发 textarea input）
                    cm.on('change', () => {
                        try { cm.save(); } catch (_) { }
                        if (window.__wizardSqlProgrammaticUpdate) return;
                        try {
                            const ev = new Event('input', { bubbles: true });
                            ta.dispatchEvent(ev);
                        } catch (_) {
                            try { ta.dispatchEvent(new Event('input')); } catch (_) { }
                        }
                    });
                    // 初始高度：尽量贴合原 textarea
                    const h = ta.offsetHeight && ta.offsetHeight > 40 ? ta.offsetHeight : 120;
                    cm.setSize('100%', h);
                    window.__cmWizardEditors[id] = cm;
                } catch (_) { }
            });
        }

        // 向导 SQL 文本框：统一写入（兼容 CodeMirror）
        function wizardSqlSetValue(textareaId, value) {
            const v = (value == null) ? '' : String(value);
            const ta = document.getElementById(textareaId);
            if (ta) ta.value = v;
            const cm = window.__cmWizardEditors ? window.__cmWizardEditors[textareaId] : null;
            if (cm) {
                try {
                    window.__wizardSqlProgrammaticUpdate = true;
                    if (cm.getValue() !== v) cm.setValue(v);
                    try { cm.save(); } catch (_) { }
                    try { cm.refresh(); } catch (_) { }
                } finally {
                    window.__wizardSqlProgrammaticUpdate = false;
                }
            }
        }

        function sqlSchemaDomId(s) {
            // 简易安全ID（不含中文/符号）
            return 't_' + btoa(unescape(encodeURIComponent(String(s || '')))).replace(/=+/g, '').replace(/[+/]/g, '_');
        }

        function refreshSqlEditorSchemaPanel() {
            const box = document.getElementById('sqlEditorSchema');
            if (!box) return;
            const tables = Array.isArray(window.__sqliteTables) ? window.__sqliteTables : [];
            const schemas = window.__sqliteTableSchemas || {};
            const q = String(document.getElementById('sqlSchemaSearch')?.value || '').trim().toLowerCase();
            if (!tables.length) {
                box.style.color = '#6c757d';
                box.innerHTML = '（尚未加载，请先在【项目管理】导入 SQLite 或刷新表列表）';
                return;
            }
            box.style.color = '#333';
            const filteredTables = q
                ? tables.filter(t => {
                    const tn = String(t || '').toLowerCase();
                    if (tn.includes(q)) return true;
                    const sc = Array.isArray(schemas[t]) ? schemas[t] : null;
                    if (!sc) return false;
                    return sc.some(c => String(c?.name || c?.ColumnName || '').toLowerCase().includes(q));
                })
                : tables;
            box.innerHTML = filteredTables.map(t => {
                const id = sqlSchemaDomId(t);
                const schema = Array.isArray(schemas[t]) ? schemas[t] : null;
                const arrow = schema ? '▼' : '▶';
                const fieldsHtml = schema ? schema.map(c => {
                    const nm = c.name || c.ColumnName || '';
                    const tp = (c.type || c.DataType || '').toUpperCase();
                    if (q) {
                        const hit = String(nm || '').toLowerCase().includes(q) || String(t || '').toLowerCase().includes(q);
                        if (!hit) return '';
                    }
                    const ins = { table: t, field: nm };
                    const dragPayload = {
                        kind: 'field',
                        table: t,
                        field: nm,
                        insertBare: sqlQuoteIdent(nm),
                        insertQualified: (function () {
                            // 默认用“别名优先”的插入规则（与双击一致）
                            let qualifier = '';
                            try {
                                const sql = sqlEditorGetText();
                                const aliasMap = sqlParseAliasMap(sql);
                                const aliases = Object.keys(aliasMap || {}).filter(a => aliasMap[a] === t);
                                qualifier = aliases.find(a => /^[A-Za-z_][A-Za-z0-9_]*$/.test(a)) || '';
                            } catch (_) { }
                            return qualifier ? `${qualifier}.${sqlQuoteIdent(nm)}` : `${sqlQuoteIdent(t)}.${sqlQuoteIdent(nm)}`;
                        })(),
                        insertText: sqlQuoteIdent(nm)
                    };
                    return `<div style="color:#666; padding:2px 0; cursor:grab;"
                                draggable="true"
                                ondragstart="sqlEditorDragStartJson(event, ${JSON.stringify(dragPayload).replace(/</g,'\\\\u003c')})"
                                ondblclick="sqlEditorInsertField(${JSON.stringify(ins.table).replace(/</g,'\\\\u003c')}, ${JSON.stringify(ins.field).replace(/</g,'\\\\u003c')})"
                                title="双击插入字段；拖放插入（按住 Alt 仅插入字段名）">• ${escapeHtml(nm)}${tp ? ` <span style=&quot;color:#999;&quot;>(${escapeHtml(tp)})</span>` : ''}</div>`;
                }).join('') : `<div style="color:#6c757d; padding:4px 0;">（点击加载字段）</div>`;
                const dragTablePayload = { kind: 'table', table: t, insertText: sqlQuoteIdent(t) };
                return `
                    <div style="margin-bottom: 8px;">
                        <div style="font-weight:bold; color:#0078d4; cursor:grab;"
                             draggable="true"
                             ondragstart="sqlEditorDragStartJson(event, ${JSON.stringify(dragTablePayload).replace(/</g,'\\\\u003c')})"
                             onclick="toggleSqlSchemaTable(${JSON.stringify(t).replace(/</g,'\\\\u003c')})"
                             ondblclick="sqlEditorInsertTable(${JSON.stringify(t).replace(/</g,'\\\\u003c')})"
                             title="单击展开字段；双击插入表名；拖放自动生成 FROM/JOIN + 别名">
                            <span id="sqlSchemaArrow_${id}">${arrow}</span> ${escapeHtml(t)}
                        </div>
                        <div id="sqlSchemaFields_${id}" style="margin-left: 12px; margin-top: 4px; ${schema ? '' : 'display:none;'}">
                            ${fieldsHtml}
                        </div>
                    </div>
                `;
            }).join('');
        }

        // SQL编辑器：从“表结构/字段”插入到编辑区（支持自动补全别名）
        function sqlEditorInsertTable(tableName) {
            const t = String(tableName || '').trim();
            if (!t) return;
            sqlEditorInsertText(sqlQuoteIdent(t));
        }
        function sqlEditorInsertField(tableName, fieldName) {
            const t = String(tableName || '').trim();
            const f = String(fieldName || '').trim();
            if (!t || !f) return;
            let qualifier = '';
            try {
                const sql = sqlEditorGetText();
                const aliasMap = sqlParseAliasMap(sql);
                // 优先使用“短别名”（A/B/T 等），避免把长表名当别名插入导致 SQL 难读/可能非法
                const aliases = Object.keys(aliasMap || {}).filter(a => aliasMap[a] === t);
                const short = aliases.find(a => /^[A-Za-z_][A-Za-z0-9_]*$/.test(a)) || '';
                qualifier = short;
            } catch (_) { }

            const ins = qualifier
                ? `${qualifier}.${sqlQuoteIdent(f)}`
                : `${sqlQuoteIdent(t)}.${sqlQuoteIdent(f)}`;
            sqlEditorInsertText(ins);
        }

        // SQL编辑器：拖放插入（表/字段）
        function sqlEditorDragStart(ev, text) {
            try {
                ev.dataTransfer.effectAllowed = 'copy';
                ev.dataTransfer.setData('text/plain', String(text || ''));
            } catch (_) { }
        }

        function sqlEditorDragStartJson(ev, payload) {
            try {
                ev.dataTransfer.effectAllowed = 'copy';
                ev.dataTransfer.setData('application/x-excelsqlite-sqlitem', JSON.stringify(payload || {}));
                // 兼容：同时提供纯文本（供外部编辑器/系统粘贴）
                if (payload && payload.insertText) ev.dataTransfer.setData('text/plain', String(payload.insertText));
            } catch (_) { }
        }

        function sqlEditorEnableDropOnElement(el, forCodeMirror) {
            if (!el) return;
            // 避免重复绑定
            if (el.__sqlDropBound) return;
            el.__sqlDropBound = true;
            el.addEventListener('dragover', (e) => { try { e.preventDefault(); e.dataTransfer.dropEffect = 'copy'; } catch (_) { } });
            el.addEventListener('drop', (e) => {
                try { e.preventDefault(); } catch (_) { }
                // 优先读取结构化 payload（支持 Alt 拖字段只插入字段名 / 拖表自动生成 FROM/JOIN+别名）
                let payload = null;
                try {
                    const raw = e.dataTransfer.getData('application/x-excelsqlite-sqlitem') || '';
                    if (raw) payload = JSON.parse(raw);
                } catch (_) { payload = null; }

                let text = '';
                if (payload && payload.kind) {
                    try { text = sqlEditorBuildDropInsertText(payload, e); } catch (_) { text = ''; }
                }
                if (!text) {
                    try { text = e.dataTransfer.getData('text/plain') || ''; } catch (_) { }
                }
                if (!text) return;
                const cm = window.__cmSqlEditor || null;
                if (forCodeMirror && cm) {
                    try {
                        const pos = cm.coordsChar({ left: e.clientX, top: e.clientY }, 'window');
                        cm.setCursor(pos);
                    } catch (_) { }
                }
                // 支持“拖表/拖 JOIN”这种需要光标落点的片段：如文本包含特殊标记 ⟂ 表示光标位置
                sqlEditorInsertSnippet(text);
            });
        }

        function sqlEditorInsertSnippet(snippet) {
            const s = String(snippet || '');
            // 光标标记：使用 ⟂（不太可能出现在用户 SQL 中）
            const marker = '⟂';
            const idx = s.indexOf(marker);
            const ins = idx >= 0 ? (s.slice(0, idx) + s.slice(idx + marker.length)) : s;
            const cm = window.__cmSqlEditor || null;
            if (cm) {
                const cur = cm.getCursor();
                cm.replaceRange(ins, cur, cur, '+input');
                if (idx >= 0) {
                    // 把插入起点作为基准，算出 marker 的偏移（按行列）
                    const before = s.slice(0, idx);
                    const lines = before.split('\n');
                    const lineOff = lines.length - 1;
                    const chOff = lines[lines.length - 1].length;
                    const pos = { line: cur.line + lineOff, ch: (lineOff === 0 ? cur.ch : 0) + chOff };
                    try { cm.setCursor(pos); } catch (_) { }
                }
                cm.focus();
                try { updateSqlEditorCursor(); } catch (_) { }
                return;
            }
            // textarea fallback：不做 marker 定位（简单插入）
            sqlEditorInsertText(ins);
        }

        function sqlEditorNextAlias(sql) {
            // A/B/C... 优先；用尽后 T1/T2...
            const used = new Set();
            try {
                const aliasMap = sqlParseAliasMap(sql || '');
                Object.keys(aliasMap || {}).forEach(a => used.add(String(a).toUpperCase()));
            } catch (_) { }
            const letters = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ'.split('');
            for (const L of letters) {
                if (!used.has(L)) return L;
            }
            let n = 1;
            while (used.has('T' + n)) n++;
            return 'T' + n;
        }

        function sqlEditorHasFrom(sql) {
            try {
                const s = stripSqlComments(String(sql || '')).toLowerCase();
                return /\bfrom\b/.test(s);
            } catch (_) { return false; }
        }

        function sqlEditorBuildDropInsertText(payload, ev) {
            const kind = String(payload.kind || '');
            const sql = sqlEditorGetText();
            if (kind === 'field') {
                // Alt：只插入字段名；否则插入限定名（别名优先）
                if (ev && (ev.altKey || ev.metaKey)) return String(payload.insertBare || payload.insertText || '');
                return String(payload.insertQualified || payload.insertText || '');
            }
            if (kind === 'table') {
                const table = String(payload.table || '').trim();
                if (!table) return String(payload.insertText || '');
                const alias = sqlEditorNextAlias(sql);
                const quotedTable = sqlQuoteIdent(table);
                if (!sqlEditorHasFrom(sql)) {
                    // 没有 FROM：生成 FROM [表] A
                    return `\nFROM ${quotedTable} ${alias}\n`;
                }
                // 已有 FROM：生成 JOIN [表] B ON ⟂（光标落在 ON 后）
                return `\nJOIN ${quotedTable} ${alias} ON ⟂\n`;
            }
            return String(payload.insertText || '');
        }

        function toggleSqlSchemaTable(tableName) {
            const id = sqlSchemaDomId(tableName);
            const box = document.getElementById('sqlSchemaFields_' + id);
            const arrow = document.getElementById('sqlSchemaArrow_' + id);
            if (!box) return;
            const isHidden = (box.style.display === 'none' || !box.style.display);
            if (isHidden) {
                // 若无 schema，则拉取字段
                const schemas = window.__sqliteTableSchemas || {};
                if (!Array.isArray(schemas[tableName])) {
                    try { window.chrome.webview.postMessage({ action: 'getSqliteTableFields', tableName }); } catch (_) { }
                }
                box.style.display = 'block';
                if (arrow) arrow.textContent = '▼';
            } else {
                box.style.display = 'none';
                if (arrow) arrow.textContent = '▶';
            }
        }

        function copySqlEditorResult() {
            const table = document.getElementById('sqlEditorResultTable');
            if (!table) { alert('没有可复制的结果'); return; }
            const thead = table.querySelector('thead');
            const tbody = table.querySelector('tbody');
            const cols = [];
            thead?.querySelectorAll('th')?.forEach(th => cols.push(th.textContent || ''));
            const lines = [];
            if (cols.length) lines.push(cols.join('\\t'));
            tbody?.querySelectorAll('tr')?.forEach(tr => {
                const cells = Array.from(tr.querySelectorAll('td')).map(td => (td.textContent || '').replace(/\\r?\\n/g, ' '));
                lines.push(cells.join('\\t'));
            });
            const text = lines.join('\\n');
            window.__clipboardMsgMap = window.__clipboardMsgMap || {};
            window.__clipboardMsgMap['sql-editor-result'] = { okMsg: '结果已复制到剪贴板', failMsg: '复制失败' };
            try { window.chrome.webview.postMessage({ action: 'setClipboard', context: 'sql-editor-result', text }); } catch (_) { alert('复制失败'); }
        }

        // ===== SQL编辑器：结果分页/筛选/冻结表头 =====
        function sqlEditorInitResultState() {
            window.__sqlEditorResultState = window.__sqlEditorResultState || {
                cols: [],
                rows: [],
                page: 1,
                pageSize: 100,
                sortKey: '',
                sortDir: 'asc',
                globalQuery: '',
                colFilters: {},
                remoteMode: false,
                remoteBaseSql: '',
                remoteHasMore: true,
                remoteCountEnabled: false,
                remoteTotalCount: null,
                hiddenCols: [],
                colWidths: {},
                freezeCount: 0,
                selection: null
            };
        }
        function sqlEditorSetPageSize(v) {
            sqlEditorInitResultState();
            const st = window.__sqlEditorResultState;
            st.pageSize = Math.max(10, Number(v || 100));
            // 远程分页：切换 pageSize 后重新拉取当前页（通常回到第一页更合理）
            if (st.remoteMode && st.remoteBaseSql) {
                st.page = 1;
                sqlEditorRequestRemotePage(1);
                return;
            }
            st.page = 1;
            sqlEditorRenderResultPage();
        }
        function sqlEditorApplyFilter() {
            sqlEditorInitResultState();
            const q = (document.getElementById('sqlEditorResultFilter')?.value || '').trim().toLowerCase();
            window.__sqlEditorResultState.globalQuery = q;
            window.__sqlEditorResultState.page = 1;
            // 远程分页：筛选交给后端（跨全量结果集）
            if (window.__sqlEditorResultState.remoteMode && window.__sqlEditorResultState.remoteBaseSql) {
                sqlEditorRequestRemotePageDebounced(1);
                return;
            }
            sqlEditorRenderResultPageDebounced();
        }

        function sqlEditorSetColFilter(col, value) {
            sqlEditorInitResultState();
            const v = String(value || '').trim().toLowerCase();
            window.__sqlEditorResultState.colFilters = window.__sqlEditorResultState.colFilters || {};
            if (!v) delete window.__sqlEditorResultState.colFilters[col];
            else window.__sqlEditorResultState.colFilters[col] = v;
            window.__sqlEditorResultState.page = 1;
            // 远程分页：筛选交给后端（跨全量结果集）
            if (window.__sqlEditorResultState.remoteMode && window.__sqlEditorResultState.remoteBaseSql) {
                sqlEditorRequestRemotePageDebounced(1);
                return;
            }
            sqlEditorRenderResultPageDebounced();
        }

        // SQL编辑器：渲染节流（避免输入筛选时频繁重排/重建DOM）
        function sqlEditorRenderResultPageDebounced() {
            try { if (window.__sqlEditorRenderDebounce) clearTimeout(window.__sqlEditorRenderDebounce); } catch (_) { }
            window.__sqlEditorRenderDebounce = setTimeout(() => {
                try { sqlEditorRenderResultPage(); } catch (_) { }
            }, 200);
        }

        // SQL编辑器：远程分页请求节流（筛选输入时避免频繁发消息）
        function sqlEditorRequestRemotePageDebounced(page) {
            try { if (window.__sqlEditorRemoteDebounce) clearTimeout(window.__sqlEditorRemoteDebounce); } catch (_) { }
            window.__sqlEditorRemoteDebounce = setTimeout(() => {
                try { sqlEditorRequestRemotePage(page); } catch (_) { }
            }, 220);
        }
        function sqlEditorToggleSort(col) {
            sqlEditorInitResultState();
            const st = window.__sqlEditorResultState;
            if (st.sortKey === col) {
                st.sortDir = (st.sortDir === 'asc') ? 'desc' : 'asc';
            } else {
                st.sortKey = col;
                st.sortDir = 'asc';
            }
            st.page = 1;
            // 远程分页：排序交给后端（跨全量结果集）
            if (st.remoteMode && st.remoteBaseSql) {
                sqlEditorRequestRemotePage(1);
                return;
            }
            sqlEditorRenderResultPage();
        }
        function sqlEditorPrevPage() {
            sqlEditorInitResultState();
            const st = window.__sqlEditorResultState;
            if (st.remoteMode && st.remoteBaseSql) {
                const next = Math.max(1, (st.page || 1) - 1);
                if (next === st.page) return;
                st.page = next;
                sqlEditorRequestRemotePage(next);
                return;
            }
            st.page = Math.max(1, (st.page || 1) - 1);
            sqlEditorRenderResultPage();
        }
        function sqlEditorNextPage() {
            sqlEditorInitResultState();
            const st = window.__sqlEditorResultState;
            if (st.remoteMode && st.remoteBaseSql) {
                if (st.remoteHasMore === false) { alert('已到最后一页'); return; }
                const next = (st.page || 1) + 1;
                st.page = next;
                sqlEditorRequestRemotePage(next);
                return;
            }
            const total = sqlEditorGetCurrentRows().length;
            const ps = st.pageSize || 100;
            const maxPage = Math.max(1, Math.ceil(total / ps));
            st.page = Math.min(maxPage, (st.page || 1) + 1);
            sqlEditorRenderResultPage();
        }
        function sqlEditorGetCurrentRows() {
            sqlEditorInitResultState();
            const st = window.__sqlEditorResultState;
            let base = (st.rows || []);
            const cols = st.cols || [];
            // 先全局过滤
            const q = (st.globalQuery || '').trim();
            if (q) {
                base = base.filter(r => {
                    try { return cols.some(c => String(r?.[c] ?? '').toLowerCase().includes(q)); } catch (_) { return false; }
                });
            }
            // 再按列过滤
            const cf = st.colFilters || {};
            const cfKeys = Object.keys(cf);
            if (cfKeys.length) {
                base = base.filter(r => {
                    try {
                        return cfKeys.every(k => String(r?.[k] ?? '').toLowerCase().includes(cf[k]));
                    } catch (_) { return false; }
                });
            }
            if (!st.sortKey) return base;
            const key = st.sortKey;
            const dir = st.sortDir === 'desc' ? -1 : 1;
            // 排序：数字优先，否则按字符串
            const copy = base.slice();
            copy.sort((a, b) => {
                const av = a?.[key];
                const bv = b?.[key];
                const an = (av === null || av === undefined) ? NaN : Number(av);
                const bn = (bv === null || bv === undefined) ? NaN : Number(bv);
                if (!Number.isNaN(an) && !Number.isNaN(bn)) {
                    if (an === bn) return 0;
                    return an > bn ? dir : -dir;
                }
                const as = String(av ?? '');
                const bs = String(bv ?? '');
                if (as === bs) return 0;
                return as.localeCompare(bs, 'zh-Hans-CN', { numeric: true, sensitivity: 'base' }) * dir;
            });
            return copy;
        }
        function sqlEditorRenderResultPage() {
            sqlEditorInitResultState();
            const table = document.getElementById('sqlEditorResultTable');
            if (!table) return;
            const thead = table.querySelector('thead');
            const tbody = table.querySelector('tbody');
            const st = window.__sqlEditorResultState;
            const colsAll = Array.isArray(st.cols) ? st.cols : [];
            const hiddenSet = new Set(Array.isArray(st.hiddenCols) ? st.hiddenCols : []);
            const cols = colsAll.filter(c => !hiddenSet.has(c));
            const rows = sqlEditorGetCurrentRows();
            const ps = st.pageSize || 100;
            const page = st.page || 1;
            const remote = !!st.remoteMode;
            const maxPage = remote ? page : Math.max(1, Math.ceil(rows.length / ps));
            const pageSafe = remote ? page : Math.min(Math.max(1, page), maxPage);
            st.page = pageSafe;
            const pageRows = remote ? rows : rows.slice((pageSafe - 1) * ps, (pageSafe - 1) * ps + ps);

            // 列宽：用 colgroup 控制（支持拖拽调整并持久化）
            try {
                const old = table.querySelector('colgroup');
                if (old) old.remove();
                const cg = document.createElement('colgroup');
                const wmap = st.colWidths || {};
                cols.forEach(c => {
                    const col = document.createElement('col');
                    const w = Number(wmap[c] || 0);
                    if (w > 40) col.style.width = w + 'px';
                    cg.appendChild(col);
                });
                table.insertBefore(cg, thead || table.firstChild);
            } catch (_) { }

            if (thead) {
                thead.innerHTML = '';
                const tr = document.createElement('tr');
                if (!cols.length) {
                    const th = document.createElement('th');
                    th.textContent = '执行结果';
                    th.style.position = 'sticky'; th.style.top = '0'; th.style.background = '#111827'; th.style.color = '#fff'; th.style.zIndex = '3';
                    tr.appendChild(th);
                } else {
                    cols.forEach((c, idx) => {
                        const th = document.createElement('th');
                        const arrow = (st.sortKey === c) ? (st.sortDir === 'desc' ? ' ▼' : ' ▲') : '';
                        th.textContent = c + arrow;
                        th.style.cursor = 'pointer';
                        th.onclick = () => sqlEditorToggleSort(c);
                        th.ondblclick = (ev) => { try { ev.stopPropagation(); sqlEditorCopyColumn(c); } catch (_) { } };
                        // 列拖拽重排（更像 Excel）
                        try {
                            th.draggable = true;
                            th.dataset.col = String(c);
                            th.ondragstart = (ev) => {
                                try { sqlEditorInitResultState(); window.__sqlEditorResultState.__dragCol = String(c); } catch (_) { }
                                try { ev.dataTransfer.setData('text/plain', String(c)); } catch (_) { }
                            };
                            th.ondragover = (ev) => { try { ev.preventDefault(); } catch (_) { } };
                            th.ondrop = (ev) => {
                                try { ev.preventDefault(); } catch (_) { }
                                let from = '';
                                try { from = (window.__sqlEditorResultState && window.__sqlEditorResultState.__dragCol) ? String(window.__sqlEditorResultState.__dragCol) : ''; } catch (_) { }
                                try { if (!from) from = String(ev.dataTransfer.getData('text/plain') || ''); } catch (_) { }
                                if (from) sqlEditorMoveColumn(from, c);
                            };
                        } catch (_) { }
                        // 右键菜单
                        th.oncontextmenu = (ev) => {
                            try { ev.preventDefault(); } catch (_) { }
                            try { sqlEditorShowContextMenuForHeader(ev.clientX, ev.clientY, c, idx); } catch (_) { }
                        };
                        th.style.position = 'sticky';
                        th.style.top = '0';
                        th.style.background = '#111827';
                        th.style.color = '#fff';
                        th.style.zIndex = '3';
                        th.style.userSelect = 'none';
                        th.style.whiteSpace = 'nowrap';
                        th.style.overflow = 'hidden';
                        th.style.textOverflow = 'ellipsis';
                        th.style.minWidth = '60px';
                        th.style.boxSizing = 'border-box';
                        try { sqlEditorApplyStickyLeft(th, idx, true); } catch (_) { }
                        try { sqlEditorAttachColResizer(th, idx); } catch (_) { }
                        tr.appendChild(th);
                    });
                }
                thead.appendChild(tr);

                // 列筛选行（第二行表头）
                if (cols.length) {
                    const tr2 = document.createElement('tr');
                    cols.forEach((c, idx) => {
                        const th = document.createElement('th');
                        th.style.position = 'sticky';
                        th.style.top = '34px';
                        th.style.background = '#fff';
                        th.style.zIndex = '2';
                        th.style.padding = '4px';
                        try { sqlEditorApplyStickyLeft(th, idx, false); } catch (_) { }
                        th.innerHTML = `<input class="form-control" style="font-size:8pt; padding:2px 6px;" placeholder="筛选…" value="${escapeHtml((window.__sqlEditorResultState.colFilters||{})[c]||'')}" oninput="sqlEditorSetColFilter('${escapeHtml(c)}', this.value)">`;
                        tr2.appendChild(th);
                    });
                    thead.appendChild(tr2);
                }
            }
            if (tbody) {
                // 性能：分批渲染，避免一次性创建大量 DOM 导致卡顿
                try { window.__sqlEditorRenderToken = (window.__sqlEditorRenderToken || 0) + 1; } catch (_) { }
                const token = window.__sqlEditorRenderToken || 0;
                tbody.innerHTML = '';
                if (!cols.length) {
                    const tr = document.createElement('tr');
                    const td = document.createElement('td');
                    td.textContent = rows.length ? String(rows[0]) : '—';
                    tr.appendChild(td);
                    tbody.appendChild(tr);
                } else {
                    let i = 0;
                    const batch = 50;
                    const renderChunk = () => {
                        try { if ((window.__sqlEditorRenderToken || 0) !== token) return; } catch (_) { }
                        const frag = document.createDocumentFragment();
                        for (let k = 0; k < batch && i < pageRows.length; k++, i++) {
                            const r = pageRows[i];
                            const tr = document.createElement('tr');
                            cols.forEach((c, idx) => {
                                const td = document.createElement('td');
                                const full = (r && r[c] !== null && r[c] !== undefined) ? String(r[c]) : '';
                                const display = full.length > 200 ? (full.slice(0, 200) + '…') : full;
                                td.textContent = display;
                                td.title = full.length > 200 ? 'Ctrl+单击查看完整内容；单击复制' : '单击复制';
                                td.dataset.r = String(i);
                                td.dataset.c = String(idx);
                                td.dataset.colname = String(c);
                                try { sqlEditorApplyStickyLeft(td, idx, false, true); } catch (_) { }
                                // 单元格/行复制：单击复制单元格，双击复制整行（TSV）
                                td.style.cursor = 'copy';
                                td.onclick = (ev) => {
                                    try {
                                        ev.stopPropagation();
                                        // Ctrl+单击：查看完整内容
                                        if (ev.ctrlKey || ev.metaKey) {
                                            xslqShowTextModal('单元格内容', full || '（空）');
                                            return;
                                        }
                                        const text = full;
                                        window.__clipboardMsgMap = window.__clipboardMsgMap || {};
                                        window.__clipboardMsgMap['sql-editor-cell'] = { okMsg: '单元格已复制', failMsg: '复制失败' };
                                        window.chrome.webview.postMessage({ action: 'setClipboard', context: 'sql-editor-cell', text });
                                    } catch (_) { }
                                };
                                tr.appendChild(td);
                            });
                            tr.ondblclick = () => {
                                try {
                                    const line = cols.map(c => String(r?.[c] ?? '').replace(/\r?\n/g, ' ')).join('\t');
                                    window.__clipboardMsgMap = window.__clipboardMsgMap || {};
                                    window.__clipboardMsgMap['sql-editor-row'] = { okMsg: '整行已复制', failMsg: '复制失败' };
                                    window.chrome.webview.postMessage({ action: 'setClipboard', context: 'sql-editor-row', text: line });
                                } catch (_) { }
                            };
                            frag.appendChild(tr);
                        }
                        tbody.appendChild(frag);
                        if (i < pageRows.length) {
                            (window.requestAnimationFrame || window.setTimeout)(renderChunk, 0);
                        } else {
                            try { sqlEditorInitGridInteractions(); } catch (_) { }
                        }
                    };
                    (window.requestAnimationFrame || window.setTimeout)(renderChunk, 0);
                }
            }

            const info = document.getElementById('sqlEditorPageInfo');
            if (info) {
                if (remote) {
                    const ps0 = st.pageSize || 100;
                    const total0 = (st.remoteTotalCount === null || st.remoteTotalCount === undefined) ? null : Number(st.remoteTotalCount);
                    if (total0 !== null && Number.isFinite(total0)) {
                        const maxP = Math.max(1, Math.ceil(total0 / ps0));
                        const more = (pageSafe >= maxP) ? '末页' : '还有更多…';
                        info.textContent = `第${pageSafe}/${maxP}页（共${total0.toLocaleString()}行｜本页${rows.length.toLocaleString()}行｜${more}）`;
                    } else {
                        const more = (st.remoteHasMore === false) ? '末页' : '还有更多…';
                        info.textContent = `第${pageSafe}页（本页${rows.length.toLocaleString()}行｜${more}）`;
                    }
                } else {
                    info.textContent = `${pageSafe}/${maxPage}（${rows.length.toLocaleString()}行）`;
                }
            }
        }

        function sqlEditorCopyColumn(col) {
            sqlEditorInitResultState();
            const rows = sqlEditorGetCurrentRows();
            const lines = rows.map(r => String(r?.[col] ?? ''));
            const text = lines.join('\n');
            window.__clipboardMsgMap = window.__clipboardMsgMap || {};
            window.__clipboardMsgMap['sql-editor-col'] = { okMsg: `已复制列：${col}`, failMsg: '复制失败' };
            try { window.chrome.webview.postMessage({ action: 'setClipboard', context: 'sql-editor-col', text }); } catch (_) { }
            try { setStatusMessage(`已复制整列：${col}（${lines.length} 行）`); } catch (_) { }
        }

        // ===== SQL查询分析：表格增强（列宽/冻结/隐藏/选区复制） =====
        function sqlEditorLoadGridPrefs() {
            sqlEditorInitResultState();
            const st = window.__sqlEditorResultState;
            try { st.hiddenCols = JSON.parse(localStorage.getItem('sqlEditorHiddenCols') || '[]') || []; } catch (_) { }
            try { st.colWidths = JSON.parse(localStorage.getItem('sqlEditorColWidths') || '{}') || {}; } catch (_) { }
            try { st.freezeCount = Number(localStorage.getItem('sqlEditorFreezeCount') || st.freezeCount || 0) || 0; } catch (_) { }
            try { st.colOrder = JSON.parse(localStorage.getItem('sqlEditorColOrder') || '[]') || []; } catch (_) { }
            try { st.copyWithHeader = (localStorage.getItem('sqlEditorCopyWithHeader') || '0') === '1'; } catch (_) { }
        }

        function sqlEditorGetVisibleCols() {
            sqlEditorInitResultState();
            const st = window.__sqlEditorResultState;
            const colsAll = Array.isArray(st.cols) ? st.cols : [];
            const hiddenSet = new Set(Array.isArray(st.hiddenCols) ? st.hiddenCols : []);
            return colsAll.filter(c => !hiddenSet.has(c));
        }

        function sqlEditorApplyColOrderToCols() {
            sqlEditorInitResultState();
            const st = window.__sqlEditorResultState;
            const cols = Array.isArray(st.cols) ? st.cols : [];
            const ord = Array.isArray(st.colOrder) ? st.colOrder : [];
            if (!ord.length || !cols.length) return;
            const set = new Set(cols);
            const ordered = ord.filter(x => set.has(x));
            const rest = cols.filter(x => !ordered.includes(x));
            st.cols = ordered.concat(rest);
        }

        function sqlEditorPersistColOrder() {
            try {
                sqlEditorInitResultState();
                const st = window.__sqlEditorResultState;
                st.colOrder = Array.isArray(st.cols) ? st.cols.slice() : [];
                localStorage.setItem('sqlEditorColOrder', JSON.stringify(st.colOrder || []));
            } catch (_) { }
        }

        function sqlEditorMoveColumn(fromCol, toCol) {
            sqlEditorInitResultState();
            const st = window.__sqlEditorResultState;
            const cols = Array.isArray(st.cols) ? st.cols.slice() : [];
            const a = String(fromCol || '').trim();
            const b = String(toCol || '').trim();
            if (!a || !b || a === b) return;
            const i1 = cols.indexOf(a);
            const i2 = cols.indexOf(b);
            if (i1 < 0 || i2 < 0) return;
            cols.splice(i1, 1);
            const insertAt = (i1 < i2) ? i2 - 1 : i2;
            cols.splice(insertAt, 0, a);
            st.cols = cols;
            try { sqlEditorPersistColOrder(); } catch (_) { }
            try { sqlEditorRenderResultPage(); } catch (_) { }
        }

        function sqlEditorApplyStickyLeft(el, idx, isHeader, isCell) {
            const st = window.__sqlEditorResultState || {};
            const n = Number(st.freezeCount || 0);
            if (!n || idx >= n) return;
            const colsAll = Array.isArray(st.cols) ? st.cols : [];
            const hiddenSet = new Set(Array.isArray(st.hiddenCols) ? st.hiddenCols : []);
            const cols = colsAll.filter(c => !hiddenSet.has(c));
            let left = 0;
            const wmap = st.colWidths || {};
            for (let i = 0; i < idx; i++) {
                const c = cols[i];
                const w = Number(wmap[c] || 0);
                left += (w > 40 ? w : 140);
            }
            el.style.position = 'sticky';
            el.style.left = left + 'px';
            el.style.zIndex = isHeader ? '6' : '4';
            if (isHeader) {
                el.style.boxShadow = '2px 0 0 rgba(0,0,0,0.06)';
            }
            if (isCell) {
                el.style.background = '#fff';
            }
        }

        function sqlEditorAttachColResizer(th, idx) {
            if (!th || th.querySelector('.sql-col-resizer')) return;
            const rz = document.createElement('div');
            rz.className = 'sql-col-resizer';
            rz.title = '拖拽调整列宽';
            rz.onmousedown = (ev) => {
                try { ev.stopPropagation(); ev.preventDefault(); } catch (_) { }
                sqlEditorInitResultState();
                const st = window.__sqlEditorResultState;
                const colsAll = Array.isArray(st.cols) ? st.cols : [];
                const hiddenSet = new Set(Array.isArray(st.hiddenCols) ? st.hiddenCols : []);
                const cols = colsAll.filter(c => !hiddenSet.has(c));
                const colName = cols[idx];
                if (!colName) return;
                const startX = ev.clientX;
                const startW = th.getBoundingClientRect().width;
                const onMove = (e2) => {
                    const dx = e2.clientX - startX;
                    const w = Math.max(60, Math.min(860, Math.round(startW + dx)));
                    st.colWidths = st.colWidths || {};
                    st.colWidths[colName] = w;
                    try { localStorage.setItem('sqlEditorColWidths', JSON.stringify(st.colWidths)); } catch (_) { }
                    // 即时更新 colgroup
                    try {
                        const table = document.getElementById('sqlEditorResultTable');
                        const cg = table?.querySelector('colgroup');
                        const colEl = cg?.children?.[idx];
                        if (colEl) colEl.style.width = w + 'px';
                    } catch (_) { }
                };
                const onUp = () => {
                    window.removeEventListener('mousemove', onMove, true);
                    window.removeEventListener('mouseup', onUp, true);
                };
                window.addEventListener('mousemove', onMove, true);
                window.addEventListener('mouseup', onUp, true);
            };
            th.style.position = 'sticky';
            th.appendChild(rz);
        }

        function sqlEditorInitGridInteractions() {
            const table = document.getElementById('sqlEditorResultTable');
            const tbody = table?.querySelector('tbody');
            if (!tbody || tbody.__sqlSelBound) return;
            tbody.__sqlSelBound = true;

            const clearSel = () => {
                try {
                    sqlEditorInitResultState();
                    window.__sqlEditorResultState.selection = null;
                    sqlEditorApplySelectionStyles();
                } catch (_) { }
            };

            tbody.addEventListener('mousedown', (ev) => {
                const td = ev.target && ev.target.closest ? ev.target.closest('td') : null;
                if (!td) return;
                const r = Number(td.dataset.r || 0);
                const c = Number(td.dataset.c || 0);
                sqlEditorInitResultState();
                const st = window.__sqlEditorResultState;
                if (ev.shiftKey && st.selection) {
                    st.selection.r2 = r; st.selection.c2 = c;
                } else {
                    st.selection = { r1: r, c1: c, r2: r, c2: c };
                }
                st.__dragSel = true;
                sqlEditorApplySelectionStyles();
            });

            tbody.addEventListener('mousemove', (ev) => {
                const st = window.__sqlEditorResultState || {};
                if (!st.__dragSel) return;
                const td = ev.target && ev.target.closest ? ev.target.closest('td') : null;
                if (!td) return;
                const r = Number(td.dataset.r || 0);
                const c = Number(td.dataset.c || 0);
                if (!st.selection) return;
                st.selection.r2 = r; st.selection.c2 = c;
                sqlEditorApplySelectionStyles();
            });

            window.addEventListener('mouseup', () => {
                const st = window.__sqlEditorResultState || {};
                st.__dragSel = false;
            });

            tbody.addEventListener('dblclick', (ev) => {
                // 双击空白处：清空选区（避免误选残留）
                try {
                    if (ev.target === tbody) clearSel();
                } catch (_) { }
            });

            // 右键菜单（单元格）
            tbody.addEventListener('contextmenu', (ev) => {
                const td = ev.target && ev.target.closest ? ev.target.closest('td') : null;
                if (!td) return;
                try { ev.preventDefault(); } catch (_) { }
                const r = Number(td.dataset.r || 0);
                const c = Number(td.dataset.c || 0);
                const colName = String(td.dataset.colname || '');
                try { sqlEditorShowContextMenuForCell(ev.clientX, ev.clientY, r, c, colName); } catch (_) { }
            });
        }

        function sqlEditorCloseContextMenu() {
            try { document.getElementById('sqlEditorCtxMenu')?.remove(); } catch (_) { }
        }

        function sqlEditorShowContextMenu(x, y, items) {
            sqlEditorCloseContextMenu();
            const menu = document.createElement('div');
            menu.id = 'sqlEditorCtxMenu';
            menu.style.cssText = `position:fixed; left:${x}px; top:${y}px; z-index:4000; background:#fff; border:1px solid #e5e7eb; border-radius:10px; box-shadow:0 10px 30px rgba(0,0,0,0.15); padding:6px; min-width: 190px;`;
            menu.innerHTML = (items || []).map(it => {
                const danger = it.danger ? 'color:#b91c1c;' : 'color:#0f172a;';
                return `<div data-act="1" style="padding:6px 10px; border-radius:8px; cursor:pointer; font-size:9pt; ${danger}">${escapeHtml(it.label || '')}</div>`;
            }).join('');
            document.body.appendChild(menu);
            Array.from(menu.querySelectorAll('[data-act="1"]')).forEach((el, idx) => {
                el.addEventListener('mouseenter', () => { el.style.background = '#f1f5f9'; });
                el.addEventListener('mouseleave', () => { el.style.background = 'transparent'; });
                el.addEventListener('click', () => {
                    try { (items[idx] && items[idx].onClick) ? items[idx].onClick() : null; } catch (_) { }
                    sqlEditorCloseContextMenu();
                });
            });
            setTimeout(() => {
                const onDoc = (e) => {
                    try {
                        const m = document.getElementById('sqlEditorCtxMenu');
                        if (!m) return;
                        if (e.target && m.contains(e.target)) return;
                        sqlEditorCloseContextMenu();
                        document.removeEventListener('mousedown', onDoc, true);
                    } catch (_) { }
                };
                document.addEventListener('mousedown', onDoc, true);
            }, 0);
        }

        function sqlEditorHideColumn(colName) {
            sqlEditorInitResultState();
            const st = window.__sqlEditorResultState;
            const c = String(colName || '');
            if (!c) return;
            st.hiddenCols = Array.isArray(st.hiddenCols) ? st.hiddenCols : [];
            if (!st.hiddenCols.includes(c)) st.hiddenCols.push(c);
            try { localStorage.setItem('sqlEditorHiddenCols', JSON.stringify(st.hiddenCols)); } catch (_) { }
            try { sqlEditorRenderResultPage(); } catch (_) { }
        }

        function sqlEditorSetFreezeCount(n) {
            sqlEditorInitResultState();
            const st = window.__sqlEditorResultState;
            const cols = sqlEditorGetVisibleCols();
            const maxN = cols.length;
            st.freezeCount = Math.max(0, Math.min(maxN, Number(n || 0)));
            try { localStorage.setItem('sqlEditorFreezeCount', String(st.freezeCount)); } catch (_) { }
            try { sqlEditorRenderResultPage(); } catch (_) { }
        }

        function sqlEditorShowContextMenuForHeader(x, y, colName, colIdx) {
            const c = String(colName || '');
            const idx = Number(colIdx || 0);
            const items = [
                { label: '复制整列', onClick: () => sqlEditorCopyColumn(c) },
                { label: '隐藏此列', onClick: () => sqlEditorHideColumn(c) },
                { label: `冻结到此列（前 ${idx + 1} 列）`, onClick: () => sqlEditorSetFreezeCount(idx + 1) },
                { label: '取消冻结', onClick: () => sqlEditorSetFreezeCount(0) },
            ];
            sqlEditorShowContextMenu(x, y, items);
        }

        function sqlEditorShowContextMenuForCell(x, y, r, c, colName) {
            sqlEditorInitResultState();
            const st = window.__sqlEditorResultState;
            const cols = sqlEditorGetVisibleCols();
            const col = String(colName || cols[c] || '');
            const rows = sqlEditorGetCurrentRows();
            const row = rows[r] || {};
            const cellText = String(row?.[col] ?? '');
            const items = [
                { label: '复制单元格', onClick: () => {
                    window.__clipboardMsgMap = window.__clipboardMsgMap || {};
                    window.__clipboardMsgMap['sql-cell'] = { okMsg: '已复制单元格', failMsg: '复制失败' };
                    try { window.chrome.webview.postMessage({ action: 'setClipboard', context: 'sql-cell', text: cellText }); } catch (_) { }
                }},
                { label: '复制整行（TSV）', onClick: () => {
                    const line = cols.map(k => String(row?.[k] ?? '').replace(/\r?\n/g, ' ')).join('\t');
                    window.__clipboardMsgMap = window.__clipboardMsgMap || {};
                    window.__clipboardMsgMap['sql-row'] = { okMsg: '已复制整行', failMsg: '复制失败' };
                    try { window.chrome.webview.postMessage({ action: 'setClipboard', context: 'sql-row', text: line }); } catch (_) { }
                }},
                { label: '复制整列', onClick: () => sqlEditorCopyColumn(col) },
                { label: '隐藏此列', onClick: () => sqlEditorHideColumn(col) },
                { label: `冻结到此列（前 ${c + 1} 列）`, onClick: () => sqlEditorSetFreezeCount(c + 1) },
                { label: '取消冻结', onClick: () => sqlEditorSetFreezeCount(0) },
            ];
            sqlEditorShowContextMenu(x, y, items);
        }

        function sqlEditorApplySelectionStyles() {
            try {
                const table = document.getElementById('sqlEditorResultTable');
                const tbody = table?.querySelector('tbody');
                if (!tbody) return;
                const st = window.__sqlEditorResultState || {};
                const sel = st.selection;
                const cells = tbody.querySelectorAll('td');
                cells.forEach(td => {
                    td.classList.remove('sql-cell-selected');
                    td.classList.remove('sql-cell-anchor');
                });
                if (!sel) return;
                const r1 = Math.min(sel.r1, sel.r2), r2 = Math.max(sel.r1, sel.r2);
                const c1 = Math.min(sel.c1, sel.c2), c2 = Math.max(sel.c1, sel.c2);
                cells.forEach(td => {
                    const r = Number(td.dataset.r || -1);
                    const c = Number(td.dataset.c || -1);
                    if (r >= r1 && r <= r2 && c >= c1 && c <= c2) td.classList.add('sql-cell-selected');
                    if (r === sel.r1 && c === sel.c1) td.classList.add('sql-cell-anchor');
                });
            } catch (_) { }
        }

        function sqlEditorCopySelection() {
            sqlEditorInitResultState();
            const st = window.__sqlEditorResultState;
            const sel = st.selection;
            if (!sel) { alert('请先在结果表格中拖拽选择一个区域'); return; }
            const r1 = Math.min(sel.r1, sel.r2), r2 = Math.max(sel.r1, sel.r2);
            const c1 = Math.min(sel.c1, sel.c2), c2 = Math.max(sel.c1, sel.c2);
            const colsAll = Array.isArray(st.cols) ? st.cols : [];
            const hiddenSet = new Set(Array.isArray(st.hiddenCols) ? st.hiddenCols : []);
            const cols = colsAll.filter(c => !hiddenSet.has(c));
            const pageRows = sqlEditorGetCurrentRows();
            const lines = [];
            // 复制带表头（用户可在结果区勾选）
            try {
                if (st.copyWithHeader) {
                    const heads = [];
                    for (let c = c1; c <= c2; c++) heads.push(String(cols[c] ?? ''));
                    lines.push(heads.join('\t'));
                }
            } catch (_) { }
            for (let r = r1; r <= r2; r++) {
                const row = pageRows[r] || {};
                const parts = [];
                for (let c = c1; c <= c2; c++) {
                    const key = cols[c];
                    parts.push(String(row?.[key] ?? '').replace(/\r?\n/g, ' '));
                }
                lines.push(parts.join('\t'));
            }
            const text = lines.join('\n');
            window.__clipboardMsgMap = window.__clipboardMsgMap || {};
            window.__clipboardMsgMap['sql-editor-sel'] = { okMsg: '选区已复制', failMsg: '复制失败' };
            try { window.chrome.webview.postMessage({ action: 'setClipboard', context: 'sql-editor-sel', text }); } catch (_) { }
            try { setStatusMessage(`已复制选区：${(r2 - r1 + 1)}×${(c2 - c1 + 1)}`); } catch (_) { }
        }

        function sqlEditorOpenColumnManager() {
            sqlEditorInitResultState();
            const st = window.__sqlEditorResultState;
            const cols = Array.isArray(st.cols) ? st.cols : [];
            if (!cols.length) { alert('暂无列'); return; }
            const hiddenSet = new Set(Array.isArray(st.hiddenCols) ? st.hiddenCols : []);

            const modal = document.createElement('div');
            modal.className = 'modal';
            modal.style.cssText = 'position: fixed; inset: 0; background: rgba(0,0,0,0.45); display:flex; align-items:center; justify-content:center; z-index: 2900;';
            modal.onclick = (e) => { if (e.target === modal) modal.remove(); };
            modal.innerHTML = `
              <div style="background:#fff; border-radius:10px; width: 720px; max-width: 92vw; max-height: 86vh; overflow:hidden; box-shadow:0 10px 30px rgba(0,0,0,0.18);">
                <div style="display:flex; align-items:center; gap:10px; padding:10px 12px; border-bottom:1px solid #eee;">
                  <div style="font-weight:bold; flex:1;">列（显示/隐藏）</div>
                  <button class="btn btn-secondary" style="padding:2px 10px;" onclick="this.closest('.modal').remove()">关闭</button>
                </div>
                <div style="padding:12px; display:flex; flex-direction:column; gap:10px;">
                  <div style="display:flex; gap:8px; flex-wrap:wrap;">
                    <button class="btn btn-secondary" onclick="sqlEditorColumnsSelectAll(true)">全选</button>
                    <button class="btn btn-secondary" onclick="sqlEditorColumnsSelectAll(false)">全不选</button>
                    <button class="btn btn-secondary" onclick="sqlEditorColumnsReset()">重置（列宽/隐藏/冻结/选区）</button>
                  </div>
                  <div id="sqlEditorColsList" style="border:1px solid #eee; border-radius:8px; padding:10px; max-height: 56vh; overflow:auto;"></div>
                  <div style="display:flex; justify-content:flex-end; gap:8px;">
                    <button class="btn btn-primary" onclick="sqlEditorColumnsApply()">应用</button>
                  </div>
                </div>
              </div>
            `;
            document.body.appendChild(modal);
            const box = modal.querySelector('#sqlEditorColsList');
            if (box) {
                box.innerHTML = cols.map(c => {
                    const w = Number((st.colWidths || {})[c] || 0);
                    return `
                      <label style="display:flex; gap:8px; align-items:center; padding:4px 0; font-size:9pt;">
                        <input type="checkbox" data-col="1" value="${escapeHtml(c)}" ${hiddenSet.has(c) ? '' : 'checked'}>
                        <span style="flex:1; overflow:hidden; text-overflow:ellipsis; white-space:nowrap;">${escapeHtml(c)}</span>
                        <span style="font-size:8pt; color:#6c757d;">宽度：${w > 40 ? w : '自动'}</span>
                      </label>
                    `;
                }).join('');
            }
        }

        function sqlEditorColumnsSelectAll(on) {
            document.querySelectorAll('#sqlEditorColsList input[data-col="1"]').forEach(x => x.checked = !!on);
        }
        function sqlEditorColumnsReset() {
            sqlEditorInitResultState();
            const st = window.__sqlEditorResultState;
            st.hiddenCols = [];
            st.colWidths = {};
            st.freezeCount = 0;
            st.selection = null;
            st.colOrder = [];
            try { localStorage.setItem('sqlEditorHiddenCols', '[]'); } catch (_) { }
            try { localStorage.setItem('sqlEditorColWidths', '{}'); } catch (_) { }
            try { localStorage.setItem('sqlEditorFreezeCount', '0'); } catch (_) { }
            try { localStorage.setItem('sqlEditorColOrder', '[]'); } catch (_) { }
            try { sqlEditorRenderResultPage(); } catch (_) { }
            try { setStatusMessage('已重置表格显示设置'); } catch (_) { }
        }
        function sqlEditorColumnsApply() {
            sqlEditorInitResultState();
            const st = window.__sqlEditorResultState;
            const all = Array.isArray(st.cols) ? st.cols : [];
            const shown = Array.from(document.querySelectorAll('#sqlEditorColsList input[data-col="1"]:checked')).map(x => x.value);
            st.hiddenCols = all.filter(c => !shown.includes(c));
            try { localStorage.setItem('sqlEditorHiddenCols', JSON.stringify(st.hiddenCols)); } catch (_) { }
            try { sqlEditorRenderResultPage(); } catch (_) { }
            try { document.querySelectorAll('.modal').forEach(m => { if (m.querySelector('#sqlEditorColsList')) m.remove(); }); } catch (_) { }
        }

        function sqlEditorToggleFreeze() {
            sqlEditorInitResultState();
            const st = window.__sqlEditorResultState;
            const cols = sqlEditorGetVisibleCols();
            const maxN = cols.length;
            // Shift+点击：输入任意冻结列数
            try {
                const ev = window.event;
                if (ev && ev.shiftKey) {
                    const v = prompt(`输入冻结列数（0~${maxN}）`, String(st.freezeCount || 0));
                    if (v === null) return;
                    const n = Math.max(0, Math.min(maxN, Number(v || 0) || 0));
                    sqlEditorSetFreezeCount(n);
                    try { setStatusMessage(n ? `已冻结前 ${n} 列` : '已取消冻结'); } catch (_) { }
                    return;
                }
            } catch (_) { }
            // 普通点击：快速循环 0~3
            const stepMax = Math.min(3, maxN);
            st.freezeCount = Number(st.freezeCount || 0);
            st.freezeCount = (st.freezeCount + 1) % (stepMax + 1); // 0..stepMax
            try { localStorage.setItem('sqlEditorFreezeCount', String(st.freezeCount)); } catch (_) { }
            try { sqlEditorRenderResultPage(); } catch (_) { }
            try { setStatusMessage(st.freezeCount ? `已冻结前 ${st.freezeCount} 列` : '已取消冻结'); } catch (_) { }
        }

        // 导出当前页 / 筛选后（不依赖SQL，直接导出表格数据）
        function exportSqlEditorView(scope) {
            sqlEditorInitResultState();
            const st = window.__sqlEditorResultState;
            const colsAll = Array.isArray(st.cols) ? st.cols : [];
            const hiddenSet = new Set(Array.isArray(st.hiddenCols) ? st.hiddenCols : []);
            const cols = colsAll.filter(c => !hiddenSet.has(c));
            if (!cols.length) { alert('没有可导出的数据'); return; }

            // 远程分页下，“导出筛选后”应当导出“全量筛选结果”（而不是仅当前页）
            if (st.remoteMode && scope !== 'page') {
                const sql = String(sqlEditorBuildRemoteSql() || '').trim();
                if (!sql) { alert('没有可导出的SQL'); return; }
                const fmt = confirm('导出格式：\n\n【确定】导出 Excel(xlsx)\n【取消】导出 CSV') ? 'xlsx' : 'csv';
                const open = confirm(`是否直接打开 ${fmt.toUpperCase()}？\n\n【确定】直接打开（临时文件）\n【取消】另存为...`);
                try { window.__exportJobId = ''; showExportProgressModal(); updateExportProgressView(null, '已提交导出请求…'); } catch (_) { }
                try {
                    window.chrome.webview.postMessage({
                        action: 'exportQueryToFile',
                        sql,
                        params: (window.__sqlParams || {}),
                        format: fmt,
                        mode: open ? 'open' : 'saveas',
                        limit: 0,
                        skipCount: true,
                        excelOptions: { fontName: '微软雅黑', fontSize: 9 }
                    });
                } catch (e) {
                    alert('导出失败：' + (e && e.message ? e.message : e));
                }
                return;
            }

            const allRows = sqlEditorGetCurrentRows();
            const exportRows = (scope !== 'page' || st.remoteMode)
                ? allRows
                : allRows.slice(((st.page || 1) - 1) * (st.pageSize || 100), ((st.page || 1) - 1) * (st.pageSize || 100) + (st.pageSize || 100));
            if (!exportRows.length) { alert('没有可导出的数据'); return; }
            const open = confirm('是否直接打开 Excel？\n\n【确定】直接打开（临时文件）\n【取消】另存为...');
            try {
                window.chrome.webview.postMessage({
                    action: 'exportGridToFile',
                    mode: open ? 'open' : 'saveas',
                    fileName: `sql-editor-${scope}-${new Date().toISOString().replace(/[:.]/g,'').slice(0,15)}.xlsx`,
                    title: scope === 'page' ? 'SQL查询分析-当前页' : 'SQL查询分析-筛选后',
                    columns: cols,
                    rows: exportRows
                });
            } catch (e) {
                alert('导出失败：' + (e && e.message ? e.message : e));
            }
        }
        
        // 清空SQL编辑器
        function clearSqlEditor() {
            if (confirm('确定要清空编辑器内容吗？')) {
                const adv = document.getElementById('sqlEditorTextarea');
                const gen = document.getElementById('sqlEditor');
                // textarea 作为 CodeMirror 的底层载体，清空请统一走 sqlEditorSetText
                if (gen) gen.value = '';
                try { sqlEditorSetText(''); } catch (_) { }
                try { updateSqlEditorCursor(); } catch (_) { }
            }
        }
        
        // 保存SQL到历史
        function saveSqlToHistory() {
            const sql = (sqlEditorGetText() || '').trim();
            if (!sql) {
                alert('没有可保存的SQL语句');
                return;
            }
            addSqlToHistory(sql);
            alert('SQL已保存到历史记录');
        }
        
        // 添加SQL到历史
        function addSqlToHistory(sql) {
            const now = new Date();
            const formattedTime = now.getFullYear() + '-' + 
                               String(now.getMonth() + 1).padStart(2, '0') + '-' + 
                               String(now.getDate()).padStart(2, '0') + ' ' + 
                               String(now.getHours()).padStart(2, '0') + ':' + 
                               String(now.getMinutes()).padStart(2, '0') + ':' + 
                               String(now.getSeconds()).padStart(2, '0');
            
            const norm = (s) => String(s || '').trim().replace(/\s+/g, ' ').toLowerCase();
            const key = norm(sql);
            // 去重：若已存在相同 SQL（忽略空白），则把它“挪到最前面”并更新时间/状态
            try {
                const existed = sqlHistory.find(h => norm(h.sql) === key);
                if (existed) {
                    existed.sql = sql;
                    existed.time = formattedTime;
                    existed.status = 'pending';
                    existed.rows = 0;
                    existed.duration = 0;
                    existed.error = '';
                    existed.source = window.__lastQueryTarget || '';
                    existed.dbType = 'sqlite';
                    // 挪到最前
                    sqlHistory = [existed].concat(sqlHistory.filter(x => x !== existed));
                    updateSqlHistoryList();
                    saveSqlHistoryToStorage();
                    return existed.id;
                }
            } catch (_) { }

            const newItem = {
                id: Date.now(), // 同时作为 requestId
                sql: sql,
                time: formattedTime,
                status: 'pending',
                rows: 0,
                duration: 0,
                error: '',
                source: window.__lastQueryTarget || '',
                dbType: 'sqlite',
                pinned: false
            };
            
            sqlHistory.unshift(newItem);
            if (sqlHistory.length > 100) {
                sqlHistory = sqlHistory.slice(0, 100);
            }
            
            updateSqlHistoryList();
            saveSqlHistoryToStorage();
            return newItem.id;
        }
        
        // 更新SQL历史列表
        function updateSqlHistoryList() {
            const container = document.getElementById('sqlHistoryList');
            if (!container) return;
            
            const searchTerm = document.getElementById('sqlHistorySearch')?.value?.toLowerCase() || '';
            // 保持原始顺序（便于“重复执行挪到最前”），仅将 pinned 项整体置顶（仍保持各自的相对顺序）
            const base = sqlHistory.filter(item => (item.sql || '').toLowerCase().includes(searchTerm));
            const filtered = base.filter(x => !!x?.pinned).concat(base.filter(x => !x?.pinned));
            
            container.innerHTML = filtered.map((item) => `
                <div class="sql-history-item" style="padding: 12px; background: white; border-radius: 4px; margin-bottom: 8px; cursor: pointer;" onclick="loadSqlFromHistory(${item.id}, false)">
                    <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 4px; gap:10px;">
                        <span style="font-size: 8pt; color: #666;">${escapeHtml(item.time || '')}</span>
                        <div style="display:flex; gap:10px; align-items:center;">
                            <button class="btn btn-secondary" style="padding:2px 8px; font-size: 8pt;" title="${item.pinned ? '取消收藏' : '收藏置顶'}" onclick="event.stopPropagation(); toggleSqlHistoryPin(${item.id});">${item.pinned ? '★' : '☆'}</button>
                            <span style="font-size: 8pt; color: ${item.status === 'success' ? '#52c41a' : item.status === 'error' ? '#f5222d' : item.status === 'cancelled' ? '#6c757d' : '#faad14'};">
                                ${item.status === 'success' ? '✓ 成功' : item.status === 'error' ? '✗ 失败' : item.status === 'cancelled' ? '⏹ 已取消' : '⏳ 执行中'}
                            </span>
                            <button class="btn btn-secondary" style="padding:2px 8px; font-size: 8pt;" onclick="event.stopPropagation(); loadSqlFromHistory(${item.id}, true)">▶ 执行</button>
                            <button class="btn btn-secondary" style="padding:2px 8px; font-size: 8pt;" onclick="event.stopPropagation(); copySqlFromHistory(${item.id});">📋 复制</button>
                            <button class="btn btn-danger" style="padding:2px 8px; font-size: 8pt;" onclick="event.stopPropagation(); deleteSqlHistoryItem(${item.id});">🗑</button>
                        </div>
                    </div>
                    <div style="font-family: monospace; font-size: 9pt; color: #333; white-space: nowrap; overflow: hidden; text-overflow: ellipsis;">${escapeHtml(item.sql || '')}</div>
                    ${item.status === 'success' ? `<div style="font-size: 8pt; color: #666; margin-top: 4px;">${item.kind === 'nonQuery' ? '影响 ' : '返回 '}${Number(item.rows || 0).toLocaleString()} 行 | 耗时 ${Number(item.duration || 0)}s</div>` : ''}
                    ${item.status === 'error' ? `<div style="font-size: 8pt; color: #f5222d; margin-top: 4px;">错误: ${escapeHtml(String(item.error || ''))}</div>` : ''}
                </div>
            `).join('');
        }

        function toggleSqlHistoryPin(id) {
            const item = sqlHistory.find(h => Number(h.id) === Number(id));
            if (!item) return;
            item.pinned = !item.pinned;
            updateSqlHistoryList();
            saveSqlHistoryToStorage();
        }

        function copySqlFromHistory(id) {
            const item = sqlHistory.find(h => Number(h.id) === Number(id));
            if (!item) return;
            try { xslqCopyToClipboard(item.sql || ''); } catch (_) { }
            try { setStatusMessage('SQL 已复制到剪贴板'); } catch (_) { }
        }

        function deleteSqlHistoryItem(id) {
            if (!confirm('确定删除该条 SQL 历史吗？')) return;
            sqlHistory = sqlHistory.filter(h => Number(h.id) !== Number(id));
            updateSqlHistoryList();
            saveSqlHistoryToStorage();
        }
        
        // 从历史加载SQL
        function loadSqlFromHistory(id, runNow) {
            const item = sqlHistory.find(h => h.id === id);
            if (item) {
                sqlEditorSetText(item.sql || '');
                switchTab('sql-editor');
                try { updateSqlEditorCursor(); } catch (_) { }
                if (runNow) {
                    try { executeSqlEditor(); } catch (_) { }
                }
            }
        }
        
        // 搜索SQL历史
        function searchSqlHistory() {
            updateSqlHistoryList();
        }

        function updateSqlHistoryStatus(requestId, ok, payload) {
            const id = Number(requestId);
            if (!id) return;
            const item = sqlHistory.find(h => Number(h.id) === id);
            if (!item) return;
            if (ok) {
                const r = payload || {};
                item.status = 'success';
                const cols = Array.isArray(r.columns) ? r.columns : [];
                item.kind = (!cols.length && !(Array.isArray(r.rows) && r.rows.length)) ? 'nonQuery' : 'select';
                item.rows = (r.totalRows != null ? r.totalRows : (Array.isArray(r.rows) ? r.rows.length : 0)) || 0;
                item.duration = Number(r.queryTime || 0);
                item.error = '';
            } else {
                const msg = String(payload || '执行失败');
                if (msg.includes('已取消') || msg.toLowerCase().includes('cancel')) {
                    item.status = 'cancelled';
                    item.error = msg;
                } else {
                    item.status = 'error';
                    item.error = msg;
                }
            }
            updateSqlHistoryList();
            saveSqlHistoryToStorage();
        }
        
        // 清空SQL历史
        function clearSqlHistory() {
            if (confirm('确定要清空所有SQL历史记录吗？')) {
                sqlHistory = [];
                updateSqlHistoryList();
                saveSqlHistoryToStorage();
            }
        }

        // ===== SQL历史：导出/导入（JSON） =====
        function exportSqlHistory() {
            try {
                const payload = {
                    version: 1,
                    exportedAt: new Date().toISOString(),
                    items: Array.isArray(sqlHistory) ? sqlHistory : []
                };
                const text = JSON.stringify(payload, null, 2);
                xslqShowTextModal('SQL历史导出（JSON）', text);
            } catch (e) {
                alert('导出失败：' + (e?.message || e));
            }
        }

        async function importSqlHistory() {
            try {
                const input = await xslqPromptTextArea('导入 SQL历史（粘贴 JSON）', '', '请粘贴 exportSqlHistory 导出的 JSON…');
                if (input == null) return;
                const obj = JSON.parse(String(input || ''));
                const items = Array.isArray(obj?.items) ? obj.items : (Array.isArray(obj) ? obj : null);
                if (!items) { alert('导入失败：JSON 格式不正确（需为 {items:[...]} 或直接数组）'); return; }

                // 自动备份（仅保留最近 3 份）
                try {
                    const bkKey = 'excelSqlite.sqlHistory.backups.v1';
                    const raw = localStorage.getItem(bkKey) || '[]';
                    const arr = JSON.parse(raw);
                    const backups = Array.isArray(arr) ? arr : [];
                    backups.unshift({ at: new Date().toISOString(), items: sqlHistory });
                    localStorage.setItem(bkKey, JSON.stringify(backups.slice(0, 3)));
                } catch (_) { }

                // 合并策略：按 SQL 去重，导入的放在后面；保留 pinned
                const norm = (s) => String(s || '').trim().replace(/\s+/g, ' ').toLowerCase();
                const map = new Map();
                (Array.isArray(sqlHistory) ? sqlHistory : []).forEach(it => { try { map.set(norm(it.sql), it); } catch (_) { } });
                items.forEach(it => {
                    try {
                        const k = norm(it.sql);
                        if (!k) return;
                        const old = map.get(k);
                        if (!old) map.set(k, it);
                        else {
                            // 保留 pinned/最新时间等
                            old.pinned = !!(old.pinned || it.pinned);
                            if (it.time) old.time = it.time;
                        }
                    } catch (_) { }
                });
                sqlHistory = Array.from(map.values());
                // 默认按 time/id 粗排（导入后“看起来合理”）
                sqlHistory.sort((a, b) => Number(b.id || 0) - Number(a.id || 0));
                updateSqlHistoryList();
                saveSqlHistoryToStorage();
                alert(`导入完成：${items.length} 条（合并去重后 ${sqlHistory.length} 条）。\n已自动备份导入前历史（最多保留 3 份）。`);
            } catch (e) {
                alert('导入失败：' + (e?.message || e));
            }
        }

        // ===== SQL模板库（本地持久化）=====
        const SQL_TPL_KEY = 'excelSqlite.sqlTemplates.v1';
        let sqlTemplates = [];

        function loadSqlTemplatesFromStorage() {
            try {
                const raw = localStorage.getItem(SQL_TPL_KEY);
                if (!raw) return;
                const arr = JSON.parse(raw);
                if (Array.isArray(arr)) sqlTemplates = arr;
            } catch (_) { }
        }
        function saveSqlTemplatesToStorage() {
            try { localStorage.setItem(SQL_TPL_KEY, JSON.stringify((sqlTemplates || []).slice(0, 500))); } catch (_) { }
        }

        function switchSqlHistoryTab(key) {
            const k = (key === 'tpl') ? 'tpl' : 'history';
            const h = document.getElementById('sqlHistoryTab_history');
            const t = document.getElementById('sqlHistoryTab_tpl');
            const bh = document.getElementById('sqlHistoryTabBtn_history');
            const bt = document.getElementById('sqlHistoryTabBtn_tpl');
            if (h) h.style.display = (k === 'history') ? 'block' : 'none';
            if (t) t.style.display = (k === 'tpl') ? 'block' : 'none';
            if (bh) bh.style.background = (k === 'history') ? 'linear-gradient(180deg,#e7f3ff 0%,#cfe8ff 100%)' : '';
            if (bt) bt.style.background = (k === 'tpl') ? 'linear-gradient(180deg,#e7f3ff 0%,#cfe8ff 100%)' : '';
            try { localStorage.setItem('sqlHistoryTab', k); } catch (_) { }
            if (k === 'tpl') { try { updateSqlTemplateList(); } catch (_) { } }
        }

        function updateSqlTemplateList() {
            const box = document.getElementById('sqlTplList');
            if (!box) return;
            const q = String(document.getElementById('sqlTplSearch')?.value || '').trim().toLowerCase();
            const arr = Array.isArray(sqlTemplates) ? sqlTemplates : [];
            const base = q
                ? arr.filter(it => (String(it.name||'') + '\n' + String(it.group||'') + '\n' + String(it.sql||'')).toLowerCase().includes(q))
                : arr;
            const filtered = base.filter(x => !!x?.pinned).concat(base.filter(x => !x?.pinned));
            box.innerHTML = filtered.map((it) => `
                <div class="sql-history-item" style="padding: 12px; background: white; border-radius: 4px; margin-bottom: 8px; cursor: pointer;" onclick="insertSqlTemplate(${it.id}, false)">
                    <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:4px; gap:10px;">
                        <div style="display:flex; flex-direction:column; gap:2px;">
                            <span style="font-size: 9pt; color:#333;"><b>${escapeHtml(it.name || '未命名模板')}</b>${it.group ? ` <span style="font-size:8pt; color:#6c757d;">[${escapeHtml(it.group)}]</span>` : ''}</span>
                            <span style="font-size: 8pt; color:#666;">${escapeHtml(it.updatedAt || it.createdAt || '')}</span>
                        </div>
                        <div style="display:flex; gap:10px; align-items:center;">
                            <button class="btn btn-secondary" style="padding:2px 8px; font-size: 8pt;" title="${it.pinned ? '取消收藏' : '收藏置顶'}" onclick="event.stopPropagation(); toggleSqlTemplatePin(${it.id});">${it.pinned ? '★' : '☆'}</button>
                            <button class="btn btn-secondary" style="padding:2px 8px; font-size: 8pt;" onclick="event.stopPropagation(); insertSqlTemplate(${it.id}, false)">⤓ 插入</button>
                            <button class="btn btn-secondary" style="padding:2px 8px; font-size: 8pt;" onclick="event.stopPropagation(); insertSqlTemplate(${it.id}, true)">▶ 执行</button>
                            <button class="btn btn-secondary" style="padding:2px 8px; font-size: 8pt;" onclick="event.stopPropagation(); editSqlTemplate(${it.id});">✎ 编辑</button>
                            <button class="btn btn-danger" style="padding:2px 8px; font-size: 8pt;" onclick="event.stopPropagation(); deleteSqlTemplate(${it.id});">🗑</button>
                        </div>
                    </div>
                    <div style="font-family: monospace; font-size: 9pt; color: #333; white-space: nowrap; overflow: hidden; text-overflow: ellipsis;">${escapeHtml(String(it.sql || ''))}</div>
                </div>
            `).join('');
        }

        function searchSqlTemplates() { updateSqlTemplateList(); }

        async function newSqlTemplate() {
            const name = prompt('模板名称：', '常用查询') || '';
            if (!name.trim()) return;
            const group = prompt('分组（可留空）：', '默认') || '';
            const sql = await xslqPromptTextArea('新建 SQL 模板（输入 SQL）', '', '请输入 SQL…');
            if (sql == null) return;
            const now = new Date().toISOString();
            const it = { id: Date.now(), name: name.trim(), group: group.trim(), sql: String(sql||''), pinned: false, createdAt: now, updatedAt: now };
            sqlTemplates.unshift(it);
            saveSqlTemplatesToStorage();
            updateSqlTemplateList();
        }

        async function editSqlTemplate(id) {
            const it = (sqlTemplates || []).find(x => Number(x.id) === Number(id));
            if (!it) return;
            const name = prompt('模板名称：', it.name || '') || '';
            if (!name.trim()) return;
            const group = prompt('分组（可留空）：', it.group || '') || '';
            const sql = await xslqPromptTextArea('编辑 SQL 模板（修改 SQL）', String(it.sql||''), '请输入 SQL…');
            if (sql == null) return;
            it.name = name.trim();
            it.group = group.trim();
            it.sql = String(sql||'');
            it.updatedAt = new Date().toISOString();
            saveSqlTemplatesToStorage();
            updateSqlTemplateList();
        }

        function deleteSqlTemplate(id) {
            if (!confirm('确定删除该模板吗？')) return;
            sqlTemplates = (sqlTemplates || []).filter(x => Number(x.id) !== Number(id));
            saveSqlTemplatesToStorage();
            updateSqlTemplateList();
        }

        function toggleSqlTemplatePin(id) {
            const it = (sqlTemplates || []).find(x => Number(x.id) === Number(id));
            if (!it) return;
            it.pinned = !it.pinned;
            saveSqlTemplatesToStorage();
            updateSqlTemplateList();
        }

        function insertSqlTemplate(id, runNow) {
            const it = (sqlTemplates || []).find(x => Number(x.id) === Number(id));
            if (!it) return;
            try { sqlEditorSetText(String(it.sql || '')); } catch (_) { }
            try { switchTab('sql-editor'); } catch (_) { }
            try { updateSqlEditorCursor(); } catch (_) { }
            if (runNow) {
                setTimeout(() => { try { executeSqlEditor(); } catch (_) { } }, 0);
            }
        }

        function exportSqlTemplates() {
            try {
                const payload = { version: 1, exportedAt: new Date().toISOString(), items: Array.isArray(sqlTemplates) ? sqlTemplates : [] };
                xslqShowTextModal('SQL模板导出（JSON）', JSON.stringify(payload, null, 2));
            } catch (e) {
                alert('导出失败：' + (e?.message || e));
            }
        }

        async function importSqlTemplates() {
            try {
                const input = await xslqPromptTextArea('导入 SQL模板（粘贴 JSON）', '', '请粘贴 exportSqlTemplates 导出的 JSON…');
                if (input == null) return;
                const obj = JSON.parse(String(input || ''));
                const items = Array.isArray(obj?.items) ? obj.items : (Array.isArray(obj) ? obj : null);
                if (!items) { alert('导入失败：JSON 格式不正确（需为 {items:[...]} 或直接数组）'); return; }
                // 备份
                try {
                    const bkKey = 'excelSqlite.sqlTemplates.backups.v1';
                    const raw = localStorage.getItem(bkKey) || '[]';
                    const arr = JSON.parse(raw);
                    const backups = Array.isArray(arr) ? arr : [];
                    backups.unshift({ at: new Date().toISOString(), items: sqlTemplates });
                    localStorage.setItem(bkKey, JSON.stringify(backups.slice(0, 3)));
                } catch (_) { }
                // 合并去重：按 name+sql
                const norm = (s) => String(s || '').trim().replace(/\s+/g, ' ').toLowerCase();
                const map = new Map();
                (Array.isArray(sqlTemplates) ? sqlTemplates : []).forEach(it => { try { map.set(norm((it.name||'')+'|'+(it.sql||'')), it); } catch (_) { } });
                items.forEach(it => {
                    try {
                        const k = norm((it.name||'')+'|'+(it.sql||''));
                        if (!k) return;
                        const old = map.get(k);
                        if (!old) map.set(k, it);
                        else old.pinned = !!(old.pinned || it.pinned);
                    } catch (_) { }
                });
                sqlTemplates = Array.from(map.values());
                sqlTemplates.sort((a, b) => Number(b.id || 0) - Number(a.id || 0));
                saveSqlTemplatesToStorage();
                updateSqlTemplateList();
                alert(`导入完成：${items.length} 条（合并去重后 ${sqlTemplates.length} 条）。\n已自动备份导入前模板（最多保留 3 份）。`);
            } catch (e) {
                alert('导入失败：' + (e?.message || e));
            }
        }

        function clearSqlTemplates() {
            if (!confirm('确定要清空所有 SQL 模板吗？')) return;
            sqlTemplates = [];
            saveSqlTemplatesToStorage();
            updateSqlTemplateList();
        }
        
        // 切换表结构显示
        function toggleSchema(tableId) {
            const element = document.getElementById('schema-' + tableId);
            const header = element.previousElementSibling;
            if (element) {
                const isVisible = element.style.display !== 'none';
                element.style.display = isVisible ? 'none' : 'block';
                header.textContent = header.textContent.replace(isVisible ? '▼' : '▶', isVisible ? '▶' : '▼');
            }
        }
        
        // 更新SQL编辑器光标位置
        function updateSqlEditorCursor() {
            const cm = window.__cmSqlEditor || null;
            if (cm) {
                const cur = cm.getCursor();
                document.getElementById('sqlEditorLine').textContent = (cur.line + 1);
                document.getElementById('sqlEditorCol').textContent = (cur.ch + 1);
                return;
            }
            const textarea = document.getElementById('sqlEditorTextarea');
            if (!textarea) return;
            const text = textarea.value || '';
            const cursorPos = textarea.selectionStart || 0;
            const lines = text.substring(0, cursorPos).split('\n');
            const currentLine = lines.length;
            const currentCol = lines[lines.length - 1].length + 1;
            document.getElementById('sqlEditorLine').textContent = currentLine;
            document.getElementById('sqlEditorCol').textContent = currentCol;
        }
        
        // 导出SQL结果
        function exportSqlResult() {
            if (!ensureSqliteMode('导出SQL结果')) return;
            const sql = normalizeSqlParamSyntax((sqlEditorGetText() || '')).trim();
            if (!sql) { alert('没有可导出的SQL：请先输入并执行查询'); return; }
            // C：提供“直接打开 + 另存为”，并支持 CSV
            const fmt = confirm('导出格式：\n\n【确定】导出 Excel(xlsx)\n【取消】导出 CSV') ? 'xlsx' : 'csv';
            const open = confirm(`是否直接打开 ${fmt.toUpperCase()}？\n\n【确定】直接打开（临时文件）\n【取消】另存为...`);
            try { window.__exportJobId = ''; showExportProgressModal(); updateExportProgressView(null, '已提交导出请求…'); } catch (_) { }
            window.chrome.webview.postMessage({
                action: 'exportQueryToFile',
                sql,
                params: (window.__sqlParams || {}),
                format: fmt,
                mode: open ? 'open' : 'saveas',
                limit: 0,
                // 大 SQL 常常会在“预统计 COUNT(*)”阶段卡很久；默认跳过预统计，让导出立即弹出保存对话框
                skipCount: true,
                excelOptions: { fontName: '微软雅黑', fontSize: 9 }
            });
        }
        
        // 显示SQL执行结果
        function showSqlResult(columns, rows, info) {
            const table = document.getElementById('sqlEditorResultTable');
            
            // 更新表头
            table.innerHTML = `
                <thead>
                    <tr>${columns.map(col => `<th>${col}</th>`).join('')}</tr>
                </thead>
                <tbody>
                    ${rows.map(row => `<tr>${columns.map(col => `<td>${row[col] !== null ? row[col] : 'NULL'}</td>`).join('')}</tr>`).join('')}
                </tbody>
            `;
            
            document.getElementById('sqlEditorResultInfo').textContent = info;
        }
        
