        function toggleMtsDownloadMenu(e) {
            if (e && e.stopPropagation) e.stopPropagation();
            const menu = document.getElementById('mtsDownloadMenu');
            if (!menu) return;
            menu.style.display = (menu.style.display === 'none' || !menu.style.display) ? 'block' : 'none';
        }
        function hideMtsDownloadMenu() {
            const menu = document.getElementById('mtsDownloadMenu');
            if (menu) menu.style.display = 'none';
        }
        function exportMts(format) {
            const baseSql = window.__mtsSqlBase || buildMtsSqlBase();
            if (!baseSql) { alert('暂无可导出的SQL，请先配置多表统计。'); return; }
            if (!window.__sqliteReady) { alert('SQLite 尚未导入：请先在【项目管理】完成导入'); return; }
            const f = (format === 'csv') ? 'csv' : (format === 'xlsx_text' ? 'xlsx_text' : 'xlsx');
            window.chrome.webview.postMessage({
                action: 'exportQueryToFile',
                sql: baseSql,
                format: f,
                limit: 0,
                skipCount: true,
                excelOptions: { fontName: '微软雅黑', fontSize: 9 }
            });
        }
        
        // 多表关联统计：显示统计结果
        function showMultiTableStatsResults(results) {
            document.getElementById('mtsResultCard').style.display = 'block';
            document.getElementById('mtsResultInfo').innerHTML = `
                <strong>关联条件：</strong>${results.joinCondition}<br>
                <strong>统计维度：</strong>${results.groupBy}<br>
                <strong>统计指标：</strong>${results.metrics}<br>
                <strong>处理行数：</strong>${results.totalRows.toLocaleString()}行<br>
                <strong>统计时间：</strong>${results.statsTime}秒
            `;
            
            const thead = document.getElementById('mtsResultHead');
            const tbody = document.getElementById('mtsResultBody');
            thead.innerHTML = '';
            tbody.innerHTML = '';
            
            // 添加表头
            const headerRow = document.createElement('tr');
            results.columns.forEach(col => {
                const th = document.createElement('th');
                th.textContent = col;
                headerRow.appendChild(th);
            });
            thead.appendChild(headerRow);
            
            // 添加数据行
            results.data.forEach(row => {
                const tr = document.createElement('tr');
                results.columns.forEach(col => {
                    const td = document.createElement('td');
                    td.textContent = row[col];
                    tr.appendChild(td);
                });
                tbody.appendChild(tr);
            });
        }

        // ========== 单表分拆 / 多表分拆（基于 SQLite SplitEngine） ==========
        function normalizeSplitField(f) {
            const s = String(f || '').trim();
            if (!s) return '';
            // 允许 A.字段 / B.字段
            if (s.includes('.')) return s.split('.').slice(1).join('.');
            return s;
        }

        function updateStsptPreview() {
            const splitField = normalizeSplitField(document.getElementById('stsptSplitField')?.value || '');
            const splitOpt = document.querySelector('input[name="stsptSplitOption"]:checked')?.value || 'unique';
            const outOpt = document.getElementById('stsptOutputOption')?.value || 'files';
            const outDir = document.getElementById('stsptOutputDirectory')?.value || '';
            const rowsPerFile = Number(document.getElementById('stsptRowsPerFile')?.value || 0);
            const fileNamePrefix = document.getElementById('stsptFileNamePrefix')?.value || '';
            const overwriteExisting = !!document.getElementById('stsptOverwriteExisting')?.checked;
            const includeNullGroup = !!document.getElementById('stsptIncludeNullGroup')?.checked;
            const csvDelimiter = (document.getElementById('stsptCsvDelimiter')?.value || ',').slice(0, 1);

            window.__stsptSplitConfig = { splitField, splitOpt, outOpt, outDir, rowsPerFile, fileNamePrefix, overwriteExisting, includeNullGroup, csvDelimiter };
            const el = document.getElementById('stsptConfigSummary');
            if (el) {
                const mainName = window.__sqliteMainTableName || 'Main';
                const mainLabel = getTableAliasName(mainName) || mainName;
                el.innerHTML = `
                    <strong>表:</strong> ${escapeHtml(mainLabel)}（SQLite）<br>
                    <strong>分拆字段:</strong> ${splitField || '—'}<br>
                    <strong>方式:</strong> ${splitOpt === 'count' ? `按行数（${rowsPerFile}）` : '按唯一值'}<br>
                    <strong>输出:</strong> ${escapeHtml(outOpt)}<br>
                    <strong>前缀:</strong> ${escapeHtml(fileNamePrefix || '（默认）')}<br>
                    <strong>覆盖:</strong> ${overwriteExisting ? '允许' : '不允许'}<br>
                    <strong>空值:</strong> ${includeNullGroup ? '单独一份' : '忽略/不输出'}<br>
                    <strong>CSV分隔符:</strong> ${escapeHtml(csvDelimiter)}<br>
                    <strong>目录:</strong> ${escapeHtml(outDir || '—')}
                `;
            }
        }

        function executeSingleTableSplit() {
            updateStsptPreview();
            if (!window.__sqliteReady) {
                alert('SQLite 尚未导入：请先在【项目管理】完成导入');
                return;
            }
            const cfg = window.__stsptSplitConfig || {};
            if (!cfg.splitField) { alert('请选择分拆字段'); return; }
            if (!cfg.outDir) { alert('请选择输出目录'); return; }

            const splitType = cfg.splitOpt === 'count' ? 'byRowCount' : 'byField';
            const sm = (document.querySelector('input[name="stsptSourceMode"]:checked')?.value || 'main');
            const sourceObj = (document.getElementById('stsptSourceObject')?.value || '').trim();
            const sqlText = (document.getElementById('stsptSourceSql')?.value || '').trim();
            const useSql = (sm === 'sql');
            const sourceTable = (sm === 'object' && sourceObj) ? sourceObj : (window.__sqliteMainTableName || 'Main');
            const payload = {
                action: 'executeSplit',
                sourceTable: sourceTable,
                splitField: cfg.splitField,
                outputDirectory: cfg.outDir,
                splitType,
                outputOption: cfg.outOpt,
                fileNamePrefix: cfg.fileNamePrefix || '',
                overwriteExisting: !!cfg.overwriteExisting,
                includeNullGroup: !!cfg.includeNullGroup,
                csvDelimiter: (cfg.csvDelimiter || ',').slice(0, 1),
                sql: (useSql && sqlText) ? sqlText : ''
            };
            if (splitType === 'byRowCount') payload.rowsPerFile = Number(cfg.rowsPerFile || 50000);

            window.__lastSplitTarget = 'stspt';
            try { updateSplitProgressUI({ target: 'stspt', percent: 0, stage: '开始', running: true }); } catch (_) { }
            window.chrome.webview.postMessage(payload);
            setStatusMessage('开始执行分拆...');
        }

        function buildMtsptSqlBase() {
            // SQL 覆盖模式：直接使用用户输入 SQL
            try {
                const useSql = !!document.getElementById('mtsptUseSql')?.checked;
                const sqlText = (document.getElementById('mtsptSourceSql')?.value || '').trim();
                if (useSql && sqlText) return sqlText.replace(/;+\s*$/, '');
            } catch (_) { }

            const mainTable = document.getElementById('mtsptMainTable')?.value || '';
            if (!mainTable) return '';
            const joinRows = Array.from(document.querySelectorAll('#mtsptJoinTables .join-table-row'));
            const joinRow = joinRows.length > 1 ? joinRows[1] : null;
            const joinTable = joinRow ? (joinRow.querySelector('select')?.value || '') : '';
            const joinType = joinRow ? ((joinRow.querySelectorAll('select')[1]?.value || 'INNER JOIN').toUpperCase()) : 'INNER JOIN';

            let sql = joinTable
                ? `SELECT A.*, B.*\nFROM ${sqlQuoteIdent(mainTable)} A`
                : `SELECT A.*\nFROM ${sqlQuoteIdent(mainTable)} A`;
            if (joinTable) {
                const conds = [];
                document.querySelectorAll('#mtsptJoinConditions .join-condition-row').forEach(row => {
                    const sels = row.querySelectorAll('select.form-control');
                    const left = sels[0] ? (sels[0].value || '') : '';
                    const opSel = row.querySelectorAll('select')[1];
                    const op = opSel ? (opSel.value || '=') : '=';
                    const right = sels[1] ? (sels[1].value || '') : '';
                    if (!left || !right) return;
                    conds.push(`${sqlQuoteRef(left, 'A')} ${op} ${sqlQuoteRef(right, 'B')}`);
                });
                const on = conds.length ? conds.join(' AND ') : '1=1';
                const jt = ['INNER JOIN', 'LEFT JOIN', 'RIGHT JOIN'].includes(joinType) ? joinType : 'INNER JOIN';
                sql += `\n${jt} ${sqlQuoteIdent(joinTable)} B ON ${on}`;
            }
            return sql;
        }

        function updateMtsptPreview() {
            const baseSql = buildMtsptSqlBase();
            const splitField = normalizeSplitField(document.getElementById('mtsptSplitField')?.value || '');
            const splitOpt = document.querySelector('input[name="mtsptSplitOption"]:checked')?.value || 'unique';
            const outOpt = document.getElementById('mtsptOutputOption')?.value || 'files';
            const outDir = document.getElementById('mtsptOutputDirectory')?.value || '';
            const rowsPerFile = Number(document.getElementById('mtsptRowsPerFile')?.value || 0);
            const fileNamePrefix = document.getElementById('mtsptFileNamePrefix')?.value || '';
            const overwriteExisting = !!document.getElementById('mtsptOverwriteExisting')?.checked;
            const includeNullGroup = !!document.getElementById('mtsptIncludeNullGroup')?.checked;
            const csvDelimiter = (document.getElementById('mtsptCsvDelimiter')?.value || ',').slice(0, 1);

            window.__mtsptSplitConfig = { baseSql, splitField, splitOpt, outOpt, outDir, rowsPerFile, fileNamePrefix, overwriteExisting, includeNullGroup, csvDelimiter };
            const el = document.getElementById('mtsptConfigSummary');
            if (el) {
                el.innerHTML = `
                    <strong>SQL:</strong><br>
                    <pre style="margin:8px 0 0; font-family:'Consolas','Courier New',monospace; font-size: 9pt; white-space: pre-wrap;">${baseSql || '（请先选择主表/关联表/条件）'}</pre>
                    <strong>分拆字段:</strong> ${splitField || '—'}<br>
                    <strong>方式:</strong> ${splitOpt === 'count' ? `按行数（${rowsPerFile}）` : '按唯一值'}<br>
                    <strong>输出:</strong> ${escapeHtml(outOpt)}<br>
                    <strong>前缀:</strong> ${escapeHtml(fileNamePrefix || '（默认）')}<br>
                    <strong>覆盖:</strong> ${overwriteExisting ? '允许' : '不允许'}<br>
                    <strong>空值:</strong> ${includeNullGroup ? '单独一份' : '忽略/不输出'}<br>
                    <strong>CSV分隔符:</strong> ${escapeHtml(csvDelimiter)}<br>
                    <strong>目录:</strong> ${escapeHtml(outDir || '—')}
                `;
            }
        }

        function executeMultiTableSplit() {
            updateMtsptPreview();
            if (!window.__sqliteReady) {
                alert('SQLite 尚未导入：请先在【项目管理】完成导入');
                return;
            }
            const cfg = window.__mtsptSplitConfig || {};
            if (!cfg.baseSql) { alert('请先配置关联表与关联条件'); return; }
            if (!cfg.splitField) { alert('请选择分拆字段'); return; }
            if (!cfg.outDir) { alert('请选择输出目录'); return; }

            const splitType = cfg.splitOpt === 'count' ? 'byRowCount' : 'byField';
            const payload = {
                action: 'executeMultiTableSplit',
                sql: cfg.baseSql,
                splitField: cfg.splitField,
                outputDirectory: cfg.outDir,
                splitType,
                outputOption: cfg.outOpt,
                fileNamePrefix: cfg.fileNamePrefix || '',
                overwriteExisting: !!cfg.overwriteExisting,
                includeNullGroup: !!cfg.includeNullGroup,
                csvDelimiter: (cfg.csvDelimiter || ',').slice(0, 1)
            };
            if (splitType === 'byRowCount') payload.rowsPerFile = Number(cfg.rowsPerFile || 50000);

            window.__lastSplitTarget = 'mtspt';
            try { updateSplitProgressUI({ target: 'mtspt', percent: 0, stage: '开始', running: true }); } catch (_) { }
            window.chrome.webview.postMessage(payload);
            setStatusMessage('开始执行多表分拆...');
        }

        function requestSplitPreview(target) {
            if (!window.__sqliteReady) return;
            if (target === 'mtspt') updateMtsptPreview(); else updateStsptPreview();
            const cfg = target === 'mtspt' ? (window.__mtsptSplitConfig || {}) : (window.__stsptSplitConfig || {});
            const splitType = cfg.splitOpt === 'count' ? 'byRowCount' : 'byField';
            // 单表分拆：若为 SQL 模式，则预览基于 SQL
            let stSql = '';
            let stSourceTable = (window.__sqliteMainTableName || 'Main');
            try {
                const sm = (document.querySelector('input[name="stsptSourceMode"]:checked')?.value || 'main');
                if (target !== 'mtspt' && sm === 'sql') stSql = (document.getElementById('stsptSourceSql')?.value || '').trim();
                if (target !== 'mtspt' && sm === 'object') {
                    const v = (document.getElementById('stsptSourceObject')?.value || '').trim();
                    if (v) stSourceTable = v;
                }
            } catch (_) { }
            const payload = {
                action: 'getSplitPreview',
                target,
                splitType,
                splitField: cfg.splitField || '',
                sourceTable: target === 'stspt' ? stSourceTable : '',
                sql: target === 'mtspt' ? (cfg.baseSql || '') : (stSql || ''),
                rowsPerFile: Number(cfg.rowsPerFile || 50000)
            };
            try { window.chrome.webview.postMessage(payload); } catch (_) { }
        }

        function requestSqlResultSchema(target, sql) {
            const s = (sql || '').trim();
            if (!s) return;
            // 避免死循环：同一段SQL只请求一次（或等待完成）
            try {
                window.__sqlSchemaCache = window.__sqlSchemaCache || {};
                window.__sqlSchemaPending = window.__sqlSchemaPending || {};
                const key = `${target || 't'}:${s}`;
                if (window.__sqlSchemaCache[key]) return;
                if (window.__sqlSchemaPending[key]) return;
                window.__sqlSchemaPending[key] = true;
            } catch (_) { }
            try { window.chrome.webview.postMessage({ action: 'getSqlResultSchema', target, sql: s }); } catch (_) { }
        }

        function applySqlResultSchema(msg) {
            const target = msg.target || 'unknown';
            const fields = Array.isArray(msg.fields) ? msg.fields : [];
            try {
                const sql = (target === 'stspt') ? (document.getElementById('stsptSourceSql')?.value || '').trim()
                    : (target === 'mtspt') ? (document.getElementById('mtsptSourceSql')?.value || '').trim()
                    : '';
                const key = `${target}:${sql}`;
                window.__sqlSchemaCache = window.__sqlSchemaCache || {};
                window.__sqlSchemaPending = window.__sqlSchemaPending || {};
                if (sql) window.__sqlSchemaCache[key] = true;
                if (sql) window.__sqlSchemaPending[key] = false;
            } catch (_) { }
            if (target === 'stspt') {
                window.__stsptSqlFields = fields;
                try { stsptFillSplitFieldOptions(); } catch (_) { }
            } else if (target === 'mtspt') {
                window.__mtsptSqlFields = fields;
                try { mtsptFillSplitFieldOptions(); } catch (_) { }
            }
        }

        function applySplitPreview(msg) {
            const target = msg.target || 'stspt';
            const el = document.getElementById(target === 'mtspt' ? 'mtsptPreviewStats' : 'stsptPreviewStats');
            if (!el) return;
            const st = msg.stats || msg;
            const totalRows = Number(st.totalRows || 0);
            const distinctCount = Number(st.distinctCount || 0);
            const nullRows = Number(st.nullRows || 0);
            const estFiles = st.estimatedFiles != null ? Number(st.estimatedFiles) : null;
            const top = Array.isArray(st.topValues) ? st.topValues : [];
            const topHtml = top.length
                ? `<table style="width:100%; border-collapse:collapse; margin-top:8px;">
                    <thead><tr><th style="text-align:left; border-bottom:1px solid #eee; padding:4px 0;">Top 分拆值</th><th style="text-align:right; border-bottom:1px solid #eee; padding:4px 0;">行数</th></tr></thead>
                    <tbody>${top.map(x => `<tr><td style="padding:4px 0;">${escapeHtml(String(x.value ?? x.Value ?? ''))}</td><td style="text-align:right; padding:4px 0;">${Number(x.count ?? x.Count ?? 0).toLocaleString()}</td></tr>`).join('')}</tbody>
                  </table>`
                : '';
            el.style.display = 'block';
            el.innerHTML = `
                <strong>预估统计（不执行，仅预览）：</strong><br>
                <strong>总行数：</strong>${totalRows.toLocaleString()}<br>
                <strong>唯一值：</strong>${distinctCount.toLocaleString()}${nullRows ? `（空值 ${nullRows.toLocaleString()}）` : ''}<br>
                ${estFiles != null ? `<strong>预计文件数：</strong>${estFiles.toLocaleString()}<br>` : ''}
                ${topHtml}
            `;
        }

        function updateSplitProgressUI(msg) {
            const target = msg.target || 'stspt';
            const wrapId = target === 'mtspt' ? 'mtsptSplitProgressWrap' : 'stsptSplitProgressWrap';
            const barId = target === 'mtspt' ? 'mtsptSplitProgressBar' : 'stsptSplitProgressBar';
            const txtId = target === 'mtspt' ? 'mtsptSplitProgressText' : 'stsptSplitProgressText';
            const wrap = document.getElementById(wrapId);
            const bar = document.getElementById(barId);
            const txt = document.getElementById(txtId);
            if (!wrap || !bar || !txt) return;
            const pct = Math.max(0, Math.min(100, Math.round(Number(msg.percent || 0))));
            const stage = msg.stage || '';
            const running = (msg.running !== false);
            wrap.style.display = running ? 'block' : 'none';
            bar.style.width = pct + '%';
            txt.textContent = stage ? `${stage}（${pct}%）` : `${pct}%`;
        }

        function showSplitResults(target, result) {
            const r = result && result.result ? result.result : result;
            const files = (r && r.files) ? r.files : [];
            const outDir = (target === 'mtspt' ? (window.__mtsptSplitConfig?.outDir || '') : (window.__stsptSplitConfig?.outDir || '')) || '';
            try {
                if (target === 'mtspt') window.__lastMtsptSplitResult = r;
                else window.__lastStsptSplitResult = r;
            } catch (_) { }
            const infoHtml = `
                <strong>文件数量：</strong>${Number(r.fileCount || files.length).toLocaleString()} 个<br>
                <strong>总行数：</strong>${Number(r.totalRows || 0).toLocaleString()} 行<br>
                <strong>耗时：</strong>${r.splitTime || ''} 秒
                <div style="margin-top:10px; display:flex; gap:8px; flex-wrap:wrap;">
                    <button class="btn btn-secondary" onclick="openSplitOutputFolder('${target}')">📁 打开输出目录</button>
                    <button class="btn btn-secondary" onclick="exportSplitHtmlReport('${target}')">📝 导出分拆报告（HTML）</button>
                    <button class="btn btn-secondary" onclick="copySplitFileList('${target}')">📋 复制文件清单</button>
                </div>
            `;

            const cardId = target === 'mtspt' ? 'mtsptResultCard' : 'stsptResultCard';
            const infoId = target === 'mtspt' ? 'mtsptResultInfo' : 'stsptResultInfo';
            const headId = target === 'mtspt' ? 'mtsptResultHead' : 'stsptResultHead';
            const bodyId = target === 'mtspt' ? 'mtsptResultBody' : 'stsptResultBody';

            document.getElementById(cardId).style.display = 'block';
            document.getElementById(infoId).innerHTML = infoHtml;
            const thead = document.getElementById(headId);
            const tbody = document.getElementById(bodyId);
            thead.innerHTML = '<tr><th>文件名</th><th>行数</th><th>分拆值</th></tr>';
            tbody.innerHTML = '';
            files.forEach(f => {
                const tr = document.createElement('tr');
                tr.innerHTML = `<td>${f.fileName || f.FileName || ''}</td><td>${(f.rowCount || f.RowCount || 0).toLocaleString()}</td><td>${f.splitValue || f.SplitValue || ''}</td>`;
                tbody.appendChild(tr);
            });

            // 结束进度条
            try {
                updateSplitProgressUI({ target: target, percent: 100, stage: '完成', running: false });
            } catch (_) { }
        }

        function openSplitOutputFolder(target) {
            const outDir = (target === 'mtspt' ? (window.__mtsptSplitConfig?.outDir || '') : (window.__stsptSplitConfig?.outDir || '')) || '';
            if (!outDir) { alert('未找到输出目录'); return; }
            try { window.chrome.webview.postMessage({ action: 'openPath', path: outDir }); } catch (_) { }
        }

        function copySplitFileList(target) {
            const last = target === 'mtspt' ? (window.__lastMtsptSplitResult || null) : (window.__lastStsptSplitResult || null);
            const files = last && last.files ? last.files : [];
            if (!files.length) { alert('暂无文件清单'); return; }
            const lines = files.map(f => `${f.fileName || f.FileName || ''}\t${f.rowCount || f.RowCount || 0}\t${f.splitValue || f.SplitValue || ''}`);
            try { window.chrome.webview.postMessage({ action: 'setClipboard', text: lines.join('\n'), context: 'splitFileList' }); } catch (_) { }
            try { setStatusMessage('已复制文件清单到剪贴板'); } catch (_) { }
        }

        function exportSplitHtmlReport(target) {
            const cfg = target === 'mtspt' ? (window.__mtsptSplitConfig || {}) : (window.__stsptSplitConfig || {});
            const last = target === 'mtspt' ? (window.__lastMtsptSplitResult || null) : (window.__lastStsptSplitResult || null);
            const files = last && last.files ? last.files : [];
            if (!files.length) { alert('暂无分拆结果可导出'); return; }
            const title = target === 'mtspt' ? '多表分拆报告' : '数据分拆报告';
            const rows = files.map(f => `<tr><td>${escapeHtml(f.fileName || f.FileName || '')}</td><td class="num">${escapeHtml(String(f.rowCount || f.RowCount || 0))}</td><td>${escapeHtml(f.splitValue || f.SplitValue || '')}</td></tr>`).join('');
            const html = `<!doctype html><html><head><meta charset="utf-8"><title>${title}</title>
<style>body{font-family:Microsoft YaHei,Arial; padding:18px; font-size:9pt;} table{border-collapse:collapse;width:100%;} th,td{border:1px solid #ddd;padding:6px 8px;font-size:9pt; text-align:left;} th{background:#fafafa;}
.num{ text-align:right; }
.k{color:#666;width:140px;}</style></head><body>
<h2 style="margin:0 0 8px;">${title}</h2>
<div style="color:#666;margin-bottom:12px;">生成时间：${new Date().toLocaleString()}</div>
<table style="margin-bottom:14px;"><tr><td class="k">输出目录</td><td>${escapeHtml(cfg.outDir||'')}</td></tr>
<tr><td class="k">分拆字段</td><td>${escapeHtml(cfg.splitField||'')}</td></tr>
<tr><td class="k">分拆方式</td><td>${escapeHtml(cfg.splitOpt==='count'?'按行数':'按唯一值')}</td></tr>
<tr><td class="k">输出选项</td><td>${escapeHtml(cfg.outOpt||'')}</td></tr>
<tr><td class="k">文件名前缀</td><td>${escapeHtml(cfg.fileNamePrefix||'（默认）')}</td></tr>
<tr><td class="k">覆盖策略</td><td>${cfg.overwriteExisting?'允许覆盖':'不允许覆盖'}</td></tr>
<tr><td class="k">空值</td><td>${cfg.includeNullGroup?'单独一份':'忽略/不输出'}</td></tr>
</table>
<h3 style="margin:12px 0 6px;">输出文件清单（${files.length}）</h3>
<table><thead><tr><th>文件名</th><th>行数</th><th>分拆值</th></tr></thead><tbody>${rows}</tbody></table>
</body></html>`;
            try {
                window.chrome.webview.postMessage({ action: 'saveHtmlReport', reportName: 'split', fileName: `${target}_split_report.html`, html: html, openAfterSave: true });
            } catch (e) {
                alert('导出失败：' + (e && e.message ? e.message : e));
            }
        }

        // ========== 单表分拆：数据源/字段联动（主表 / 表视图 / SQL） ==========
        function stsptOnSourceModeChanged() {
            const mode = document.querySelector('input[name="stsptSourceMode"]:checked')?.value || 'main';
            const gObj = document.getElementById('stsptSourceObjectGroup');
            const gSql = document.getElementById('stsptSourceSqlGroup');
            if (gObj) gObj.style.display = (mode === 'object') ? 'block' : 'none';
            if (gSql) gSql.style.display = (mode === 'sql') ? 'block' : 'none';
            if (mode === 'object') {
                try { stsptFillSourceObjectOptions(); } catch (_) { }
            }
            stsptFillSplitFieldOptions();
        }

        function stsptFillSourceObjectOptions() {
            const sel = document.getElementById('stsptSourceObject');
            if (!sel) return;
            const prev = sel.value || '';
            const objs = Array.isArray(window.__dbmObjects) ? window.__dbmObjects : [];
            const names = objs.map(x => ({ name: String(x.name || x.Name || '').trim(), type: String(x.type || x.Type || '').trim().toLowerCase() }))
                .filter(x => x.name);
            if (names.length) {
                const views = names.filter(x => x.type === 'view').map(x => x.name);
                const opt = (t) => `<option value="${escapeHtml(t)}" title="${escapeHtml(t)}">${escapeHtml(getTableAliasName(t) || t)}</option>`;
                sel.innerHTML = '<option value="">选择透视表</option>'
                    + (views.length ? `<optgroup label="透视表（视图）">${views.map(opt).join('')}</optgroup>` : '');
                if (prev && names.some(x => x.name === prev)) sel.value = prev;
                return;
            }
            const list = Array.isArray(window.__sqliteObjects) ? window.__sqliteObjects : (Array.isArray(window.__sqliteTables) ? window.__sqliteTables : []);
            sel.innerHTML = '<option value="">选择透视表</option>' + list.map(t => `<option value="${escapeHtml(t)}" title="${escapeHtml(t)}">${escapeHtml(getTableAliasName(t) || t)}</option>`).join('');
            if (prev && list.includes(prev)) sel.value = prev;
        }

        function stsptOnSourceObjectChanged() {
            stsptFillSplitFieldOptions();
        }

        function stsptCopySqlFromEditor() {
            // 尝试从 SQL 实验室编辑器取 SQL；取不到就忽略
            try {
                const sql = (window.__sqlEditor && typeof window.__sqlEditor.getValue === 'function') ? window.__sqlEditor.getValue() : '';
                const ta = document.getElementById('stsptSourceSql');
                if (ta && sql) ta.value = sql;
                stsptFillSplitFieldOptions();
            } catch (_) { }
        }

        function stsptFillSplitFieldOptions() {
            const mode = document.querySelector('input[name="stsptSourceMode"]:checked')?.value || 'main';
            const sel = document.getElementById('stsptSplitField');
            if (!sel) return;

            // 1) SQL 模式：用 SQL schema 字段
            if (mode === 'sql') {
                const sql = (document.getElementById('stsptSourceSql')?.value || '').trim();
                if (sql) requestSqlResultSchema('stspt', sql);
                const fields = Array.isArray(window.__stsptSqlFields) ? window.__stsptSqlFields : [];
                const prev = sel.value || '';
                sel.innerHTML = '<option value="">选择分拆字段</option>' + fields.map(f => `<option value="${escapeHtml(f)}">${escapeHtml(f)}</option>`).join('');
                if (prev && fields.includes(prev)) sel.value = prev;
                return;
            }

            // 2) 表/视图 or 主表：从 sqliteTableFields 取字段
            let table = window.__sqliteMainTableName || '';
            if (mode === 'object') {
                table = (document.getElementById('stsptSourceObject')?.value || '').trim() || table;
            }
            if (table) requestSqliteTableFields(table);
            const m = window.__sqliteTableFields || {};
            const fields = table && Array.isArray(m[table]) ? m[table] : [];
            const prev = sel.value || '';
            sel.innerHTML = '<option value="">选择分拆字段</option>' + fields.map(f => `<option value="${escapeHtml(f)}">${escapeHtml(f)}</option>`).join('');
            if (prev && fields.includes(prev)) sel.value = prev;
        }

        // ========== 多表分拆：分拆字段候选（A/B 字段 or SQL schema） ==========
        function mtsptOnUseSqlChanged() {
            const useSql = !!document.getElementById('mtsptUseSql')?.checked;
            const ta = document.getElementById('mtsptSourceSql');
            if (ta) ta.style.display = useSql ? 'block' : 'none';
            try { mtsptFillSplitFieldOptions(); } catch (_) { }
        }

        function mtsptCopySqlFromMtq() {
            try {
                const sql = (window.__mtqSqlBase || window.__mtqSql || '').trim();
                const ta = document.getElementById('mtsptSourceSql');
                if (ta && sql) ta.value = sql;
                document.getElementById('mtsptUseSql').checked = true;
                mtsptOnUseSqlChanged();
            } catch (_) { }
        }

        function mtsptFillSplitFieldOptions() {
            const sel = document.getElementById('mtsptSplitField');
            if (!sel) return;
            const useSql = !!document.getElementById('mtsptUseSql')?.checked;
            if (useSql) {
                const sql = (document.getElementById('mtsptSourceSql')?.value || '').trim();
                if (sql) requestSqlResultSchema('mtspt', sql);
                const fields = Array.isArray(window.__mtsptSqlFields) ? window.__mtsptSqlFields : [];
                const prev = sel.value || '';
                sel.innerHTML = '<option value="">选择分拆字段</option>' + fields.map(f => `<option value="${escapeHtml(f)}">${escapeHtml(f)}</option>`).join('');
                if (prev && fields.includes(prev)) sel.value = prev;
                return;
            }

            const main = (document.getElementById('mtsptMainTable')?.value || '').trim();
            const joinRow = document.querySelectorAll('#mtsptJoinTables .join-table-row')[1] || null;
            const joinTable = joinRow ? (joinRow.querySelector('select')?.value || '').trim() : '';
            if (main) requestSqliteTableFields(main);
            if (joinTable) requestSqliteTableFields(joinTable);
            const m = window.__sqliteTableFields || {};
            const a = main && Array.isArray(m[main]) ? m[main] : [];
            const b = joinTable && Array.isArray(m[joinTable]) ? m[joinTable] : [];
            const opts = []
                .concat(a.map(f => ({ v: `A.${f}`, t: `A（${getTableAliasName(main)||main||'A'}）.${f}` })))
                .concat(b.map(f => ({ v: `B.${f}`, t: `B（${getTableAliasName(joinTable)||joinTable||'B'}）.${f}` })));
            const prev = sel.value || '';
            sel.innerHTML = '<option value="">选择分拆字段</option>' + opts.map(o => `<option value="${escapeHtml(o.v)}">${escapeHtml(o.t)}</option>`).join('');
            if (prev && opts.some(o => o.v === prev)) sel.value = prev;
        }

        // 当表字段加载完成时，顺便刷新分拆字段候选
        try { const _oldMtqRefresh = window.mtqRefreshUiAfterFieldsLoaded; } catch (_) { }

        // ---- 单表分拆向导：步骤切换 ----
        let stsptCurrentStep = 1;
        function nextStsptStep(step) {
            document.querySelector(`[data-step="stspt${step}"]`)?.classList.remove('active');
            document.getElementById(`step-stspt${step}`)?.classList.remove('active');
            stsptCurrentStep = step + 1;
            document.querySelector(`[data-step="stspt${stsptCurrentStep}"]`)?.classList.add('active');
            document.getElementById(`step-stspt${stsptCurrentStep}`)?.classList.add('active');
            if (stsptCurrentStep === 3) updateStsptPreview();
            if (stsptCurrentStep === 3) { try { requestSplitPreview('stspt'); } catch (_) { } }
            try { dsUpdateBottomBar(); } catch (_) { }
        }

        // 数据分拆：底部栏逻辑（整合原 Step 按钮）
        function dsUpdateBottomBar() {
            const prev = document.getElementById('dsBarPrev');
            const next = document.getElementById('dsBarNext');
            const pv = document.getElementById('dsBarPreview');
            const ex = document.getElementById('dsBarExecute');
            const s = Number(stsptCurrentStep || 1);
            if (prev) prev.style.display = (s <= 1) ? 'none' : 'inline-block';
            if (next) next.style.display = (s >= 3) ? 'none' : 'inline-block';
            if (pv) pv.style.display = (s >= 3) ? 'inline-block' : 'none';
            if (ex) ex.style.display = (s >= 3) ? 'inline-block' : 'none';
        }
        function dsBarPrev() { try { prevStsptStep(stsptCurrentStep); } catch (_) { } }
        function dsBarNext() { try { nextStsptStep(stsptCurrentStep); } catch (_) { } }
        function dsBarPreview() { try { requestSplitPreview('stspt'); } catch (_) { } }
        function prevStsptStep(step) {
            document.querySelector(`[data-step="stspt${step}"]`)?.classList.remove('active');
            document.getElementById(`step-stspt${step}`)?.classList.remove('active');
            stsptCurrentStep = step - 1;
            document.querySelector(`[data-step="stspt${stsptCurrentStep}"]`)?.classList.add('active');
            document.getElementById(`step-stspt${stsptCurrentStep}`)?.classList.add('active');
            try { dsUpdateBottomBar(); } catch (_) { }
        }
        function showStsptStepHelp(step) {
            const msg = {
                1: '步骤1（选择配置）：\n- 选择“分拆依据字段”\n- 选择“按唯一值分拆”或“按行数分拆”\n说明：此步只负责确定分拆对象与分拆方式，不执行。',
                2: '步骤2（设置输出）：\n- 选择输出选项\n- 选择输出目录（建议空目录）\n- 若按行数分拆：填写每个文件行数\n说明：此步只保存配置，不执行。',
                3: '步骤3（执行分拆）：\n- 查看预览摘要\n- 点击“执行分拆”开始生成文件/工作表'
            }[step] || '帮助信息';
            alert(msg);
        }
        function saveStsptStepSettings(step) {
            try {
                saveTempTemplate('stspt', collectStsptSettings());
                setStatusMessage(`数据分拆：已保存设置（Step${step}）`);
            } catch (e) {
                console.error(e);
                alert('保存设置失败：' + (e && e.message ? e.message : e));
            }
        }

        function stsptOnSplitOptionChanged() {
            const splitOpt = document.querySelector('input[name="stsptSplitOption"]:checked')?.value || 'unique';
            const g = document.getElementById('stsptRowsPerFileGroup');
            if (g) g.style.display = (splitOpt === 'count') ? 'block' : 'none';
            updateStsptPreview();
        }

        function stsptOnOutputOptionChanged() {
            const outOpt = document.getElementById('stsptOutputOption')?.value || 'files';
            const g = document.getElementById('stsptCsvDelimiterGroup');
            if (g) g.style.display = (outOpt === 'csv') ? 'block' : 'none';
            updateStsptPreview();
        }

        function collectStsptSettings() {
            return {
                currentStep: stsptCurrentStep,
                splitField: document.getElementById('stsptSplitField')?.value || '',
                splitOpt: document.querySelector('input[name="stsptSplitOption"]:checked')?.value || 'unique',
                outOpt: document.getElementById('stsptOutputOption')?.value || 'files',
                outDir: document.getElementById('stsptOutputDirectory')?.value || '',
                rowsPerFile: Number(document.getElementById('stsptRowsPerFile')?.value || 50000),
                fileNamePrefix: document.getElementById('stsptFileNamePrefix')?.value || '',
                overwriteExisting: !!document.getElementById('stsptOverwriteExisting')?.checked,
                includeNullGroup: !!document.getElementById('stsptIncludeNullGroup')?.checked,
                csvDelimiter: (document.getElementById('stsptCsvDelimiter')?.value || ',').slice(0, 1)
            };
        }

        function applyStsptSettings(obj) {
            if (!obj) return;
            try {
                if (obj.splitField && document.getElementById('stsptSplitField')) document.getElementById('stsptSplitField').value = obj.splitField;
                if (obj.splitOpt) {
                    document.querySelectorAll('input[name="stsptSplitOption"]').forEach(r => { r.checked = (r.value === obj.splitOpt); });
                }
                if (obj.outOpt && document.getElementById('stsptOutputOption')) document.getElementById('stsptOutputOption').value = obj.outOpt;
                if (typeof obj.outDir === 'string' && document.getElementById('stsptOutputDirectory')) document.getElementById('stsptOutputDirectory').value = obj.outDir;
                if (obj.rowsPerFile && document.getElementById('stsptRowsPerFile')) document.getElementById('stsptRowsPerFile').value = String(obj.rowsPerFile);
                if (typeof obj.fileNamePrefix === 'string' && document.getElementById('stsptFileNamePrefix')) document.getElementById('stsptFileNamePrefix').value = obj.fileNamePrefix;
                if (document.getElementById('stsptOverwriteExisting')) document.getElementById('stsptOverwriteExisting').checked = !!obj.overwriteExisting;
                if (document.getElementById('stsptIncludeNullGroup')) document.getElementById('stsptIncludeNullGroup').checked = (obj.includeNullGroup !== false);
                if (typeof obj.csvDelimiter === 'string' && document.getElementById('stsptCsvDelimiter')) document.getElementById('stsptCsvDelimiter').value = (obj.csvDelimiter || ',').slice(0, 1);
                stsptOnSplitOptionChanged();
                stsptOnOutputOptionChanged();
                if (obj.currentStep && Number(obj.currentStep) >= 1 && Number(obj.currentStep) <= 3) {
                    // 恢复步骤（不强制跳转，避免误打断）
                    // 仅刷新预览即可
                    updateStsptPreview();
                }
            } catch (e) { console.warn('applyStsptSettings failed', e); }
        }

        // ---- 多表分拆向导：步骤切换 + 关联表/条件 ----
        let mtsptCurrentStep = 1;
        let mtsptJoinTableCount = 1;
        function nextMtsptStep(step) {
            document.querySelector(`[data-step="mtspt${step}"]`)?.classList.remove('active');
            document.getElementById(`step-mtspt${step}`)?.classList.remove('active');
            mtsptCurrentStep = step + 1;
            document.querySelector(`[data-step="mtspt${mtsptCurrentStep}"]`)?.classList.add('active');
            document.getElementById(`step-mtspt${mtsptCurrentStep}`)?.classList.add('active');
            if (mtsptCurrentStep === 4) updateMtsptPreview();
            if (mtsptCurrentStep === 4) { try { requestSplitPreview('mtspt'); } catch (_) { } }
        }
        function prevMtsptStep(step) {
            document.querySelector(`[data-step="mtspt${step}"]`)?.classList.remove('active');
            document.getElementById(`step-mtspt${step}`)?.classList.remove('active');
            mtsptCurrentStep = step - 1;
            document.querySelector(`[data-step="mtspt${mtsptCurrentStep}"]`)?.classList.add('active');
            document.getElementById(`step-mtspt${mtsptCurrentStep}`)?.classList.add('active');
        }
        function showMtsptStepHelp(step) {
            const msg = {
                1: '步骤1（选择表）：\n- 选择主表（别名 A）\n- 可添加 1 个关联表（别名 B）\n说明：此步只确定参与的表，不执行。',
                2: '步骤2（设置关联）：\n- 配置 ON 条件（左字段/运算符/右字段）\n说明：此步只确认关联逻辑，不执行。',
                3: '步骤3（设置分拆）：\n- 选择分拆字段\n- 选择按唯一值/按行数\n- 配置输出目录与选项',
                4: '步骤4（执行分拆）：\n- 查看 SQL 与分拆预览\n- 点击执行开始输出'
            }[step] || '帮助信息';
            alert(msg);
        }
        function saveMtsptStepSettings(step) {
            try {
                saveTempTemplate('mtspt', collectMtsptSettings());
                setStatusMessage(`多表分拆：已保存设置（Step${step}）`);
            } catch (e) {
                console.error(e);
                alert('保存设置失败：' + (e && e.message ? e.message : e));
            }
        }

        function mtsptOnSplitOptionChanged() {
            const splitOpt = document.querySelector('input[name="mtsptSplitOption"]:checked')?.value || 'unique';
            const g = document.getElementById('mtsptRowsPerFileGroup');
            if (g) g.style.display = (splitOpt === 'count') ? 'block' : 'none';
            updateMtsptPreview();
        }

        function mtsptOnOutputOptionChanged() {
            const outOpt = document.getElementById('mtsptOutputOption')?.value || 'files';
            const g = document.getElementById('mtsptCsvDelimiterGroup');
            if (g) g.style.display = (outOpt === 'csv') ? 'block' : 'none';
            updateMtsptPreview();
        }

        function collectMtsptSettings() {
            const joinRows = Array.from(document.querySelectorAll('#mtsptJoinTables .join-table-row'));
            const mainTable = document.getElementById('mtsptMainTable')?.value || '';
            const joinTables = joinRows.slice(1).map(r => (r.querySelector('select')?.value || '')).filter(Boolean);
            const conds = [];
            document.querySelectorAll('#mtsptJoinConditions .join-condition-row').forEach(row => {
                const sels = row.querySelectorAll('select.form-control');
                const left = sels[0] ? (sels[0].value || '') : '';
                const opSel = row.querySelectorAll('select')[1];
                const op = opSel ? (opSel.value || '=') : '=';
                const right = sels[1] ? (sels[1].value || '') : '';
                if (!left || !right) return;
                conds.push({ left, op, right });
            });
            return {
                currentStep: mtsptCurrentStep,
                mainTable,
                joinTables,
                joinConditions: conds,
                splitField: document.getElementById('mtsptSplitField')?.value || '',
                splitOpt: document.querySelector('input[name="mtsptSplitOption"]:checked')?.value || 'unique',
                outOpt: document.getElementById('mtsptOutputOption')?.value || 'files',
                outDir: document.getElementById('mtsptOutputDirectory')?.value || '',
                rowsPerFile: Number(document.getElementById('mtsptRowsPerFile')?.value || 50000),
                fileNamePrefix: document.getElementById('mtsptFileNamePrefix')?.value || '',
                overwriteExisting: !!document.getElementById('mtsptOverwriteExisting')?.checked,
                includeNullGroup: !!document.getElementById('mtsptIncludeNullGroup')?.checked,
                csvDelimiter: (document.getElementById('mtsptCsvDelimiter')?.value || ',').slice(0, 1)
            };
        }

        function applyMtsptSettings(obj) {
            if (!obj) return;
            try {
                if (obj.mainTable && document.getElementById('mtsptMainTable')) document.getElementById('mtsptMainTable').value = obj.mainTable;

                // 仅恢复 1 个关联表（当前 SQL 生成器也只取第一个关联表）
                const joinTables = Array.isArray(obj.joinTables) ? obj.joinTables : [];
                // 清理多余 join table 行
                const jt = document.getElementById('mtsptJoinTables');
                if (jt) {
                    Array.from(jt.querySelectorAll('.join-table-row')).slice(1).forEach(x => x.remove());
                }
                mtsptJoinTableCount = 1;
                if (joinTables.length) {
                    addMtsptJoinTable();
                    const row = document.querySelectorAll('#mtsptJoinTables .join-table-row')[1];
                    const sel = row ? row.querySelector('select') : null;
                    if (sel) sel.value = joinTables[0] || '';
                }

                // 恢复 join 条件
                const jc = document.getElementById('mtsptJoinConditions');
                if (jc) {
                    Array.from(jc.querySelectorAll('.join-condition-row')).forEach((x, idx) => { if (idx > 0) x.remove(); });
                    const first = jc.querySelector('.join-condition-row');
                    const conds = Array.isArray(obj.joinConditions) ? obj.joinConditions : [];
                    if (first && conds.length) {
                        const c0 = conds[0];
                        const sels = first.querySelectorAll('select.form-control');
                        if (sels[0]) sels[0].value = c0.left || '';
                        const opSel = first.querySelectorAll('select')[1];
                        if (opSel) opSel.value = c0.op || '=';
                        if (sels[1]) sels[1].value = c0.right || '';
                        for (let i = 1; i < conds.length; i++) {
                            addMtsptJoinCondition();
                            const row = jc.querySelectorAll('.join-condition-row')[i];
                            const sels2 = row.querySelectorAll('select.form-control');
                            if (sels2[0]) sels2[0].value = conds[i].left || '';
                            const opSel2 = row.querySelectorAll('select')[1];
                            if (opSel2) opSel2.value = conds[i].op || '=';
                            if (sels2[1]) sels2[1].value = conds[i].right || '';
                        }
                    }
                }

                if (obj.splitField && document.getElementById('mtsptSplitField')) document.getElementById('mtsptSplitField').value = obj.splitField;
                if (obj.splitOpt) {
                    document.querySelectorAll('input[name="mtsptSplitOption"]').forEach(r => { r.checked = (r.value === obj.splitOpt); });
                }
                if (obj.outOpt && document.getElementById('mtsptOutputOption')) document.getElementById('mtsptOutputOption').value = obj.outOpt;
                if (typeof obj.outDir === 'string' && document.getElementById('mtsptOutputDirectory')) document.getElementById('mtsptOutputDirectory').value = obj.outDir;
                if (obj.rowsPerFile && document.getElementById('mtsptRowsPerFile')) document.getElementById('mtsptRowsPerFile').value = String(obj.rowsPerFile);
                if (typeof obj.fileNamePrefix === 'string' && document.getElementById('mtsptFileNamePrefix')) document.getElementById('mtsptFileNamePrefix').value = obj.fileNamePrefix;
                if (document.getElementById('mtsptOverwriteExisting')) document.getElementById('mtsptOverwriteExisting').checked = !!obj.overwriteExisting;
                if (document.getElementById('mtsptIncludeNullGroup')) document.getElementById('mtsptIncludeNullGroup').checked = (obj.includeNullGroup !== false);
                if (typeof obj.csvDelimiter === 'string' && document.getElementById('mtsptCsvDelimiter')) document.getElementById('mtsptCsvDelimiter').value = (obj.csvDelimiter || ',').slice(0, 1);
                mtsptOnSplitOptionChanged();
                mtsptOnOutputOptionChanged();
            } catch (e) { console.warn('applyMtsptSettings failed', e); }
        }

        function addMtsptJoinTable() {
            mtsptJoinTableCount++;
            const container = document.getElementById('mtsptJoinTables');
            const newRow = document.createElement('div');
            newRow.className = 'join-table-row';
            newRow.style.cssText = 'display: flex; gap: 8px; margin-bottom: 8px; align-items: center;';
            const alias = String.fromCharCode(65 + mtsptJoinTableCount - 1);
            newRow.innerHTML = `
                <span style="min-width: 60px; font-weight: bold;">关联${mtsptJoinTableCount}:</span>
                <select class="form-control" style="flex: 2;" onchange="mtsptFillSplitFieldOptions()"><option value="">选择关联表</option></select>
                <select class="form-control" style="flex: 1;" onchange="mtsptFillSplitFieldOptions()">
                    <option>INNER JOIN</option>
                    <option>LEFT JOIN</option>
                    <option>RIGHT JOIN</option>
                </select>
                <span style="min-width: 50px; text-align: center;">(别名: ${alias})</span>
                <button class="btn btn-danger" style="padding: 4px 8px;" onclick="this.parentElement.remove()">删除</button>
            `;
            container.appendChild(newRow);
            const tables = Array.isArray(window.__sqliteObjects) ? window.__sqliteObjects : (Array.isArray(window.__sqliteTables) ? window.__sqliteTables : []);
            const sel = newRow.querySelector('select.form-control');
            if (sel && tables.length) {
                sel.innerHTML = '<option value="">选择关联表</option>';
                tables.forEach(t => {
                    const opt = document.createElement('option');
                    opt.value = t;
                    opt.textContent = getTableAliasName(t) || t;
                    opt.title = t;
                    sel.appendChild(opt);
                });
            }
            try { mtsptFillSplitFieldOptions(); } catch (_) { }
        }

        function addMtsptJoinCondition() {
            const container = document.getElementById('mtsptJoinConditions');
            const newRow = document.createElement('div');
            newRow.className = 'join-condition-row';
            newRow.style.cssText = 'display: flex; gap: 8px; margin-bottom: 8px; align-items: center;';
            newRow.innerHTML = `
                <select class="form-control" style="flex: 1;"><option value="">左表字段</option></select>
                <select class="form-control" style="width: 80px;">
                    <option>=</option><option><></option><option>></option><option><</option><option>>=</option><option><=</option>
                </select>
                <select class="form-control" style="flex: 1;"><option value="">右表字段</option></select>
                <button class="btn btn-danger" style="padding: 4px 8px;" onclick="this.parentElement.remove()">删除</button>
            `;
            container.appendChild(newRow);
        }
        
        // 显示数据脱敏结果
        function showDataMaskingResults(results) {
            document.getElementById('dmResultCard').style.display = 'block';
            document.getElementById('dmResultInfo').innerHTML = `
                <strong>脱敏规则：</strong>${results.rules}<br>
                <strong>处理行数：</strong>${results.totalRows.toLocaleString()}行<br>
                <strong>脱敏字段：</strong>${results.maskedFields}<br>
                <strong>处理时间：</strong>${results.processTime}秒
            `;
            
            const thead = document.getElementById('dmResultHead');
            const tbody = document.getElementById('dmResultBody');
            thead.innerHTML = '';
            tbody.innerHTML = '';
            
            // 添加表头
            const headerRow = document.createElement('tr');
            results.columns.forEach(col => {
                const th = document.createElement('th');
                th.textContent = col;
                headerRow.appendChild(th);
            });
            thead.appendChild(headerRow);
            
            // 添加数据行
            results.data.forEach(row => {
                const tr = document.createElement('tr');
                results.columns.forEach(col => {
                    const td = document.createElement('td');
                    td.textContent = row[col];
                    tr.appendChild(td);
                });
                tbody.appendChild(tr);
            });
            
            // 显示映射表
            if (results.mapping) {
                document.getElementById('dmMappingCard').style.display = 'block';
                const mappingThead = document.getElementById('dmMappingHead');
                const mappingTbody = document.getElementById('dmMappingBody');
                mappingThead.innerHTML = '';
                mappingTbody.innerHTML = '';
                
                // 添加映射表表头
                const mappingHeaderRow = document.createElement('tr');
                results.mapping.columns.forEach(col => {
                    const th = document.createElement('th');
                    th.textContent = col;
                    mappingHeaderRow.appendChild(th);
                });
                mappingThead.appendChild(mappingHeaderRow);
                
                // 添加映射表数据行
                results.mapping.data.forEach(row => {
                    const tr = document.createElement('tr');
                    results.mapping.columns.forEach(col => {
                        const td = document.createElement('td');
                        td.textContent = row[col];
                        tr.appendChild(td);
                    });
                    mappingTbody.appendChild(tr);
                });
            }
        }
        
