        initSidebarState();
        // 项目管理：初始化源文件清单（默认 1 条）
        try { ensureSourceFilesInit(); } catch (_) { }
        // 文件分析：口径默认 SQLite（可切换为 Excel 队列）
        try { faSetMode(localStorage.getItem('faMode') || 'sqlite'); } catch (_) { try { faSetMode('sqlite'); } catch (_) { } }

        // ========= 工作表解析页联动（统一 SQLite） =========
        function refreshWorksheetSelectForDb() {
            const select = document.getElementById('worksheetSelect');
            if (!select) return;
            // SQLite：工作表解析对应 SQLite 表（不再固定主表）
            select.innerHTML = '';
            const tables = Array.isArray(window.__sqliteTables) ? window.__sqliteTables : [];
            const list = tables.length ? tables : [window.__sqliteMainTableName || 'Main'];
            list.forEach(tn => {
                const opt = document.createElement('option');
                opt.value = tn;
                opt.textContent = `${tn}（SQLite表）`;
                select.appendChild(opt);
            });
            const prefer = window.__sqliteMainTableName || (list[0] || 'Main');
            select.value = list.includes(prefer) ? prefer : (list[0] || 'Main');
            window.__currentSheetName = select.value;
        }

        // 显示查询结果
        function showQueryResults(results) {
            const r0 = (results && results.result) ? results.result : results;
            let cols = (r0 && Array.isArray(r0.columns)) ? r0.columns : [];
            let rows = (r0 && Array.isArray(r0.rows)) ? r0.rows : [];
            let total = (r0 && r0.totalRows !== undefined) ? r0.totalRows : (Array.isArray(rows) ? rows.length : 0);
            let time = (r0 && r0.queryTime !== undefined) ? r0.queryTime : (r0 && r0.elapsed !== undefined ? r0.elapsed : '');

            // 兼容：宿主可能直接返回数组（List<Dictionary<string,object>> / DataTable 序列化）
            if ((!cols || !cols.length) && Array.isArray(r0)) {
                const arr = r0;
                if (arr.length && typeof arr[0] === 'object' && !Array.isArray(arr[0])) {
                    cols = Array.from(new Set(arr.flatMap(o => Object.keys(o || {}))));
                    rows = arr;
                    total = arr.length;
                }
            }
            // 兼容：rows 是二维数组，columns 单独给
            if (Array.isArray(cols) && cols.length && Array.isArray(rows) && rows.length && Array.isArray(rows[0])) {
                rows = rows.map(a => {
                    const o = {};
                    cols.forEach((c, i) => { o[c] = a[i]; });
                    return o;
                });
                total = rows.length;
            }
            // 兼容：data/items 字段
            if ((!rows || !rows.length) && r0 && Array.isArray(r0.data)) {
                rows = r0.data;
                total = r0.totalRows !== undefined ? r0.totalRows : rows.length;
                if ((!cols || !cols.length) && rows.length && typeof rows[0] === 'object') {
                    cols = Object.keys(rows[0]);
                }
            }
            if ((!rows || !rows.length) && r0 && Array.isArray(r0.items)) {
                rows = r0.items;
                total = r0.totalRows !== undefined ? r0.totalRows : rows.length;
                if ((!cols || !cols.length) && rows.length && typeof rows[0] === 'object') {
                    cols = Object.keys(rows[0]);
                }
            }

            function render(cardId, infoId, headId, bodyId, sqlText) {
                const card = document.getElementById(cardId);
                const info = document.getElementById(infoId);
                const head = document.getElementById(headId);
                const body = document.getElementById(bodyId);

                if (card) card.style.display = 'block';
                if (info) {
                    const sqlOneLine = (sqlText || '').replace(/\s+/g, ' ').trim();
                    const sqlShort = sqlOneLine.length > 160 ? (sqlOneLine.slice(0, 160) + '…') : sqlOneLine;
                    // 说明：SQL 文本已在“执行查询/预览SQL”步骤提供，结果区不再重复显示（避免过长占位）
                    const lim = Number(r0?.limit || 0);
                    const off = Number(r0?.offset || 0);
                    const previewNote = (lim > 0) ? `&nbsp;&nbsp;|&nbsp;&nbsp;<span style="color:#d46b08;"><strong>预览：</strong>LIMIT ${lim}${off > 0 ? ` OFFSET ${off}` : ''}</span>` : '';
                    info.innerHTML =
                        `<strong>返回行数：</strong>${Number(total || 0).toLocaleString()} 行`
                        + `&nbsp;&nbsp;|&nbsp;&nbsp;<strong>耗时：</strong>${time} 秒`
                        + previewNote;
                }

                if (head) {
                    head.innerHTML = '';
                    const tr = document.createElement('tr');
                    cols.forEach(c => {
                        const th = document.createElement('th');
                        th.textContent = c;
                        tr.appendChild(th);
                    });
                    head.appendChild(tr);
                }
                if (body) {
                    // 性能：分批渲染，避免 rows 很大时卡顿
                    try { window.__resultRenderToken = (window.__resultRenderToken || 0) + 1; } catch (_) { }
                    const token = window.__resultRenderToken || 0;
                    body.innerHTML = '';
                    let i = 0;
                    const batch = 80;
                    const renderChunk = () => {
                        try { if ((window.__resultRenderToken || 0) !== token) return; } catch (_) { }
                        const frag = document.createDocumentFragment();
                        for (let k = 0; k < batch && i < rows.length; k++, i++) {
                            const row = rows[i];
                            const tr = document.createElement('tr');
                            cols.forEach(c => {
                                const td = document.createElement('td');
                                td.textContent = (row && row[c] !== null && row[c] !== undefined) ? row[c] : '';
                                tr.appendChild(td);
                            });
                            frag.appendChild(tr);
                        }
                        body.appendChild(frag);
                        if (i < rows.length) (window.requestAnimationFrame || window.setTimeout)(renderChunk, 0);
                    };
                    (window.requestAnimationFrame || window.setTimeout)(renderChunk, 0);
                }
            }

            const target = window.__lastQueryTarget || 'stq';
            // 记录明细弹窗：detail:<id>
            if (String(target || '').startsWith('detail:')) {
                const id = String(target).slice('detail:'.length);
                try {
                    const info = document.getElementById(`${id}_info`);
                    const head = document.getElementById(`${id}_head`);
                    const body = document.getElementById(`${id}_body`);
                    if (info) {
                        info.innerHTML =
                            `<strong>返回行数：</strong>${Number(total || 0).toLocaleString()} 行`
                            + `&nbsp;&nbsp;|&nbsp;&nbsp;<strong>耗时：</strong>${time} 秒`;
                    }
                    if (head) {
                        head.innerHTML = '';
                        const tr = document.createElement('tr');
                        cols.forEach(c => { const th = document.createElement('th'); th.textContent = c; tr.appendChild(th); });
                        head.appendChild(tr);
                    }
                    if (body) {
                        body.innerHTML = '';
                        rows.forEach(row => {
                            const tr = document.createElement('tr');
                            cols.forEach(c => {
                                const td = document.createElement('td');
                                td.textContent = (row && row[c] !== null && row[c] !== undefined) ? row[c] : '';
                                tr.appendChild(td);
                            });
                            body.appendChild(tr);
                        });
                    }
                } catch (_) { }
                return;
            }

            // 数据清洗：预览表（Step3）
            if (target === 'dc-preview') {
                try {
                    const head = document.getElementById('dcPreviewHead');
                    const body = document.getElementById('dcPreviewBody');
                    if (head) {
                        head.innerHTML = '';
                        const tr = document.createElement('tr');
                        cols.forEach(c => { const th = document.createElement('th'); th.textContent = c; tr.appendChild(th); });
                        head.appendChild(tr);
                    }
                    if (body) {
                        body.innerHTML = '';
                        if (!rows.length) {
                            body.innerHTML = '<tr><td style="color:#6c757d;">（无数据）</td></tr>';
                        } else {
                            rows.forEach(row => {
                                const tr = document.createElement('tr');
                                cols.forEach(c => {
                                    const td = document.createElement('td');
                                    td.textContent = (row && row[c] !== null && row[c] !== undefined) ? row[c] : '';
                                    tr.appendChild(td);
                                });
                                body.appendChild(tr);
                            });
                        }
                    }
                } catch (_) { }
                return;
            }

            // SQL 搜索：主表/指定表/多表联合/全局联合
            if (target === 'search:mst') {
                showSqlSearchResults('mst', document.getElementById('mstKeyword')?.value || '', rows, total, time);
                return;
            }
            if (target === 'search:sst') {
                showSqlSearchResults('sst', document.getElementById('sstKeyword')?.value || '', rows, total, time);
                return;
            }
            if (target === 'search:mtjs') {
                showSqlSearchResults('mtjs', document.getElementById('mtjsKeyword')?.value || '', rows, total, time);
                return;
            }
            if (target === 'search:gus') {
                showSqlSearchResults('gus', document.getElementById('gusKeyword')?.value || '', rows, total, time);
                return;
            }
            if (target === 'mtq') {
                // 兼容旧逻辑：若仍有结果区则渲染；【多表关联】本身不再执行查询
                render('mtqResultCard', 'mtqResultInfo', 'mtqResultHead', 'mtqResultBody', '');
                return;
            }
            if (target === 'mtql') {
                render('mtqlResultCard', 'mtqlResultInfo', 'mtqlResultHead', 'mtqlResultBody', '');
                try {
                    const tab = document.getElementById('multi-table-query-lite');
                    if (tab && tab.style.display === 'block') {
                        for (let i = 1; i <= 3; i++) {
                            tab.querySelector(`[data-step="mtql${i}"]`)?.classList.remove('active');
                            tab.querySelector(`[data-step="mtql${i}"]`)?.classList.add('completed');
                            tab.querySelector(`#step-mtql${i}`)?.classList.remove('active');
                        }
                        window.__mtqlCurrentStep = 4;
                        tab.querySelector(`[data-step="mtql4"]`)?.classList.remove('completed');
                        tab.querySelector(`[data-step="mtql4"]`)?.classList.add('active');
                        tab.querySelector('#step-mtql4')?.classList.add('active');
                        try { updateMtqlBottomBar(); } catch (_) { }
                    }
                } catch (_) { }
                return;
            }
            if (target === 'mtsl') {
                render('mtslResultCard', 'mtslResultInfo', 'mtslResultHead', 'mtslResultBody', '');
                try {
                    const tab = document.getElementById('multi-table-stats-lite');
                    if (tab && tab.style.display === 'block') {
                        for (let i = 1; i <= 4; i++) {
                            tab.querySelector(`[data-step="mtsl${i}"]`)?.classList.remove('active');
                            tab.querySelector(`[data-step="mtsl${i}"]`)?.classList.add('completed');
                            tab.querySelector(`#step-mtsl${i}`)?.classList.remove('active');
                        }
                        window.__mtslCurrentStep = 5;
                        tab.querySelector(`[data-step="mtsl5"]`)?.classList.remove('completed');
                        tab.querySelector(`[data-step="mtsl5"]`)?.classList.add('active');
                        tab.querySelector('#step-mtsl5')?.classList.add('active');
                        try { updateMtslBottomBar(); } catch (_) { }
                    }
                } catch (_) { }
                return;
            }
            if (target === 'sts') {
                // 复用单表统计结果区
                showSingleTableStatsResults({ columns: cols, rows: rows, totalRows: total, queryTime: time });
                return;
            }
            if (target === 'mts') {
                // 渲染到多表统计结果区
                render('mtsResultCard', 'mtsResultInfo', 'mtsResultHead', 'mtsResultBody', window.__mtsSqlBase || '');
                return;
            }

            // SQL实验室：SQL编辑器/执行SQL
            if (target === 'sql-editor') {
                try {
                    // 结果信息
                    const info = document.getElementById('sqlEditorResultInfo');
                    const isNonQuery = (!cols.length && !rows.length);
                    // 事务状态（专家模式：非查询时可能存在未提交事务）
                    const txnOpen = !!(results && (results.txnOpen || results.transactionOpen));
                    window.__sqlLabTxnOpen = txnOpen;
                    const btnC = document.getElementById('sqlEditorCommitBtn');
                    const btnR = document.getElementById('sqlEditorRollbackBtn');
                    if (btnC) btnC.style.display = txnOpen ? 'inline-block' : 'none';
                    if (btnR) btnR.style.display = txnOpen ? 'inline-block' : 'none';
                    try { sqlLabArmTxnTimeout(); } catch (_) { }

                    if (info) {
                        if (isNonQuery) {
                            info.textContent = `影响 ${Number(total || 0).toLocaleString()} 行 | 耗时 ${time} 秒`;
                        } else {
                            // 远程分页预览：这里的 rows 是“本页”，total 未必可信（可能是 LIMIT 结果）
                            try {
                                sqlEditorInitResultState();
                                const st0 = window.__sqlEditorResultState;
                                if (st0.remoteMode) {
                                    info.textContent = `第 ${(st0.page || 1)} 页：本页 ${Number(rows.length || 0).toLocaleString()} 行 | 耗时 ${time} 秒`;
                                } else {
                                    info.textContent = `返回 ${Number(total || rows.length || 0).toLocaleString()} 行 | 耗时 ${time} 秒`;
                                }
                            } catch (_) {
                                info.textContent = `返回 ${Number(total || rows.length || 0).toLocaleString()} 行 | 耗时 ${time} 秒`;
                            }
                        }
                    }
                    // 保存结果用于分页/筛选渲染
                    sqlEditorInitResultState();
                    const st = window.__sqlEditorResultState;
                    st.cols = Array.isArray(cols) ? cols : [];
                    try { sqlEditorApplyColOrderToCols(); } catch (_) { }
                    st.rows = Array.isArray(rows) ? rows : [];
                    st.filtered = null;
                    // 远程分页：不强制回到第1页
                    if (!st.remoteMode) st.page = 1;
                    // 排序/过滤：默认清空（避免“上一轮筛选”导致看起来没数据）
                    st.sortKey = '';
                    st.sortDir = 'asc';
                    st.globalQuery = '';
                    st.colFilters = {};
                    // 同步 pageSize（来自下拉）
                    try { st.pageSize = Number(document.getElementById('sqlEditorPageSize')?.value || st.pageSize || 100); } catch (_) { }
                    // 非查询：用单行文本显示
                    if (isNonQuery) {
                        st.cols = ['执行结果'];
                        st.rows = [{ '执行结果': `已执行（影响 ${Number(total || 0).toLocaleString()} 行）` }];
                        st.remoteMode = false;
                    }
                    // 远程分页：判断是否还有下一页
                    if (st.remoteMode) {
                        const ps = st.pageSize || 100;
                        st.remoteHasMore = (Array.isArray(st.rows) ? st.rows.length : 0) >= ps;
                    }
                    sqlEditorRenderResultPage();
                    // UX：执行完成自动切到“结果”视图（避免用户看不到结果区）
                    try { if (!isNonQuery) setSqlEditorView('result'); } catch (_) { }
                    // 可选：统计总行数（用户勾选时才触发）
                    try {
                        if (st.remoteMode && st.remoteCountEnabled && (st.remoteTotalCount === null || st.remoteTotalCount === undefined)) {
                            setTimeout(() => { try { sqlEditorRequestCount(); } catch (_) { } }, 80);
                        }
                    } catch (_) { }
                } catch (_) { }
                return;
            }
            if (target === 'sql-generator') {
                render('sqlResultCard', 'sqlResultInfo', 'sqlResultHead', 'sqlResultBody', '');
                return;
            }

            // 默认：单表查询结果区
            render('queryResultCard', 'queryResultInfo', 'queryResultHead', 'queryResultBody', window.__stqSqlBase || '');

            // 单表查询：执行完成后自动进入“查看结果”(Step4)
            try {
                const stqTab = document.getElementById('single-table-query');
                if (stqTab && stqTab.style.display === 'block') gotoStqStep(4);
            } catch (_) { }
        }

        // 显示工作表分析结果
        function showWorksheetAnalysisResults(results) {
            if (!results) return;
            window.__lastWorksheetAnalysisResults = results;
            window.__wsFieldSelected = window.__wsFieldSelected || new Set();
            window.__wsFieldLastIndex = -1;
            try {
                const btn = document.getElementById('btnExportWorksheetAnalysisReport');
                if (btn) btn.disabled = false;
            } catch (_) { }

            // 显示区域
            const statsGrid = document.getElementById('worksheetStatsGrid');
            const fieldCard = document.getElementById('worksheetFieldCard');
            const qualityCard = document.getElementById('worksheetQualityCard');
            if (statsGrid) statsGrid.style.display = 'grid';
            if (fieldCard) fieldCard.style.display = 'block';
            if (qualityCard) qualityCard.style.display = 'block';

            const sheetName = results.sheetName || document.getElementById('worksheetSelect')?.value || '';
            const fields = Array.isArray(results.fields) ? results.fields : [];
            const preview = Array.isArray(results.preview) ? results.preview : [];

            // 统计区（部分字段当前后端未提供，用样本替代）
            const setText = (id, text) => {
                const el = document.getElementById(id);
                if (el) el.textContent = (text === undefined || text === null || text === '') ? '-' : String(text);
            };

            setText('wsStatFieldCount', fields.length);
            setText('wsStatRowCount', results.totalRows || (preview.length ? `${preview.length}（预览）` : '-'));
            setText('wsStatSize', results.size || '-');
            setText('wsStatCompleteness', (results.completeness !== undefined && results.completeness !== null) ? `${results.completeness}%` : '-');

            // 结果说明
            const infoEl = document.getElementById('worksheetResultInfo');
            if (infoEl) {
                infoEl.innerHTML = `<strong>工作表:</strong> ${sheetName || '-'}<br><strong>样本行:</strong> ${preview.length} 行`;
            }

            // 字段分析（基于样本预览）
            const tbody = document.getElementById('wsFieldAnalysisBody');
            if (tbody) {
                tbody.innerHTML = '';
                const getValues = (field) => preview.map(r => (r && Object.prototype.hasOwnProperty.call(r, field)) ? r[field] : null);
                const normalize = (v) => (v === null || v === undefined || v === '' ? null : v);

                const inferType = (vals) => {
                    const v = vals.find(x => x !== null && x !== undefined && x !== '');
                    if (v === undefined) return 'Text';
                    if (typeof v === 'number') return 'Number';
                    if (typeof v === 'boolean') return 'Boolean';
                    // 简单日期判断
                    const s = String(v);
                    if (!isNaN(Date.parse(s)) && s.length >= 8) return 'DateTime';
                    if (!isNaN(Number(s))) return 'Number';
                    return 'Text';
                };

                const calcMinMax = (vals, type) => {
                    const xs = vals.map(normalize).filter(x => x !== null);
                    if (xs.length === 0) return { min: '-', max: '-' };
                    if (type === 'Number') {
                        const ns = xs.map(x => Number(x)).filter(x => !isNaN(x));
                        if (ns.length === 0) return { min: '-', max: '-' };
                        return { min: Math.min(...ns), max: Math.max(...ns) };
                    }
                    if (type === 'DateTime') {
                        const ds = xs.map(x => Date.parse(String(x))).filter(x => !isNaN(x));
                        if (ds.length === 0) return { min: '-', max: '-' };
                        const minD = new Date(Math.min(...ds));
                        const maxD = new Date(Math.max(...ds));
                        return { min: minD.toISOString().slice(0, 10), max: maxD.toISOString().slice(0, 10) };
                    }
                    return { min: '-', max: '-' };
                };

                fields.forEach(field => {
                    const valsRaw = getValues(field);
                    const vals = valsRaw.map(normalize);
                    const nonNull = vals.filter(v => v !== null).length;
                    const uniq = new Set(vals.filter(v => v !== null).map(v => String(v))).size;
                    const sample = vals.find(v => v !== null);
                    const type = inferType(valsRaw);
                    const { min, max } = calcMinMax(valsRaw, type);

                    const tr = document.createElement('tr');
                    tr.dataset.fieldName = field;
                    tr.style.cursor = 'pointer';
                    tr.innerHTML = `
                        <td>${field}</td>
                        <td>${type}</td>
                        <td>${nonNull}</td>
                        <td>${uniq}</td>
                        <td>${min}</td>
                        <td>${max}</td>
                        <td>${sample === null || sample === undefined ? '' : String(sample).slice(0, 50)}</td>
                    `;
                    tr.addEventListener('click', (ev) => {
                        try { wsToggleFieldRowSelect(tr, ev); } catch (_) { }
                    });
                    tr.addEventListener('dblclick', (ev) => {
                        try { ev.stopPropagation(); xslqCopyToClipboard(field); setStatusMessage('字段名已复制'); } catch (_) { }
                    });
                    tbody.appendChild(tr);
                });
            }

            // 质量报告（基于样本：简单提示）
            const q = document.getElementById('wsQualityReport');
            if (q) {
                if (preview.length === 0 || fields.length === 0) {
                    q.innerHTML = '暂无报告（请先解析工作表）';
                } else {
                    const issues = [];
                    fields.forEach(f => {
                        const vals = preview.map(r => (r && Object.prototype.hasOwnProperty.call(r, f)) ? r[f] : null);
                        const nonNull = vals.filter(v => v !== null && v !== undefined && v !== '').length;
                        const rate = nonNull / preview.length;
                        if (rate < 0.5) issues.push(`字段「${f}」样本非空率偏低（${Math.round(rate * 100)}%）`);
                    });
                    q.innerHTML = issues.length
                        ? `<div style="color:#d46b08;">检测到 ${issues.length} 项潜在问题：</div><ul style="margin:8px 0 0 18px;">${issues.map(i => `<li>${i}</li>`).join('')}</ul>`
                        : `<div style="color:#52c41a;">样本数据未发现明显质量问题。</div>`;
                }
            }
            try { wsUpdateFieldToolbar(); } catch (_) { }
        }

        function wsUpdateFieldToolbar() {
            const n = (window.__wsFieldSelected && window.__wsFieldSelected.size) ? window.__wsFieldSelected.size : 0;
            const el = document.getElementById('wsFieldSelCount');
            if (el) el.textContent = `已选字段：${n}`;
            // 高亮
            document.querySelectorAll('#wsFieldAnalysisBody tr').forEach(tr => {
                const f = tr.dataset.fieldName || '';
                const on = window.__wsFieldSelected && window.__wsFieldSelected.has(f);
                tr.style.background = on ? '#e7f3ff' : '';
            });
        }

        function wsToggleFieldRowSelect(tr, ev) {
            const field = tr?.dataset?.fieldName;
            if (!field) return;
            const rows = Array.from(document.querySelectorAll('#wsFieldAnalysisBody tr'));
            const idx = rows.indexOf(tr);
            if (idx < 0) return;

            window.__wsFieldSelected = window.__wsFieldSelected || new Set();

            if (ev && ev.shiftKey && window.__wsFieldLastIndex >= 0) {
                const a = Math.min(window.__wsFieldLastIndex, idx);
                const b = Math.max(window.__wsFieldLastIndex, idx);
                for (let i = a; i <= b; i++) {
                    const f = rows[i]?.dataset?.fieldName;
                    if (f) window.__wsFieldSelected.add(f);
                }
            } else if (ev && (ev.ctrlKey || ev.metaKey)) {
                if (window.__wsFieldSelected.has(field)) window.__wsFieldSelected.delete(field);
                else window.__wsFieldSelected.add(field);
                window.__wsFieldLastIndex = idx;
            } else {
                // 单击：单选（再次单击同一行则取消）
                const onlyThis = (window.__wsFieldSelected.size === 1 && window.__wsFieldSelected.has(field));
                window.__wsFieldSelected.clear();
                if (!onlyThis) window.__wsFieldSelected.add(field);
                window.__wsFieldLastIndex = idx;
            }
            wsUpdateFieldToolbar();
        }

        function wsSelectAllFields() {
            window.__wsFieldSelected = window.__wsFieldSelected || new Set();
            window.__wsFieldSelected.clear();
            document.querySelectorAll('#wsFieldAnalysisBody tr').forEach(tr => {
                const f = tr.dataset.fieldName;
                if (f) window.__wsFieldSelected.add(f);
            });
            wsUpdateFieldToolbar();
        }

        function wsClearFieldSelection() {
            window.__wsFieldSelected = window.__wsFieldSelected || new Set();
            window.__wsFieldSelected.clear();
            window.__wsFieldLastIndex = -1;
            wsUpdateFieldToolbar();
        }

        function wsCopySelectedFields() {
            const set = window.__wsFieldSelected;
            const arr = set ? Array.from(set) : [];
            if (!arr.length) { alert('请先选择字段（单击/Shift 连选）'); return; }
            const text = arr.join('\n');
            try { xslqCopyToClipboard(text); setStatusMessage(`已复制 ${arr.length} 个字段名`); } catch (_) { }
        }

        // 显示元数据扫描结果
        function showMetadataScanResults(results) {
            const items = (results && results.items) ? results.items : (Array.isArray(results) ? results : []);
            document.getElementById('metadataResultCard').style.display = 'block';
            window.__lastMetadataScanResults = results || {};

            const info = document.getElementById('metadataResultInfo');
            if (info) {
                const canceled = !!results.canceled;
                const isSqlite = String(results.scope || '').toLowerCase() === 'sqlite';
                info.innerHTML = `
                    <strong>扫描范围：</strong>${(results && results.scopeLabel) ? results.scopeLabel : '—'}<br>
                    <strong>${isSqlite ? '对象数量' : '文件数量'}：</strong>${items.length.toLocaleString()} 个<br>
                    <strong>耗时：</strong>${(results && results.scanTime) ? results.scanTime : '—'} 秒
                    ${canceled ? `<br><span style="color:#d46b08;"><strong>状态：</strong>已取消（结果可能不完整）</span>` : ``}
                `;
            }

            // 顶部按钮联动
            try {
                const btn = document.getElementById('btnExportMetadataReport');
                if (btn) btn.disabled = items.length === 0;
                const b2 = document.getElementById('btnMetadataToRelationDetect');
                const isSqlite = String(results.scope || '').toLowerCase() === 'sqlite';
                if (b2) b2.style.display = isSqlite ? 'inline-block' : 'none';
                const b3 = document.getElementById('btnMetadataAddAllSources');
                const b4 = document.getElementById('btnMetadataAddAllImport');
                if (b3) b3.style.display = isSqlite ? 'none' : 'inline-block';
                if (b4) b4.style.display = isSqlite ? 'none' : 'inline-block';
                const optWrap = document.getElementById('metadataBatchOptions');
                if (optWrap) optWrap.style.display = isSqlite ? 'none' : 'flex';
                const title = document.getElementById('metadataListTitle');
                if (title) title.textContent = isSqlite ? '表/视图清单' : '文件清单';
            } catch (_) { }
            try { metadataBatchUiChanged(); } catch (_) { }

            const tbody = document.getElementById('metadataFileBody');
            tbody.innerHTML = '';

            items.forEach(it => {
                const tr = document.createElement('tr');
                const fp = (it.filePath || '').replace(/'/g, "\\'");
                const sheets = Array.isArray(it.sheets) ? it.sheets : [];
                const hasFields = sheets.some(s => s && Array.isArray(s.fields) && s.fields.length);
                tr.innerHTML = `
                    <td title="${(it.filePath || '').replace(/"/g, '&quot;')}">${it.fileName || ''}</td>
                    <td>${(it.sheetCount ?? 0).toLocaleString()}</td>
                    <td>${(it.totalRows ?? 0).toLocaleString()}</td>
                    <td>${it.fileSize || ''}</td>
                    <td>${it.lastModified || ''}</td>
                    <td>
                        <button class="btn btn-secondary" style="padding:2px 8px; margin-right:6px;" onclick="openMetadataSheetsModal('${fp}', ${JSON.stringify(sheets).replace(/</g,'\\u003c')})">${hasFields ? '工作表/字段' : '查看工作表'}</button>
                        <button class="btn btn-secondary" style="padding:2px 8px; margin-right:6px;" onclick="setMainFromMetadata('${fp}', ${JSON.stringify(sheets).replace(/</g,'\\u003c')})">设为主表</button>
                        <button class="btn btn-secondary" style="padding:2px 8px; margin-right:6px;" onclick="addSourceFileFromMetadata('${fp}', ${JSON.stringify(sheets).replace(/</g,'\\u003c')})">加入源文件清单</button>
                        <button class="btn btn-success" style="padding:2px 8px; margin-right:6px;" onclick="msAddAndImport('${fp}', ${JSON.stringify(sheets).replace(/</g,'\\u003c')})">加入并导入SQLite</button>
                        <button class="btn btn-secondary" style="padding:2px 8px;" onclick="addFileToAnalysisList('${fp}')">加入文件分析</button>
                    </td>
                `;
                tbody.appendChild(tr);
            });

            // 结束态：恢复按钮
            try {
                window.__metadataScanRunning = false;
                const b1 = document.getElementById('btnStartMetadataScan');
                const b2 = document.getElementById('btnCancelMetadataScan');
                const pb = document.getElementById('metadataScanProgressBarWrap');
                if (b1) b1.disabled = false;
                if (b2) b2.style.display = 'none';
                if (pb) pb.style.display = 'none';
            } catch (_) { }

            setStatusMessage('元数据扫描完成');
        }

        function buildMetadataScanReportHtml() {
            const now = new Date();
            const title = '元数据扫描报告';
            const results = window.__lastMetadataScanResults || {};
            const items = (results && results.items) ? results.items : [];
            const css = reportCss(`
                .summary{white-space:pre-wrap; font-size:9pt; line-height:1.5; border-left:4px solid #0d6efd; background:#e7f3ff; padding:10px 12px; border-radius:8px;}
                .small{font-size:8pt; color:#6c757d;}
            `);
            const isSqlite = String(results.scope || '').toLowerCase() === 'sqlite';
            const header = `
                <div class="sub">生成时间：${now.toLocaleString()}｜范围：${escapeHtml(results.scopeLabel || '')}</div>
                <div class="summary">${escapeHtml(`对象数量：${(items || []).length}\n耗时：${results.scanTime || '-'} 秒\n口径：${isSqlite ? '当前 SQLite 表/视图' : 'Excel 文件扫描'}`)}</div>`;
            const rows = (items || []).map(it => {
                const sheets = Array.isArray(it.sheets) ? it.sheets : [];
                const first = sheets[0] || {};
                const fields = Array.isArray(first.fields) ? first.fields : [];
                return {
                    name: it.fileName || '',
                    sheetCount: it.sheetCount ?? '',
                    totalRows: it.totalRows ?? '',
                    fieldCount: fields.length,
                    fileSize: it.fileSize || '',
                    lastModified: it.lastModified || ''
                };
            });
            const tableHtml = rows.length ? `
                <table>
                  <thead><tr><th>${isSqlite ? '对象名' : '文件名'}</th><th>工作表数</th><th>总行数</th><th>字段数（首表）</th><th>大小</th><th>修改时间</th></tr></thead>
                  <tbody>
                    ${rows.map(r => `<tr>${reportTd(r.name)}${reportTd(r.sheetCount)}${reportTd(r.totalRows)}${reportTd(r.fieldCount)}${reportTd(r.fileSize)}${reportTd(r.lastModified)}</tr>`).join('')}
                  </tbody>
                </table>` : `<div class="small">（无数据）</div>`;
            return `<!doctype html><html><head><meta charset="utf-8"><title>${title}</title><style>${css}</style></head>
                <body>
                  <h1>${title}</h1>
                  ${header}
                  <h2>${isSqlite ? '表/视图清单' : '文件清单'}</h2>
                  ${tableHtml}
                </body></html>`;
        }

        function exportMetadataScanReport() {
            try {
                const html = buildMetadataScanReportHtml();
                const ts = new Date();
                const fileName = `metadata-scan-report-${ts.getFullYear()}${String(ts.getMonth()+1).padStart(2,'0')}${String(ts.getDate()).padStart(2,'0')}-${String(ts.getHours()).padStart(2,'0')}${String(ts.getMinutes()).padStart(2,'0')}${String(ts.getSeconds()).padStart(2,'0')}.html`;
                window.chrome.webview.postMessage({ action: 'saveHtmlReport', reportName: 'metadata-scan', title: '元数据扫描报告', fileName, html, openAfterSave: true });
            } catch (e) {
                alert('导出失败：' + (e?.message || e));
            }
        }

        function metadataGotoRelationDetect() {
            const results = window.__lastMetadataScanResults || {};
            const isSqlite = String(results.scope || '').toLowerCase() === 'sqlite';
            if (!isSqlite) { alert('该功能仅适用于“当前SQLite”扫描结果'); return; }
            const items = Array.isArray(results.items) ? results.items : [];
            const tables = items.map(x => String(x.fileName || '').trim()).filter(Boolean);
            if (!tables.length) { alert('未获取到表清单'); return; }
            try { switchTab('relation-check'); } catch (_) { }
            try { const sel2 = document.getElementById('relMainTable'); if (sel2 && tables[0]) sel2.value = tables[0]; } catch (_) { }
            try {
                const sel = document.getElementById('relTables');
                if (sel) Array.from(sel.options).forEach(o => { o.selected = tables.includes(o.value); });
            } catch (_) { }
            try { setStatusMessage('已从元数据扫描联动：请直接点击“开始识别”'); } catch (_) { }
        }

        // 元数据扫描：查看工作表明细（简易弹窗）
        function openMetadataSheetsModal(filePath, sheets) {
            const arr = Array.isArray(sheets) ? sheets : [];
            const title = `工作表清单：${(filePath || '').split('/').pop().split('\\\\').pop()}`;

            const modal = document.createElement('div');
            modal.className = 'modal';
            modal.style.cssText = 'position: fixed; inset: 0; background: rgba(0,0,0,0.45); display:flex; align-items:center; justify-content:center; z-index: 2100;';
            modal.onclick = (e) => { if (e.target === modal) modal.remove(); };

            const rowsHtml = arr.length ? arr.map(s => {
                const name = (s && (s.name || s.sheetName)) ? (s.name || s.sheetName) : String(s || '');
                const rc = (s && s.rowCount !== undefined) ? s.rowCount : '';
                const cc = (s && s.colCount !== undefined) ? s.colCount : '';
                const fields = (s && Array.isArray(s.fields)) ? s.fields : [];
                const fc = fields.length;
                return `<tr>
                    <td>${escapeHtml(name)}</td>
                    <td>${escapeHtml(String(rc))}</td>
                    <td>${escapeHtml(String(cc))}</td>
                    <td style="white-space:nowrap;">
                        <button class="btn btn-secondary" style="padding:2px 8px;" onclick='openMetadataFieldsModal(${JSON.stringify(name)}, ${JSON.stringify(filePath || "")}, ${JSON.stringify(fields).replace(/</g,"\\\\u003c")})'>查看字段${fc ? `（${fc}）` : ''}</button>
                    </td>
                </tr>`;
            }).join('') : `<tr><td colspan="4" style="text-align:center; color:#6c757d;">未获取到工作表信息</td></tr>`;

            modal.innerHTML = `
                <div style="background:#fff; border-radius:10px; width: 92vw; max-width: 900px; max-height: 86vh; overflow:hidden; box-shadow:0 10px 30px rgba(0,0,0,0.18);">
                    <div style="display:flex; align-items:center; gap:10px; padding:10px 12px; border-bottom:1px solid #eee;">
                        <div style="font-weight:bold; flex:1;">${escapeHtml(title)}</div>
                        <button class="btn btn-secondary" style="padding:2px 10px;" onclick="this.closest('.modal').remove()">关闭</button>
                    </div>
                    <div style="padding:12px;">
                        <div style="font-size:9pt; color:#6c757d; margin-bottom:8px;">提示：点击“查看字段”将获取字段清单并弹窗展示。</div>
                        <div style="max-height: 60vh; overflow:auto; border:1px solid #eee; border-radius:6px;">
                            <table class="table table-head-dark" style="margin:0;">
                                <thead><tr><th>工作表名</th><th>行数</th><th>列数</th><th>操作</th></tr></thead>
                                <tbody>${rowsHtml}</tbody>
                            </table>
                        </div>
                    </div>
                </div>
            `;
            document.body.appendChild(modal);
        }

        // 元数据扫描：查看字段（直接用扫描结果中的 fields；不依赖 SQLite）
        function openMetadataFieldsModal(sheetName, filePath, fields) {
            const list = Array.isArray(fields) ? fields : [];
            const title = `字段清单：${sheetName}`;
            const modal = document.createElement('div');
            modal.className = 'modal';
            modal.style.cssText = 'position: fixed; inset: 0; background: rgba(0,0,0,0.45); display:flex; align-items:center; justify-content:center; z-index: 2200;';
            modal.onclick = (e) => { if (e.target === modal) modal.remove(); };
            const isObj = list.length && typeof list[0] === 'object' && list[0] !== null;
            const renderObj = () => {
                const rows = list.map(x => ({
                    name: x.name || x.column || x.field || '',
                    type: x.type || x.dataType || '',
                    nonNullRate: (x.nonNullRate !== undefined && x.nonNullRate !== null) ? `${x.nonNullRate}%` : '',
                    distinct: (x.sampleDistinct !== undefined && x.sampleDistinct !== null) ? x.sampleDistinct : '',
                    sample: (x.sampleValue !== undefined && x.sampleValue !== null) ? String(x.sampleValue).slice(0, 80) : ''
                }));
                return `
                    <div style="max-height: 65vh; overflow:auto; border:1px solid #eee; border-radius:6px;">
                        <table class="table table-head-dark" style="margin:0;">
                            <thead><tr><th>字段</th><th>类型</th><th>样本非空率</th><th>样本唯一值</th><th>示例</th></tr></thead>
                            <tbody>
                                ${rows.map(r => `<tr>${reportTd(r.name)}${reportTd(r.type)}${reportTd(r.nonNullRate)}${reportTd(r.distinct)}${reportTd(r.sample)}</tr>`).join('')}
                            </tbody>
                        </table>
                    </div>`;
            };
            modal.innerHTML = `
                <div style="background:#fff; border-radius:10px; width: 92vw; max-width: 900px; max-height: 86vh; overflow:hidden; box-shadow:0 10px 30px rgba(0,0,0,0.18);">
                    <div style="display:flex; align-items:center; gap:10px; padding:10px 12px; border-bottom:1px solid #eee;">
                        <div style="font-weight:bold; flex:1;">${escapeHtml(title)}</div>
                        <button class="btn btn-secondary" style="padding:2px 10px;" onclick="this.closest('.modal').remove()">关闭</button>
                    </div>
                    <div style="padding:12px;">
                        ${list.length
                            ? (isObj
                                ? renderObj()
                                : `<div style="display:flex;flex-wrap:wrap;gap:8px;">${list.map(f => `<span style="background:#f5f5f5;border:1px solid #eee;border-radius:12px;padding:4px 10px;font-size:12px;">${escapeHtml(String(f))}</span>`).join('')}</div>`)
                            : `<div style="color:#6c757d;">（未包含字段信息。可重新扫描；或在【项目管理】导入后用“查看字段”查看 SQLite 字段。）</div>`
                        }
                    </div>
                </div>
            `;
            document.body.appendChild(modal);
        }

        // 元数据扫描：一键加入源文件并启动导入
        function msAddAndImport(filePath, sheets) {
            try {
                addSourceFileFromMetadata(filePath, sheets);
                // 若还没设主表：设为第一张表
                if (!window.__fileWizardMain) {
                    const ws = (Array.isArray(sheets) ? sheets : []).map(s => s.name || s.sheetName || s).filter(Boolean);
                    if (ws.length) window.__fileWizardMain = { sourceId: (window.__sourceFiles || []).slice(-1)[0]?.id, filePath: filePath, sheetName: ws[0] };
                }
                switchTab('file-wizard');
                setTimeout(() => { try { loadToSqlite(); } catch (_) { } }, 150);
            } catch (e) {
                alert('执行失败：' + (e && e.message ? e.message : e));
            }
        }

        // 元数据扫描：一键加入“源文件清单”（支持携带工作表列表）
        function addSourceFileFromMetadata(filePath, sheets) {
            try {
                const id = 'src_' + Date.now() + '_' + Math.floor(Math.random() * 1000);
                const ws = (Array.isArray(sheets) ? sheets : []).map(s => s.name || s.sheetName || s).filter(Boolean);
                window.__sourceFiles = window.__sourceFiles || [];
                window.__sourceFiles.push({ id, filePath: (filePath || '').replace(/\\\\/g, '/'), worksheets: ws, selected: ws.length ? [ws[0]] : [], mainSheet: ws.length ? ws[0] : '' });
                // 若还未设置主表，则把该文件第一张表设为主表
                if (!window.__fileWizardMain && ws.length) {
                    window.__fileWizardMain = { sourceId: id, filePath: (filePath || '').replace(/\\\\/g, '/'), sheetName: ws[0] };
                }
                renderSourceFiles();
                refreshSqliteMainTableSelect();
                syncMainTableUiAndHost();
                alert('已加入到【项目管理】页的源文件清单。');
            } catch (e) {
                alert('加入失败：' + (e && e.message ? e.message : e));
            }
        }

        function metadataBatchUiChanged() {
            try {
                const sr = document.getElementById('msBatchSheetRule')?.value || 'first';
                const sw = document.getElementById('msBatchSheetKeywordWrap');
                if (sw) sw.style.display = (sr === 'keyword') ? 'block' : 'none';
                const mr = document.getElementById('msBatchMainRule')?.value || 'first';
                const mw = document.getElementById('msBatchMainKeywordWrap');
                if (mw) mw.style.display = (mr === 'file_keyword' || mr === 'sheet_keyword') ? 'block' : 'none';
            } catch (_) { }
        }

        function metadataGetBatchOptions() {
            const sheetRule = document.getElementById('msBatchSheetRule')?.value || 'first';
            const sheetKeyword = (document.getElementById('msBatchSheetKeyword')?.value || '').trim();
            const mainRule = document.getElementById('msBatchMainRule')?.value || 'first';
            const mainKeyword = (document.getElementById('msBatchMainKeyword')?.value || '').trim();
            return { sheetRule, sheetKeyword, mainRule, mainKeyword };
        }

        function metadataPickSelectedSheets(allWs, opt) {
            const ws = Array.isArray(allWs) ? allWs.filter(Boolean) : [];
            if (!ws.length) return [];
            const rule = opt?.sheetRule || 'first';
            if (rule === 'all') return ws.slice();
            if (rule === 'keyword') {
                const kw = String(opt?.sheetKeyword || '').trim().toLowerCase();
                if (!kw) return [ws[0]];
                const hit = ws.filter(x => String(x).toLowerCase().includes(kw));
                return hit.length ? hit : [ws[0]];
            }
            return [ws[0]];
        }

        function addSourceFileFromMetadataIfNotExists(filePath, sheets, opt) {
            try {
                const fp = (filePath || '').replace(/\\\\/g, '/');
                window.__sourceFiles = window.__sourceFiles || [];
                const existed = window.__sourceFiles.find(x => String(x?.filePath || '') === fp);
                const ws = (Array.isArray(sheets) ? sheets : []).map(s => s.name || s.sheetName || s).filter(Boolean);
                const selected = metadataPickSelectedSheets(ws, opt);
                if (existed) {
                    // 尽量补齐工作表列表（不强行覆盖用户已有选择）
                    try { if (Array.isArray(ws) && ws.length) existed.worksheets = Array.from(new Set([...(existed.worksheets || []), ...ws])); } catch (_) { }
                    try { if ((!existed.selected || !existed.selected.length) && selected.length) existed.selected = selected.slice(); } catch (_) { }
                    try { if ((!existed.mainSheet) && selected.length) existed.mainSheet = selected[0]; } catch (_) { }
                    return existed.id;
                }
                const id = 'src_' + Date.now() + '_' + Math.floor(Math.random() * 1000);
                window.__sourceFiles.push({ id, filePath: fp, worksheets: ws, selected: selected, mainSheet: selected.length ? selected[0] : '' });
                return id;
            } catch (_) { return null; }
        }

        function metadataAddAllToSources() {
            try {
                const results = window.__lastMetadataScanResults || {};
                const items = Array.isArray(results.items) ? results.items : [];
                if (!items.length) { alert('暂无扫描结果'); return; }
                // 仅文件扫描才有意义
                const isSqlite = String(results.scope || '').toLowerCase() === 'sqlite';
                if (isSqlite) { alert('当前为“SQLite扫描结果”，无需加入源文件'); return; }

                try { ensureSourceFilesInit(); } catch (_) { }
                const opt = metadataGetBatchOptions();
                let added = 0;
                items.forEach(it => {
                    const fp = it.filePath || '';
                    const sheets = Array.isArray(it.sheets) ? it.sheets : [];
                    const before = (window.__sourceFiles || []).length;
                    addSourceFileFromMetadataIfNotExists(fp, sheets, opt);
                    const after = (window.__sourceFiles || []).length;
                    if (after > before) added++;
                });

                // 主表策略：尽量按照关键字命中，否则兜底第一文件第一张
                try {
                    const mainRule = opt?.mainRule || 'first';
                    const mainKw = String(opt?.mainKeyword || '').trim().toLowerCase();
                    let mainSrc = null;
                    let mainSheet = '';
                    const srcs = Array.isArray(window.__sourceFiles) ? window.__sourceFiles : [];
                    if (mainRule === 'file_keyword' && mainKw) {
                        mainSrc = srcs.find(s => String(s?.filePath || '').toLowerCase().includes(mainKw));
                        mainSheet = mainSrc?.selected?.[0] || mainSrc?.mainSheet || '';
                    } else if (mainRule === 'sheet_keyword' && mainKw) {
                        mainSrc = srcs.find(s => (Array.isArray(s?.worksheets) ? s.worksheets : []).some(w => String(w).toLowerCase().includes(mainKw)));
                        if (mainSrc) {
                            const hit = (Array.isArray(mainSrc.worksheets) ? mainSrc.worksheets : []).find(w => String(w).toLowerCase().includes(mainKw));
                            mainSheet = hit || mainSrc?.selected?.[0] || mainSrc?.mainSheet || '';
                        }
                    }
                    if (!mainSrc) {
                        // 兜底：按扫描结果顺序取第一个
                        const fp0 = (items[0].filePath || '').replace(/\\\\/g, '/');
                        mainSrc = srcs.find(s => String(s?.filePath || '') === fp0) || srcs[0] || null;
                        mainSheet = mainSrc?.selected?.[0] || mainSrc?.mainSheet || '';
                    }
                    if (mainSrc && mainSheet) {
                        window.__fileWizardMain = { sourceId: mainSrc.id, filePath: mainSrc.filePath, sheetName: mainSheet };
                    }
                } catch (_) { }

                try { renderSourceFiles(); refreshSqliteMainTableSelect(); syncMainTableUiAndHost(); } catch (_) { }
                alert(`已加入源文件清单：新增 ${added} 个（重复的自动跳过）`);
                try { switchTab('file-wizard'); } catch (_) { }
            } catch (e) {
                alert('操作失败：' + (e?.message || e));
            }
        }

        function metadataAddAllAndImport() {
            try {
                const results = window.__lastMetadataScanResults || {};
                const items = Array.isArray(results.items) ? results.items : [];
                if (!items.length) { alert('暂无扫描结果'); return; }
                const isSqlite = String(results.scope || '').toLowerCase() === 'sqlite';
                if (isSqlite) { alert('当前为“SQLite扫描结果”，无需导入'); return; }
                if (!confirm(`将把扫描结果中的 ${items.length} 个文件加入源文件清单，并开始导入 SQLite。\n\n提示：若你希望只导入部分文件，请先用“加入全部源文件”，再在项目管理页手动删减后导入。`)) return;
                metadataAddAllToSources();
                try { switchTab('file-wizard'); } catch (_) { }
                setTimeout(() => { try { loadToSqlite(); } catch (_) { } }, 120);
            } catch (e) {
                alert('操作失败：' + (e?.message || e));
            }
        }

        function setMainFromMetadata(filePath, sheets) {
            try {
                const arr = Array.isArray(sheets) ? sheets : [];
                const ws = arr.map(s => s.name || s.sheetName || s).filter(Boolean);
                if (!ws.length) { alert('未获取到工作表列表，无法设置主表'); return; }
                // 确保已加入源文件清单
                addSourceFileFromMetadata(filePath, sheets);
                // 把最后一个加入的设为主表
                const last = (window.__sourceFiles || []).slice(-1)[0];
                if (last) {
                    window.__fileWizardMain = { sourceId: last.id, filePath: last.filePath, sheetName: ws[0] };
                    renderSourceFiles();
                    refreshSqliteMainTableSelect();
                    syncMainTableUiAndHost();
                }
                switchTab('file-wizard');
                alert('已设为主表（请在【项目管理】页检查后点击“保存设置/导入”）。');
            } catch (e) {
                alert('设置失败：' + (e && e.message ? e.message : e));
            }
        }

        // 加载表列表
        function loadTableList(tables) {
            const baseTables = Array.isArray(tables) ? tables : [];
            const mode = (window.__outputMode || 'raw');
            // 视图支持：若宿主返回了 dbObjects（table/view），则下拉优先用它，避免只能选“表不能选视图”
            let list = baseTables.slice();
            try {
                const objs = Array.isArray(window.__dbmObjects) ? window.__dbmObjects : [];
                const names = objs
                    .map(x => String(x.name || x.Name || '').trim())
                    .filter(Boolean);
                if (names.length) {
                    // 保留顺序：先表后视图（按 sqlite_master 默认排序）
                    list = Array.from(new Set([...names]));
                }
            } catch (_) { }
            // 既要保留“全量”，又要给 UI 下拉“按输出模式过滤”的视图
            window.__sqliteTables = baseTables.slice(); // 全量表
            window.__sqliteObjects = list.slice();      // 全量表+视图
            const listShown = (mode === 'masked')
                ? list.filter(t => String(t).toLowerCase().endsWith('_masked'))
                : list.slice();
            // 用“源文件清单里的显示名”构建别名对照（用于所有下拉显示）
            try { window.__tableAliasLookup = buildTableAliasLookup(); } catch (_) { window.__tableAliasLookup = {}; }
            // 关键：项目库已存在表时，应视为“SQLite已导入”，否则很多模块会一直提示“未导入”
            window.__sqliteReady = baseTables.length > 0;
            try { setSqliteStatus(list.length ? `已导入（${list.length}表）` : '未导入'); } catch (_) { }
            try { setStatusCurrentMainTable(window.__sqliteMainTableName || (listShown[0] || list[0] || '-') || '-'); } catch (_) { }
            try { dcRefreshSourceTableSelect(); } catch (_) { }

            // 刷新“选定主表”下拉
            try { refreshSqliteMainTableSelect(); } catch (_) { }

            const fill = (select, selectedValue) => {
                if (!select) return;
                const prev = selectedValue || select.value;
                select.innerHTML = '<option value="">选择表/视图</option>';
                listShown.forEach(t => {
                    const opt = document.createElement('option');
                    opt.value = t;
                    opt.textContent = getTableAliasName(t) || t;
                    opt.title = t;
                    select.appendChild(opt);
                });
                if (prev && listShown.includes(prev)) select.value = prev;
            };
            const isJoinTypeSelect = (sel) => {
                try { return Array.from(sel.options || []).some(o => /join/i.test(o.textContent || '')); } catch (_) { return false; }
            };

            // 多表查询/统计/分拆：主表选择
            fill(document.getElementById('mtqMainTable'));
            fill(document.getElementById('mtsMainTable'));
            fill(document.getElementById('mtsptMainTable'));
            // 单表分拆：表/视图选择
            fill(document.getElementById('stsptSourceObject'));
            // 关联关系识别：主表候选
            fill(document.getElementById('relMainTable'), window.__sqliteMainTableName || '');
            // 关联关系识别：多选表（默认全选）
            try {
                const sel = document.getElementById('relTables');
                if (sel) {
                    sel.innerHTML = '';
                    listShown.forEach(t => {
                        const opt = document.createElement('option');
                        opt.value = t;
                        opt.textContent = getTableAliasName(t) || t;
                        opt.title = t;
                        opt.selected = true;
                        sel.appendChild(opt);
                    });
                }
            } catch (_) { }
            // 指定表搜索：表选择
            fill(document.getElementById('sstTable'));
            // 单表切换：单表查询/单表统计
            fill(document.getElementById('stqTableSelect'), window.__singleTableSelectedName || window.__sqliteMainTableName || '');
            fill(document.getElementById('stsTableSelect'), window.__singleTableSelectedName || window.__sqliteMainTableName || '');
            // 差异比对：清洗后表选择
            fill(document.getElementById('compareAfterTable'));

            // 动态添加的关联表下拉：填充所有 join rows 中的“选择关联表”下拉（不含主表那行）
            document.querySelectorAll('#mtqJoinTables .join-table-row select').forEach(sel => {
                if (sel.id === 'mtqMainTable') return;
                if (isJoinTypeSelect(sel)) return; // 避免把表列表灌进 JOIN 类型下拉
                fill(sel);
            });
            document.querySelectorAll('#mtsJoinTables .join-table-row select').forEach(sel => {
                if (sel.id === 'mtsMainTable') return;
                if (isJoinTypeSelect(sel)) return;
                fill(sel);
            });
            document.querySelectorAll('#mtsptJoinTables .join-table-row select').forEach(sel => {
                if (sel.id === 'mtsptMainTable') return;
                if (isJoinTypeSelect(sel)) return;
                fill(sel);
            });

            // 多表查询：刷新别名对照/Join 设计器
            try { mtqOnTablesChanged(); } catch (_) { }
            try { updateMtsDataSourceLabel(); } catch (_) { }
            try { refreshSearchDataSources(); } catch (_) { }
            // SQL编辑器：刷新右侧表结构树
            try { refreshSqlEditorSchemaPanel(); } catch (_) { }

            setStatusMessage(`SQLite 表列表已刷新：${listShown.length} 张表（输出模式：${mode === 'masked' ? 'Masked' : 'Raw'}）`);
            try { updateAllTablePickers(); } catch (_) { }
            // 工作表分析：下拉框应展示 SQLite 表列表
            try { refreshWorksheetSelectForDb(); } catch (_) { }
        }

        function refreshSqliteMainTableSelect() {
            const sel = document.getElementById('sqliteMainTableSelect');
            if (!sel) return;
            const tables = Array.isArray(window.__sqliteTables) ? window.__sqliteTables : [];
            // 构建别名对照
            try { window.__tableAliasLookup = buildTableAliasLookup(); } catch (_) { window.__tableAliasLookup = {}; }
            // 允许“未导入前”也能选定主表：从源文件清单构造候选（源文件名|工作表名）
            const pending = [];
            try {
                (window.__sourceFiles || []).forEach(sf => {
                    const fp = sf.filePath || '';
                    (Array.isArray(sf.worksheets) ? sf.worksheets : []).forEach(ws => {
                        if (fp && ws) {
                            const physical = getCustomTableName(sf.id, ws) || mkSqliteTableNameFromFileSheet(fp, ws);
                            pending.push(physical);
                        }
                    });
                });
            } catch (_) { }
            const all = Array.from(new Set([...(tables || []), ...pending]));
            const cur = window.__sqliteMainTableName || '';
            sel.innerHTML = '';
            if (!all.length) {
                const opt = document.createElement('option');
                opt.value = '';
                opt.textContent = '（尚未导入）';
                sel.appendChild(opt);
                sel.value = '';
                return;
            }
            all.forEach(t => {
                const opt = document.createElement('option');
                opt.value = t;
                opt.textContent = getTableAliasName(t) || t;
                opt.title = t;
                sel.appendChild(opt);
            });
            // 默认选当前主表；若为空则选第一个并设为主表
            if (cur && all.includes(cur)) sel.value = cur;
            else {
                sel.value = all[0];
                // 初始化时同步设主表（不提示）
                if (!window.__sqliteMainTableName) {
                    window.__sqliteMainTableName = all[0];
                    // 仅当该表已存在于 SQLite 时才通知宿主（避免“表不存在”的误报）
                    try { if (tables.includes(all[0])) postSetMainTable(all[0], false); } catch (_) { }
                }
            }
        }

        function postSetMainTable(tableName, showToast) {
            if (!tableName) return;
            if (!window.chrome || !window.chrome.webview || !window.chrome.webview.postMessage) return;
            window.chrome.webview.postMessage({ action: 'setMainTable', tableName: tableName });
            if (showToast) setStatusMessage(`已切换主表：${tableName}`);
        }

        function onSqliteMainTableChanged() {
            const sel = document.getElementById('sqliteMainTableSelect');
            const tableName = sel ? sel.value : '';
            if (!tableName) return;
            window.__sqliteMainTableName = tableName;
            try { setStatusCurrentMainTable(tableName); } catch (_) { }
            if (!window.__singleTableSelectedName) window.__singleTableSelectedName = tableName;
            const tables = Array.isArray(window.__sqliteTables) ? window.__sqliteTables : [];

            // 1) 若该表已经在 SQLite 内存库中：立即切换主表（不重新导入）
            if (tables.includes(tableName)) {
                try { postSetMainTable(tableName, true); } catch (_) { }
                try { refreshWorksheetSelectForDb(); } catch (_) { }
                try { requestActiveFields(); } catch (_) { }
                try { stsRequestSchemaAndBuild(); } catch (_) { }
                return;
            }

            // 2) 若尚未导入：将其作为“导入时的主表”预选（不发给宿主）
            // 这里 tableName 可能是默认“文件|工作表”，也可能是用户自定义物理表名
            try {
                const hit = (window.__sourceFiles || []).flatMap(sf => {
                    const fp = sf.filePath || '';
                    const ws = Array.isArray(sf.worksheets) ? sf.worksheets : [];
                    return ws.map(w => ({
                        sourceId: sf.id,
                        sheet: w,
                        physical: getCustomTableName(sf.id, w) || mkSqliteTableNameFromFileSheet(fp, w)
                    }));
                }).find(x => x.physical === tableName);
                if (hit) setMainWorksheet(hit.sourceId, hit.sheet);
            } catch (_) { }
        }
        
        // ========= 项目管理：源文件清单（多文件 + 多工作表 + 选定主表） =========
        window.__sourceFiles = window.__sourceFiles || []; // [{id,filePath,worksheets:[],selected:Set, mainSheet:''}]
        window.__pendingWorksheetTargetId = window.__pendingWorksheetTargetId || null; // 当前等待 worksheetListLoaded 的 sourceId
        window.__importWriteMode = window.__importWriteMode || 'overwrite';

        function mkSqliteTableNameFromFileSheet(filePath, sheetName) {
            const base = (filePath || '').split('\\').pop().split('/').pop().replace(/\.[^.]+$/, '');
            return `${base}|${sheetName}`;
        }

        function getCustomTableName(sourceId, sheetName) {
            const sf = (window.__sourceFiles || []).find(x => x.id === sourceId);
            if (!sf) return '';
            const map = sf.tableNameMap || {};
            return (map && sheetName && map[sheetName]) ? String(map[sheetName]) : '';
        }

        function setCustomTableName(sourceId, sheetName, tableName) {
            const sf = (window.__sourceFiles || []).find(x => x.id === sourceId);
            if (!sf) return;
            sf.tableNameMap = sf.tableNameMap || {};
            sf.tableAliasMap = sf.tableAliasMap || {};
            const old = sf.tableNameMap[sheetName] || mkSqliteTableNameFromFileSheet(sf.filePath, sheetName);
            const oldAlias = sf.tableAliasMap[sheetName] || '';
            const v = String(tableName || '').trim();
            if (!v) delete sf.tableNameMap[sheetName];
            else sf.tableNameMap[sheetName] = v;
            // 若显示名仍等于旧物理名（或为空），则跟随新物理名自动更新（避免“表名改了但显示名没跟上”）
            try {
                if (!oldAlias || oldAlias === old) {
                    sf.tableAliasMap[sheetName] = v || old;
                }
            } catch (_) { }
            // 若正在编辑的是主表，联动 sqliteMainTableName（仅当尚未导入或表名不存在时）
            try {
                if (window.__fileWizardMain && window.__fileWizardMain.sourceId === sourceId && window.__fileWizardMain.sheetName === sheetName) {
                    window.__sqliteMainTableName = v || mkSqliteTableNameFromFileSheet(sf.filePath, sheetName);
                    refreshSqliteMainTableSelect();
                }
            } catch (_) { }
        }

        // 物理表名被“数据库对象管理”重命名后：同步项目管理的映射（tableNameMap/sqliteMainTableName/显示名跟随）
        function fwApplyPhysicalRenameToMappings(oldName, newName) {
            const o = String(oldName || '').trim();
            const n = String(newName || '').trim();
            if (!o || !n || o === n) return;
            try {
                (window.__sourceFiles || []).forEach(sf => {
                    sf.tableNameMap = sf.tableNameMap || {};
                    sf.tableAliasMap = sf.tableAliasMap || {};
                    Object.keys(sf.tableNameMap).forEach(sh => {
                        if (String(sf.tableNameMap[sh] || '') === o) {
                            sf.tableNameMap[sh] = n;
                            // 若显示名原本等于旧物理名，则跟随更新（避免显示名滞后）
                            try {
                                if (!sf.tableAliasMap[sh] || String(sf.tableAliasMap[sh]) === o) sf.tableAliasMap[sh] = n;
                            } catch (_) { }
                        }
                    });
                });
            } catch (_) { }
            try {
                if (String(window.__sqliteMainTableName || '') === o) window.__sqliteMainTableName = n;
            } catch (_) { }
            try { window.__tableAliasLookup = buildTableAliasLookup(); } catch (_) { }
            try { refreshSqliteMainTableSelect(); } catch (_) { }
            try { updateAllTablePickers(); } catch (_) { }
            try { renderSourceFiles(); } catch (_) { }
        }

        function getCustomTableAlias(sourceId, sheetName) {
            const sf = (window.__sourceFiles || []).find(x => x.id === sourceId);
            if (!sf) return '';
            const map = sf.tableAliasMap || {};
            return (map && sheetName && map[sheetName]) ? String(map[sheetName]) : '';
        }

        function setCustomTableAlias(sourceId, sheetName, alias) {
            const sf = (window.__sourceFiles || []).find(x => x.id === sourceId);
            if (!sf) return;
            sf.tableAliasMap = sf.tableAliasMap || {};
            const v = String(alias || '').trim();
            if (!v) delete sf.tableAliasMap[sheetName];
            else sf.tableAliasMap[sheetName] = v;
            // 仅刷新 UI，不影响物理表名（不破坏关联/视图/模板）
            try { refreshSqliteMainTableSelect(); } catch (_) { }
        }

        function buildTableAliasLookup() {
            const map = {};
            try {
                (window.__sourceFiles || []).forEach(sf => {
                    const fp = sf.filePath || '';
                    const wsList = Array.isArray(sf.worksheets) ? sf.worksheets : [];
                    wsList.forEach(ws => {
                        if (!ws) return;
                        const physical = getCustomTableName(sf.id, ws) || mkSqliteTableNameFromFileSheet(fp, ws);
                        const alias = getCustomTableAlias(sf.id, ws) || physical;
                        map[physical] = alias;
                    });
                });
            } catch (_) { }
            return map;
        }

        function getTableDisplayName(physicalName) {
            const n = String(physicalName || '');
            if (!n) return '';
            const m = window.__tableAliasLookup || {};
            const alias = m[n];
            if (alias && alias !== n) return `${alias}（${n}）`;
            return n;
        }

        // 仅显示“用户显示名”（若未设置则回退物理名）
        function getTableAliasName(physicalName) {
            const n = String(physicalName || '');
            if (!n) return '';
            const m = window.__tableAliasLookup || {};
            const alias = m[n];
            return (alias && alias.trim()) ? String(alias).trim() : n;
        }

        function getObjectTypeLabel(name) {
            const n = String(name || '').toLowerCase();
            // 约定：vw_ 前缀均视为 VIEW（其它情况按表处理）
            if (n.startsWith('vw_')) return '视图';
            return '表';
        }

        // ===== 表/视图选择器（双列 + 快速搜索）=====
        window.__tablePickerInstances = window.__tablePickerInstances || {};
        window.__tablePickerSelectIds = window.__tablePickerSelectIds || [
            'sqliteMainTableSelect',
            'stqTableSelect',
            'stsTableSelect',
            'sstTable',
            'relMainTable',
            'compareAfterTable',
            'dcVerifyRefTable',
            'mtqMainTable',
            'mtsMainTable',
            'mtsptMainTable'
        ];

        function ensureTablePicker(selectId) {
            if (!selectId) return;
            if (window.__tablePickerInstances[selectId]) return;
            const sel = document.getElementById(selectId);
            if (!sel) return;

            // 隐藏原生 select
            sel.style.display = 'none';

            const wrap = document.createElement('div');
            wrap.className = 'table-picker-wrap';

            const display = document.createElement('div');
            display.className = 'table-picker-display';
            display.innerHTML = `<span class="tp-text">选择表/视图</span><span class="tp-caret">▾</span>`;

            const panel = document.createElement('div');
            panel.className = 'table-picker-panel';
            panel.innerHTML = `
                <input class="table-picker-search" placeholder="输入名称快速定位（支持别名/物理名）" />
                <div class="table-picker-list"></div>
            `;

            wrap.appendChild(display);
            wrap.appendChild(panel);
            sel.insertAdjacentElement('afterend', wrap);

            const textEl = display.querySelector('.tp-text');
            const searchEl = panel.querySelector('.table-picker-search');
            const listEl = panel.querySelector('.table-picker-list');

            const inst = { selectId, sel, wrap, display, panel, textEl, searchEl, listEl, items: [] };
            window.__tablePickerInstances[selectId] = inst;

            const close = () => panel.classList.remove('open');
            const open = () => {
                panel.classList.add('open');
                try { searchEl.value = ''; } catch (_) { }
                try { render(); } catch (_) { }
                try { setTimeout(() => searchEl.focus(), 0); } catch (_) { }
            };
            const toggle = () => panel.classList.contains('open') ? close() : open();

            const render = () => {
                const q = String(searchEl.value || '').trim().toLowerCase();
                const filtered = !q ? inst.items : inst.items.filter(x =>
                    String(x.label || '').toLowerCase().includes(q) ||
                    String(x.value || '').toLowerCase().includes(q)
                );
                listEl.innerHTML = '';
                if (!filtered.length) {
                    const empty = document.createElement('div');
                    empty.style.padding = '10px';
                    empty.style.color = '#6c757d';
                    empty.style.fontSize = '9pt';
                    empty.textContent = '无匹配结果';
                    listEl.appendChild(empty);
                    return;
                }
                filtered.forEach(item => {
                    const row = document.createElement('div');
                    row.className = 'table-picker-item';
                    row.title = item.label !== item.value ? item.value : item.value;
                    row.innerHTML = `
                        <div class="tp-left">
                            <div class="tp-name">${escapeHtml(item.label)}</div>
                            ${item.sub ? `<div class="tp-sub">${escapeHtml(item.sub)}</div>` : ``}
                        </div>
                        <div class="tp-type">${escapeHtml(item.type)}</div>
                    `;
                    row.addEventListener('click', () => {
                        inst.sel.value = item.value;
                        // 触发原有 onchange 逻辑
                        try { inst.sel.dispatchEvent(new Event('change', { bubbles: true })); } catch (_) { }
                        updateTablePickerText(inst);
                        close();
                    });
                    listEl.appendChild(row);
                });
            };

            display.addEventListener('click', (e) => { try { e.stopPropagation(); } catch (_) { } toggle(); });
            panel.addEventListener('click', (e) => { try { e.stopPropagation(); } catch (_) { } });
            searchEl.addEventListener('input', () => { try { render(); } catch (_) { } });
            searchEl.addEventListener('keydown', (e) => {
                if (e.key === 'Escape') { close(); }
                if (e.key === 'Enter') {
                    // 选择第一个可见项
                    const first = listEl.querySelector('.table-picker-item');
                    if (first) first.click();
                }
            });
            document.addEventListener('click', close);

            // 首次同步
            updateTablePickerOptions(inst);
            updateTablePickerText(inst);
        }

        function updateTablePickerOptions(inst) {
            if (!inst || !inst.sel) return;
            const opts = Array.from(inst.sel.options || []).filter(o => String(o.value || '').trim());
            inst.items = opts.map(o => {
                const v = String(o.value || '');
                const label = getTableAliasName(v) || v;
                return {
                    value: v,
                    label,
                    sub: (label !== v) ? v : '',
                    type: getObjectTypeLabel(v)
                };
            });
        }

        function updateTablePickerText(inst) {
            if (!inst || !inst.textEl || !inst.sel) return;
            const v = String(inst.sel.value || '').trim();
            if (!v) { inst.textEl.textContent = '选择表/视图'; return; }
            const label = getTableAliasName(v) || v;
            inst.textEl.textContent = label;
            try { inst.display.title = (label !== v) ? v : ''; } catch (_) { }
        }

        function updateAllTablePickers() {
            try {
                (window.__tablePickerSelectIds || []).forEach(id => {
                    ensureTablePicker(id);
                    const inst = window.__tablePickerInstances[id];
                    if (!inst) return;
                    updateTablePickerOptions(inst);
                    updateTablePickerText(inst);
                });
            } catch (_) { }
        }

        // ===== 数据库对象管理（表/视图集中管理）=====
        window.__dbmObjects = window.__dbmObjects || [];

        function dbmRefresh() {
            if (!window.chrome || !window.chrome.webview || !window.chrome.webview.postMessage) return;
            if (!window.__sqliteReady) { alert('SQLite 尚未导入：请先在【项目管理】完成导入'); return; }
            window.chrome.webview.postMessage({ action: 'getDbObjects' });
            setStatusMessage('正在刷新数据库对象...');
        }

        function dbmClassify(name, type) {
            const n = String(name || '').toLowerCase();
            const t = String(type || '').toLowerCase();
            if (t === 'view' || n.startsWith('vw_')) return '视图';
            if (n.startsWith('raw__')) return 'raw';
            if (n.startsWith('clean__')) return 'clean';
            if (n.includes('__tmp__') || n.includes('_tmp_') || n.includes('backup') || n.includes('_bak') || n.endsWith('_bak')) return '临时/备份';
            return '导入表';
        }

        function dbmToggleAll(flag) {
            document.querySelectorAll('#dbmBody input[type="checkbox"][data-dbobj="1"]').forEach(cb => cb.checked = !!flag);
        }

        function dbmRender() {
            const body = document.getElementById('dbmBody');
            if (!body) return;
            const list = Array.isArray(window.__dbmObjects) ? window.__dbmObjects : [];

            const ft = !!document.getElementById('dbmFilterTables')?.checked;
            const fv = !!document.getElementById('dbmFilterViews')?.checked;
            const fr = !!document.getElementById('dbmFilterRaw')?.checked;
            const fc = !!document.getElementById('dbmFilterClean')?.checked;
            const fp = !!document.getElementById('dbmFilterTmp')?.checked;
            const q = String(document.getElementById('dbmSearch')?.value || '').trim().toLowerCase();

            const filtered = list.filter(x => {
                const name = String(x.name || x.Name || '');
                const type = String(x.type || x.Type || '');
                if (!name) return false;
                const isView = (String(type).toLowerCase() === 'view') || name.toLowerCase().startsWith('vw_');
                if (isView && !fv) return false;
                if (!isView && !ft) return false;
                const cat = dbmClassify(name, type);
                if (cat === 'raw' && !fr) return false;
                if (cat === 'clean' && !fc) return false;
                if (cat === '临时/备份' && !fp) return false;
                // 搜索：支持显示名/物理名
                const alias = getTableAliasName(name) || name;
                if (q && !(name.toLowerCase().includes(q) || alias.toLowerCase().includes(q))) return false;
                return true;
            });

            body.innerHTML = '';
            if (!filtered.length) {
                body.innerHTML = `<tr><td colspan="5" style="color:#6c757d;">（无匹配对象）</td></tr>`;
                return;
            }

            filtered.forEach(x => {
                const name = String(x.name || x.Name || '');
                const type = String(x.type || x.Type || '');
                const isView = (String(type).toLowerCase() === 'view') || name.toLowerCase().startsWith('vw_');
                const typeLabel = isView ? '视图' : '表';
                const cat = dbmClassify(name, type);
                const alias = getTableAliasName(name) || name;
                const label = alias;
                const sub = (alias !== name) ? name : '';

                const tr = document.createElement('tr');
                tr.innerHTML = `
                    <td><input type="checkbox" data-dbobj="1" data-name="${escapeHtml(name)}" data-type="${escapeHtml(typeLabel)}"></td>
                    <td title="${escapeHtml(name)}">
                        <div style="font-weight:600; color:#212529;">${escapeHtml(label)}</div>
                        ${sub ? `<div style="font-size:8pt; color:#6c757d;">${escapeHtml(sub)}</div>` : ``}
                    </td>
                    <td>${escapeHtml(typeLabel)}</td>
                    <td>${escapeHtml(cat)}</td>
                    <td>
                        <button class="btn btn-secondary dbm-dep-btn" style="padding:2px 8px; font-size:9pt;" data-name="${escapeHtml(name)}">依赖</button>
                        <button class="btn btn-primary dbm-ren-btn" style="padding:2px 8px; font-size:9pt;" data-name="${escapeHtml(name)}" data-type="${escapeHtml(typeLabel)}">重命名</button>
                        <button class="btn btn-danger dbm-del-btn" style="padding:2px 8px; font-size:9pt;" data-name="${escapeHtml(name)}" data-type="${escapeHtml(typeLabel)}">删除</button>
                    </td>
                `;
                try {
                    tr.querySelector('.dbm-dep-btn')?.addEventListener('click', (ev) => {
                        try { ev.stopPropagation(); } catch (_) { }
                        dbmShowDependencies(name);
                    });
                    tr.querySelector('.dbm-ren-btn')?.addEventListener('click', (ev) => {
                        try { ev.stopPropagation(); } catch (_) { }
                        dbmRenameOne(name, typeLabel);
                    });
                    tr.querySelector('.dbm-del-btn')?.addEventListener('click', (ev) => {
                        try { ev.stopPropagation(); } catch (_) { }
                        dbmDeleteOne(name, typeLabel);
                    });
                } catch (_) { }
                body.appendChild(tr);
            });
        }

        function dbmDeleteOne(name, typeLabel) {
            const n = String(name || '');
            if (!n) return;
            const t = (String(typeLabel || '').includes('视图') || n.toLowerCase().startsWith('vw_')) ? 'view' : 'table';
            // 删除前：依赖检测（view/建模/模板等后续可扩展；目前先覆盖“视图依赖”）
            dbmFetchDependencies(n, (res) => {
                const deps = res && Array.isArray(res.dependents) ? res.dependents : [];
                const cfg = res && Array.isArray(res.configRefs) ? res.configRefs : [];
                const depNames = deps.map(x => x && x.name ? x.name : '').filter(Boolean);
                const depText = depNames.length ? `\n\n检测到依赖视图（${depNames.length}）：\n${depNames.slice(0, 20).join('\n')}${depNames.length > 20 ? '\n...' : ''}\n\n建议：先处理依赖或谨慎强删。` : '';
                const cfgText = cfg.length ? `\n\n检测到项目配置引用：${cfg.map(x => x.scope || '配置').join('，')}` : '';
                const extra = (window.__sqliteMainTableName && n === window.__sqliteMainTableName) ? '\n\n注意：你正在删除“当前主表”，删除后需重新选择主表。' : '';
                if (!confirm(`确认删除${t === 'view' ? '视图' : '表'}：\n${n}${extra}\n\n提示：删除后无法恢复（可通过修订点备份回滚）。${depText}${cfgText}`)) return;
                window.chrome?.webview?.postMessage?.({ action: 'dropDbObjects', objects: [{ name: n, type: t }] });
            });
        }

        function dbmRenameOne(name, typeLabel) {
            const oldName = String(name || '').trim();
            if (!oldName) return;
            if (oldName.includes('.')) { alert('暂不支持对“附加库对象（含 db. 前缀）”重命名'); return; }
            const t = (String(typeLabel || '').includes('视图') || oldName.toLowerCase().startsWith('vw_')) ? 'view' : 'table';
            const newName = String(prompt(`请输入新的${t === 'view' ? '视图' : '表'}名称（将执行物理重命名）`, oldName) || '').trim();
            if (!newName || newName === oldName) return;
            if (newName.includes('.')) { alert('名称中不允许包含“.”'); return; }

            // 依赖检测：表/视图重命名若有依赖视图，建议级联更新
            dbmFetchDependencies(oldName, (res) => {
                const deps = res && Array.isArray(res.dependents) ? res.dependents : [];
                const cfg = res && Array.isArray(res.configRefs) ? res.configRefs : [];
                const depNames = deps.map(x => x && x.name ? String(x.name) : '').filter(Boolean).filter(x => !x.includes('.'));
                let cascade = false;
                if (depNames.length) {
                    cascade = confirm(`检测到依赖视图（${depNames.length}）：\n${depNames.slice(0, 20).join('\n')}${depNames.length > 20 ? '\n...' : ''}\n\n是否尝试“级联更新依赖视图SQL”（可能失败，需要手动修复）？\n【取消】则终止重命名。`);
                    if (!cascade) return;
                }
                if (cfg.length && t === 'view') {
                    // 视图重命名会影响项目配置里的引用：给出额外提示
                    if (!confirm(`检测到当前项目配置中可能引用了该对象。\n为避免后续加载项目失败，重命名后会尝试自动更新项目配置引用。\n\n是否继续？`)) return;
                }
                if (cfg.length && t === 'table') {
                    if (!confirm(`检测到当前项目配置中可能引用了该表。\n重命名后会尝试自动更新项目配置引用。\n\n是否继续？`)) return;
                }
                if (!confirm(`确认重命名${t === 'view' ? '视图' : '表'}：\n${oldName}\n→ ${newName}\n\n提示：这是物理重命名，会影响SQL/脚本/模板引用。`)) return;
                const reqId = String(Date.now());
                window.chrome?.webview?.postMessage?.({
                    action: 'renameDbObject',
                    requestId: reqId,
                    oldName,
                    newName,
                    type: t,
                    cascadeDependents: !!cascade,
                    dependents: depNames
                });
            });
        }

        function dbmShowDependencies(name) {
            const n = String(name || '').trim();
            if (!n) return;
            dbmFetchDependencies(n, (res) => {
                const deps = res && Array.isArray(res.dependents) ? res.dependents : [];
                const cfg = res && Array.isArray(res.configRefs) ? res.configRefs : [];
                const depNames = deps.map(x => x && x.name ? x.name : '').filter(Boolean);
                const cfgLines = cfg.map(x => {
                    const p = x && x.path ? String(x.path) : '';
                    const h = x && x.hint ? String(x.hint) : '';
                    const s = x && x.snippet ? String(x.snippet) : '';
                    if (!p && !s) return '';
                    return `${p}${h ? `（${h}）` : ''}${s ? `：${s}` : ''}`;
                }).filter(Boolean);
                if (!depNames.length && !cfgLines.length) { xslqShowTextModal('依赖分析', '未检测到依赖'); return; }
                const a = depNames.length ? `依赖视图（${depNames.length}）：\n${depNames.join('\n')}` : '';
                const b = cfgLines.length ? `\n\n项目配置引用（${cfgLines.length}）：\n${cfgLines.slice(0,30).join('\n')}${cfgLines.length>30?'\n...':''}` : '';
                xslqShowTextModal('依赖分析', `${a}${b}`);
            });
        }

        window.__dbmDepCallbacks = window.__dbmDepCallbacks || {};
        function dbmFetchDependencies(name, cb) {
            const n = String(name || '').trim();
            if (!n) { cb({ dependents: [], configRefs: [] }); return; }
            const reqId = 'dbmdep_' + Date.now() + '_' + Math.floor(Math.random() * 1000);
            window.__dbmDepCallbacks[reqId] = cb;
            window.chrome?.webview?.postMessage?.({ action: 'getDbObjectDependencies', requestId: reqId, name: n });
        }

        function dbmFetchDependenciesPromise(name) {
            return new Promise((resolve) => {
                try { dbmFetchDependencies(name, (res) => resolve(res || { dependents: [], configRefs: [] })); }
                catch (_) { resolve({ dependents: [], configRefs: [] }); }
            });
        }

        function dbmGetSelectedItems() {
            return Array.from(document.querySelectorAll('#dbmBody input[type="checkbox"][data-dbobj="1"]:checked'))
                .map(cb => {
                    const n = cb.getAttribute('data-name') || '';
                    const tl = cb.getAttribute('data-type') || '';
                    const t = (String(tl).includes('视图') || String(n).toLowerCase().startsWith('vw_')) ? 'view' : 'table';
                    return n ? { name: n, type: t } : null;
                })
                .filter(Boolean);
        }

        window.__dbmRenameWaiters = window.__dbmRenameWaiters || {};
        function dbmWaitRename(requestId) {
            return new Promise((resolve) => {
                if (!requestId) return resolve({ ok: false });
                window.__dbmRenameWaiters[requestId] = resolve;
                // 超时保护（60s）
                setTimeout(() => {
                    if (window.__dbmRenameWaiters[requestId]) {
                        delete window.__dbmRenameWaiters[requestId];
                        resolve({ ok: false, timeout: true });
                    }
                }, 60000);
            });
        }

        function dbmDeleteSelected() {
            const items = dbmGetSelectedItems();
            if (!items.length) { alert('请先勾选要删除的对象'); return; }

            (async () => {
                const rows = [];
                const details = {};
                let totalDepViews = 0;
                let totalCfgRefs = 0;
                for (const it of items) {
                    const res = await dbmFetchDependenciesPromise(it.name);
                    const deps = Array.isArray(res?.dependents) ? res.dependents : [];
                    const cfg = Array.isArray(res?.configRefs) ? res.configRefs : [];
                    details[it.name] = { deps, cfg };
                    totalDepViews += deps.length;
                    totalCfgRefs += cfg.length;
                    const depNames = deps.map(x => x && x.name ? x.name : '').filter(Boolean).slice(0, 5);
                    const cfgNames = cfg.map(x => x && x.path ? String(x.path) : '').filter(Boolean).slice(0, 3);
                    rows.push({
                        name: it.name,
                        type: it.type,
                        depViews: deps.length,
                        cfgRefs: cfg.length,
                        depPreview: depNames.join('，'),
                        cfgPreview: cfgNames.join('，')
                    });
                }

                const main = window.__sqliteMainTableName || '';
                const mainHit = main ? rows.some(r => String(r.name) === String(main)) : false;

                const html = `
                    <div class="result-info" style="background:#fff7e6; border-left:4px solid #fa8c16;">
                        <div><b>即将删除对象：</b>${rows.length} 个</div>
                        <div style="margin-top:4px;"><b>依赖视图总数：</b>${totalDepViews} ｜ <b>项目配置引用总数：</b>${totalCfgRefs}</div>
                        ${mainHit ? `<div style="margin-top:6px; color:#cf1322;"><b>注意：</b>选中项包含“当前主表”，删除后需要重新设定主表。</div>` : ``}
                    </div>
                    <div style="margin-top:10px; max-height:42vh; overflow:auto; border:1px solid #e9ecef; border-radius:6px; background:#fff;">
                        <table class="table" style="font-size:9pt; margin:0;">
                            <thead><tr><th>对象</th><th style="width:64px;">类型</th><th style="width:90px;">依赖视图</th><th style="width:110px;">配置引用</th><th>依赖预览</th></tr></thead>
                            <tbody>
                                ${rows.map(r => `
                                    <tr>
                                        <td style="font-family:Consolas,monospace;">${escapeHtml(r.name)}</td>
                                        <td>${escapeHtml(r.type === 'view' ? '视图' : '表')}</td>
                                        <td>${escapeHtml(String(r.depViews))}</td>
                                        <td>${escapeHtml(String(r.cfgRefs))}</td>
                                        <td style="color:#6c757d;">${escapeHtml([r.depPreview, r.cfgPreview].filter(Boolean).join(' ｜ '))}</td>
                                    </tr>
                                `).join('')}
                            </tbody>
                        </table>
                    </div>
                `;

                const choice = await xslqShowDangerModal({
                    title: '批量删除（高风险）',
                    html,
                    okText: '确认删除',
                    cancelText: '取消',
                    checks: [
                        { label: '我已知晓：删除将不可恢复（可通过修订点回滚）', required: true },
                        { label: '我已检查依赖（视图/配置引用）并确认允许断链', required: true }
                    ]
                });
                if (choice !== 'ok') return;

                // 导出影响报告（审计留档）
                try {
                    const ts = new Date().toISOString().replace(/[-:]/g, '').slice(0, 15);
                    const rowsHtml = rows.map(r => {
                        const depList = (details[r.name]?.deps || []).map(x => x && x.name ? x.name : '').filter(Boolean).slice(0, 30).join('<br>');
                        const cfgList = (details[r.name]?.cfg || []).map(x => x && x.path ? x.path : '').filter(Boolean).slice(0, 30).join('<br>');
                        return `<tr>
                            <td style="font-family:Consolas,monospace;">${escapeHtml(r.name)}</td>
                            <td>${escapeHtml(r.type === 'view' ? '视图' : '表')}</td>
                            <td class="num">${escapeHtml(String(r.depViews))}</td>
                            <td class="num">${escapeHtml(String(r.cfgRefs))}</td>
                            <td style="color:#6c757d; font-size:8.5pt;">${depList || '-'}</td>
                            <td style="color:#6c757d; font-size:8.5pt;">${cfgList || '-'}</td>
                        </tr>`;
                    }).join('');
                    const reportHtml = `
                        <!doctype html><html><head><meta charset="utf-8"><title>批量删除影响报告</title>
                        <style>
                          ${reportCss('body{margin:16px;} th{background:#fafafa;color:#212529;}')}
                          .box{border:1px solid #e1e4e8; border-radius:8px; padding:12px; background:#fff;}
                          .num{text-align:right;}
                        </style></head><body>
                          <h1>数据库对象管理：批量删除影响报告</h1>
                          <div class="box">
                            <div><b>时间：</b>${escapeHtml(new Date().toLocaleString())}</div>
                            <div><b>对象数：</b>${escapeHtml(String(rows.length))} ｜ <b>依赖视图总数：</b>${escapeHtml(String(totalDepViews))} ｜ <b>配置引用总数：</b>${escapeHtml(String(totalCfgRefs))}</div>
                            <div style="margin-top:6px; color:#6c757d;">提示：执行删除前系统会自动创建修订点，可在项目中心恢复。</div>
                          </div>
                          <table>
                            <thead><tr><th>对象</th><th style="width:70px;">类型</th><th style="width:90px;">依赖视图数</th><th style="width:90px;">配置引用数</th><th>依赖视图（前30）</th><th>配置引用路径（前30）</th></tr></thead>
                            <tbody>${rowsHtml}</tbody>
                          </table>
                        </body></html>`;
                    window.chrome?.webview?.postMessage?.({ action: 'saveHtmlReport', reportName: 'dbm-batch-delete', fileName: `dbm-batch-delete-${ts}.html`, html: reportHtml, openAfterSave: true });
                } catch (_) { }

                window.chrome?.webview?.postMessage?.({ action: 'dropDbObjects', objects: items });
            })();
        }

        async function dbmBatchRenameSelected() {
            const items = dbmGetSelectedItems();
            if (!items.length) { alert('请先勾选要重命名的对象'); return; }

            // 选择模式：1前缀替换 2后缀追加 3正则替换 4粘贴映射
            const mode = String(prompt('批量重命名模式：\n1=前缀替换（raw__ -> raw__2026_）\n2=后缀追加（_bak -> _bak_2026）\n3=正则替换（支持 /pattern/flags）\n4=粘贴映射（每行 old -> new）\n\n请输入 1/2/3/4：', '1') || '').trim();
            if (!mode) return;

            let mapping = [];
            let modeLabel = '';
            let ruleLabel = '';

            const buildFromMap = (mapObj) => {
                const mm = [];
                items.forEach(it => {
                    const oldName = String(it.name);
                    const newName = mapObj[oldName] || mapObj[oldName.toLowerCase()] || '';
                    if (newName && newName !== oldName) mm.push({ ...it, oldName, newName: String(newName) });
                });
                return mm;
            };

            if (mode === '1') {
                modeLabel = '前缀替换';
                const oldPrefix = String(prompt('请输入“旧前缀”（例如 raw__）', '') || '').trim();
                if (!oldPrefix) return;
                const newPrefix = String(prompt('请输入“新前缀”（例如 raw__2026_）', '') || '').trim();
                if (!newPrefix) return;
                ruleLabel = `${oldPrefix} -> ${newPrefix}`;
                mapping = items.map(it => {
                    const oldName = String(it.name);
                    if (!oldName.startsWith(oldPrefix)) return null;
                    const newName = newPrefix + oldName.slice(oldPrefix.length);
                    return { ...it, oldName, newName };
                }).filter(Boolean);
            } else if (mode === '2') {
                modeLabel = '后缀追加';
                const oldSuffix = String(prompt('请输入“旧后缀”（例如 _bak 或留空=全部匹配）', '') || '').trim();
                const addSuffix = String(prompt('请输入“要追加的新后缀”（例如 _2026 或 _v2）', '') || '').trim();
                if (!addSuffix) return;
                ruleLabel = `${oldSuffix || '(全部)'} + ${addSuffix}`;
                mapping = items.map(it => {
                    const oldName = String(it.name);
                    if (oldSuffix && !oldName.endsWith(oldSuffix)) return null;
                    const newName = oldName + addSuffix;
                    return { ...it, oldName, newName };
                }).filter(Boolean);
            } else if (mode === '3') {
                modeLabel = '正则替换';
                const raw = String(prompt('请输入正则（支持两种写法）：\n1) 直接写 pattern（默认全局 g）\n2) /pattern/flags（例如 /^raw__/i）', '') || '').trim();
                if (!raw) return;
                const replacement = String(prompt('请输入 replacement（例如 clean__）', '') || '');
                let rx = null;
                try {
                    if (raw.startsWith('/') && raw.lastIndexOf('/') > 0) {
                        const last = raw.lastIndexOf('/');
                        const pat = raw.slice(1, last);
                        const flags = raw.slice(last + 1) || 'g';
                        rx = new RegExp(pat, flags.includes('g') ? flags : (flags + 'g'));
                    } else {
                        rx = new RegExp(raw, 'g');
                    }
                } catch (e) {
                    alert('正则无效：' + (e && e.message ? e.message : e));
                    return;
                }
                ruleLabel = `${raw} -> ${replacement}`;
                mapping = items.map(it => {
                    const oldName = String(it.name);
                    const newName = oldName.replace(rx, replacement);
                    if (!newName || newName === oldName) return null;
                    return { ...it, oldName, newName };
                }).filter(Boolean);
            } else if (mode === '4') {
                modeLabel = '粘贴映射';
                const text = await xslqPromptTextArea('粘贴映射（每行 old -> new）', '', '示例：\nraw__A -> raw__2026_A\nvw_x -> vw_x_v2\n\n支持分隔符：-> , tab');
                if (text == null) return;
                const lines = String(text).split(/\r?\n/).map(x => x.trim()).filter(Boolean);
                const mapObj = {};
                lines.forEach(ln => {
                    let a = '', b = '';
                    if (ln.includes('->')) {
                        const parts = ln.split('->');
                        a = (parts[0] || '').trim();
                        b = (parts.slice(1).join('->') || '').trim();
                    } else if (ln.includes('\t')) {
                        const parts = ln.split('\t');
                        a = (parts[0] || '').trim();
                        b = (parts[1] || '').trim();
                    } else if (ln.includes(',')) {
                        const parts = ln.split(',');
                        a = (parts[0] || '').trim();
                        b = (parts[1] || '').trim();
                    }
                    if (a && b) mapObj[a] = b;
                });
                mapping = buildFromMap(mapObj);
                ruleLabel = `映射行数：${lines.length}`;
            } else {
                alert('无效模式');
                return;
            }

            if (!mapping.length) { alert('未生成任何重命名映射（可能都未匹配或替换后无变化）'); return; }

            // 冲突检查：新名称重复/为空
            const set = new Set();
            const dup = [];
            mapping.forEach(m => {
                const k = m.newName.toLowerCase();
                if (set.has(k)) dup.push(m.newName);
                set.add(k);
            });
            if (dup.length) { xslqShowTextModal('批量重命名', '检测到重复目标名称：\n' + dup.join('\n')); return; }

            // 冲突检查：与现有对象冲突（不含自己）
            try {
                const existing = new Set((Array.isArray(window.__dbmObjects) ? window.__dbmObjects : []).map(x => String(x.name||x.Name||'').toLowerCase()).filter(Boolean));
                const conflict = [];
                mapping.forEach(m => {
                    const nn = String(m.newName||'').toLowerCase();
                    const on = String(m.oldName||'').toLowerCase();
                    if (nn && nn !== on && existing.has(nn)) conflict.push(m.newName);
                });
                if (conflict.length) {
                    xslqShowTextModal('批量重命名', '检测到目标名称与现有对象冲突（请先删除/改名冲突对象）：\n' + conflict.slice(0,100).join('\n') + (conflict.length>100?'\n...':''));
                    return;
                }
            } catch (_) { }

            // 依赖检查 & 汇总
            const depMap = {};
            let totalDep = 0, totalCfg = 0;
            for (const m of mapping) {
                const res = await dbmFetchDependenciesPromise(m.oldName);
                const deps = Array.isArray(res?.dependents) ? res.dependents : [];
                const cfg = Array.isArray(res?.configRefs) ? res.configRefs : [];
                depMap[m.oldName] = { deps, cfg };
                totalDep += deps.length;
                totalCfg += cfg.length;
            }

            const cascade = (totalDep > 0) ? confirm(`检测到依赖视图总数：${totalDep}\n是否尝试“级联更新依赖视图SQL”（可能失败，需要手动修复）？\n【取消】将终止批量重命名。`) : true;
            if (!cascade) return;

            const text = mapping.slice(0, 60).map(m => `${m.oldName} -> ${m.newName}`).join('\n') + (mapping.length > 60 ? '\n...' : '');
            const choice = await xslqShowDangerModal({
                title: '批量重命名（高风险）',
                plainText:
                    `模式：${modeLabel}\n规则：${ruleLabel}\n\n对象数量：${mapping.length}\n依赖视图总数：${totalDep}\n配置引用总数：${totalCfg}\n\n映射预览：\n${text}`,
                okText: '开始执行',
                cancelText: '取消',
                checks: [
                    { label: '我已知晓：这是物理重命名，会影响SQL/模板/下游脚本', required: true },
                    { label: '我已确认目标名称不会与现有对象冲突', required: true }
                ]
            });
            if (choice !== 'ok') return;

            // 串行执行（保证稳定）
            let ok = 0, fail = 0;
            const failList = [];
            const rpIds = [];
            // 导出预检报告（审计留档）
            try {
                const ts = new Date().toISOString().replace(/[-:]/g, '').slice(0, 15);
                const mapHtml = mapping.map(m => {
                    const deps = (depMap[m.oldName]?.deps || []).map(x => x && x.name ? x.name : '').filter(Boolean).slice(0, 20).join('<br>');
                    const cfg = (depMap[m.oldName]?.cfg || []).map(x => x && x.path ? x.path : '').filter(Boolean).slice(0, 20).join('<br>');
                    return `<tr>
                        <td style="font-family:Consolas,monospace;">${escapeHtml(m.oldName)}</td>
                        <td style="font-family:Consolas,monospace;">${escapeHtml(m.newName)}</td>
                        <td>${escapeHtml(m.type === 'view' ? '视图' : '表')}</td>
                        <td class="num">${escapeHtml(String((depMap[m.oldName]?.deps||[]).length))}</td>
                        <td class="num">${escapeHtml(String((depMap[m.oldName]?.cfg||[]).length))}</td>
                        <td style="color:#6c757d; font-size:8.5pt;">${deps || '-'}</td>
                        <td style="color:#6c757d; font-size:8.5pt;">${cfg || '-'}</td>
                    </tr>`;
                }).join('');
                const reportHtml = `
                    <!doctype html><html><head><meta charset="utf-8"><title>批量重命名预检报告</title>
                    <style>
                      ${reportCss('body{margin:16px;} th{background:#fafafa;color:#212529;}')}
                      .box{border:1px solid #e1e4e8; border-radius:8px; padding:12px; background:#fff;}
                      .num{text-align:right;}
                    </style></head><body>
                      <h1>数据库对象管理：批量重命名预检报告</h1>
                      <div class="box">
                        <div><b>时间：</b>${escapeHtml(new Date().toLocaleString())}</div>
                        <div><b>模式：</b>${escapeHtml(modeLabel)} ｜ <b>规则：</b>${escapeHtml(ruleLabel)}</div>
                        <div><b>对象数：</b>${escapeHtml(String(mapping.length))} ｜ <b>依赖视图总数：</b>${escapeHtml(String(totalDep))} ｜ <b>配置引用总数：</b>${escapeHtml(String(totalCfg))}</div>
                        <div><b>级联更新依赖视图：</b>${escapeHtml(cascade ? '是' : '否')}</div>
                        <div style="margin-top:6px; color:#6c757d;">提示：执行重命名前系统会自动创建修订点，可在项目中心恢复。</div>
                      </div>
                      <table>
                        <thead><tr><th>旧名</th><th>新名</th><th style="width:70px;">类型</th><th style="width:90px;">依赖视图</th><th style="width:90px;">配置引用</th><th>依赖视图（前20）</th><th>配置引用路径（前20）</th></tr></thead>
                        <tbody>${mapHtml}</tbody>
                      </table>
                    </body></html>`;
                window.chrome?.webview?.postMessage?.({ action: 'saveHtmlReport', reportName: 'dbm-batch-rename', fileName: `dbm-batch-rename-precheck-${ts}.html`, html: reportHtml, openAfterSave: true });
            } catch (_) { }

            for (const m of mapping) {
                try {
                    const reqId = 'dbmren_' + Date.now() + '_' + Math.floor(Math.random() * 1000);
                    const depNames = (depMap[m.oldName]?.deps || []).map(x => x && x.name ? String(x.name) : '').filter(Boolean).filter(x => !x.includes('.'));
                    window.chrome?.webview?.postMessage?.({
                        action: 'renameDbObject',
                        requestId: reqId,
                        oldName: m.oldName,
                        newName: m.newName,
                        type: m.type,
                        cascadeDependents: !!cascade,
                        dependents: depNames
                    });
                    const r = await dbmWaitRename(reqId);
                    if (r && r.ok !== false) {
                        ok++;
                        try { const rp = r.data && (r.data.revisionPointId || r.data.revisionPointID); if (rp) rpIds.push(String(rp)); } catch (_) { }
                    }
                    else { fail++; failList.push(`${m.oldName} -> ${m.newName}`); }
                } catch (_) {
                    fail++;
                    failList.push(`${m.oldName} -> ${m.newName}`);
                }
            }

            xslqShowTextModal('批量重命名结果', `完成：成功 ${ok}，失败 ${fail}\n\n提示：可到【项目中心-修订点】回滚。`);
            // 导出结果报告
            try {
                const ts2 = new Date().toISOString().replace(/[-:]/g, '').slice(0, 15);
                const report = `批量重命名结果\\n时间：${new Date().toLocaleString()}\\n模式：${modeLabel}\\n规则：${ruleLabel}\\n\\n成功：${ok}\\n失败：${fail}\\n\\n失败项（前200）：\\n${failList.slice(0,200).join('\\n')}`;
                const html2 = `<!doctype html><html><head><meta charset="utf-8"><title>批量重命名结果报告</title><style>${reportCss('body{margin:16px;} pre{font-size:9pt;}')}</style></head><body><pre class="mono" style="white-space:pre-wrap;">${escapeHtml(report)}</pre></body></html>`;
                window.chrome?.webview?.postMessage?.({ action: 'saveHtmlReport', reportName: 'dbm-batch-rename', fileName: `dbm-batch-rename-result-${ts2}.html`, html: html2, openAfterSave: true });
            } catch (_) { }
            try { dbmRefresh(); } catch (_) { }

            // 审计：批量重命名（关联预检/结果报告）
            try {
                const last = window.__lastHtmlReports || {};
                const paths = [];
                if (last['dbm-batch-rename']) paths.push(last['dbm-batch-rename']);
                appendAuditLog({
                    type: 'dbm-batch-rename',
                    note: `批量重命名：${modeLabel}｜${ruleLabel}｜成功${ok}失败${fail}`,
                    revisionPointIds: Array.from(new Set(rpIds)).slice(0, 50),
                    reportPaths: paths.filter(Boolean),
                    payload: { mode: modeLabel, rule: ruleLabel, ok, fail }
                });
            } catch (_) { }
        }

        function appendAuditLog(payload) {
            try {
                const meta = window.__selectedProjectMeta || null;
                const schemeId = (meta && (meta.Id || meta.id)) ? (meta.Id || meta.id) : (window.__activeSchemeId || '');
                if (!schemeId) return;
                window.chrome?.webview?.postMessage?.({ action: 'appendAuditLog', schemeId, ...(payload || {}) });
            } catch (_) { }
        }

        function syncMainTableUiAndHost() {
            // 根据“设为主表”的选择，同步上方下拉与宿主当前主表（若已导入）
            try {
                ensureMainExists();
                const m = window.__fileWizardMain || null;
                if (!m || !m.filePath || !m.sheetName) return;
                const tn = getCustomTableName(m.sourceId, m.sheetName) || mkSqliteTableNameFromFileSheet(m.filePath, m.sheetName);
                window.__sqliteMainTableName = tn;
                try { refreshSqliteMainTableSelect(); } catch (_) { }
                const tables = Array.isArray(window.__sqliteTables) ? window.__sqliteTables : [];
                if (tables.includes(tn)) {
                    try { postSetMainTable(tn, false); } catch (_) { }
                    try { refreshWorksheetSelectForDb(); } catch (_) { }
                    try { requestActiveFields(); } catch (_) { }
                }
            } catch (_) { }
        }

        function ensureSourceFilesInit() {
            const container = document.getElementById('sourceFilesContainer');
            if (!container) return;
            if (!window.__sourceFiles.length) {
                addSourceFile(true); // 默认添加 1 个源文件
            } else {
                renderSourceFiles();
            }
        }

        function addSourceFile(isFirst) {
            // 兜底：避免某些初始化顺序导致 __sourceFiles 未定义
            window.__sourceFiles = window.__sourceFiles || [];
            const id = 'src_' + Date.now() + '_' + Math.floor(Math.random() * 1000);
            window.__sourceFiles.push({
                id,
                filePath: '',
                worksheets: [],
                selected: [],
                mainSheet: '',
                tableNameMap: {},
                tableAliasMap: {}
            });
            try { renderSourceFiles(); } catch (e) { console.error('renderSourceFiles failed', e); }
            // 交互优化：用户点“+ 添加源文件”时，直接弹出选择文件对话框
            if (!isFirst) {
                try { browseSourceFile(id); } catch (_) { }
            }
        }

        function removeSourceFile(id) {
            window.__sourceFiles = (window.__sourceFiles || []).filter(x => x.id !== id);
            // 若删除的是当前主表所在文件，清空主表标记（后续会重新自动选定）
            if (window.__fileWizardMain && window.__fileWizardMain.sourceId === id) {
                window.__fileWizardMain = null;
            }
            renderSourceFiles();
            refreshSqliteMainTableSelect();
        }

        function browseSourceFile(id) {
            if (!window.chrome || !window.chrome.webview || !window.chrome.webview.postMessage) {
                alert('WebView2 环境不可用，请检查应用程序配置');
                return;
            }
            window.__pendingWorksheetTargetId = id;
            // 复用宿主已有的 browseSubTableFile（带 subTableId）
            window.chrome.webview.postMessage({ action: 'browseSubTableFile', subTableId: id });
        }

        function setSourceFilePath(id, filePath) {
            const it = (window.__sourceFiles || []).find(x => x.id === id);
            if (!it) return;
            it.filePath = filePath || '';
            it.worksheets = [];
            it.selected = [];
            it.mainSheet = '';
            renderSourceFiles();
        }

        function setSourceWorksheets(id, sheets) {
            const it = (window.__sourceFiles || []).find(x => x.id === id);
            if (!it) return;
            it.worksheets = Array.isArray(sheets) ? sheets : [];
            // 默认：首个工作表选定（符合你要求“初次导入默认第一个文件的第一个工作表”）
            if (!it.selected || !it.selected.length) {
                it.selected = it.worksheets.length ? [it.worksheets[0]] : [];
            }
            // 默认：如果还没选过主表，则把“第一个源文件的第一个工作表”设为主表
            if (!window.__fileWizardMain) {
                const first = window.__sourceFiles[0];
                if (first && first.worksheets.length) {
                    window.__fileWizardMain = { sourceId: first.id, filePath: first.filePath, sheetName: first.worksheets[0] };
                }
            }
            renderSourceFiles();
            refreshSqliteMainTableSelect();
            // 同步“选定主表”下拉（与设为主表一致）
            syncMainTableUiAndHost();
        }

        function toggleWorksheetSelected(sourceId, sheetName, checked) {
            const it = (window.__sourceFiles || []).find(x => x.id === sourceId);
            if (!it) return;
            it.selected = Array.isArray(it.selected) ? it.selected : [];
            const has = it.selected.includes(sheetName);
            if (checked && !has) it.selected.push(sheetName);
            if (!checked && has) it.selected = it.selected.filter(x => x !== sheetName);
            // 取消勾选：移除该工作表的自定义表名（避免残留）
            try {
                if (!checked && it.tableNameMap && it.tableNameMap[sheetName]) delete it.tableNameMap[sheetName];
                if (!checked && it.tableAliasMap && it.tableAliasMap[sheetName]) delete it.tableAliasMap[sheetName];
            } catch (_) { }
            // 如果取消勾选的是主表，则清空主表，后续自动补一个
            if (window.__fileWizardMain
                && window.__fileWizardMain.sourceId === sourceId
                && window.__fileWizardMain.sheetName === sheetName
                && !checked) {
                window.__fileWizardMain = null;
            }
            ensureMainExists();
            renderSourceFiles();
            refreshSqliteMainTableSelect();
            syncMainTableUiAndHost();
        }

        function setMainWorksheet(sourceId, sheetName) {
            const it = (window.__sourceFiles || []).find(x => x.id === sourceId);
            if (!it) return;
            // 设为主表时必须勾选导入
            if (!Array.isArray(it.selected) || !it.selected.includes(sheetName)) {
                it.selected = Array.isArray(it.selected) ? it.selected : [];
                it.selected.push(sheetName);
            }
            // 若尚未设置自定义表名，则默认填充（让用户一眼看见可改）
            try {
                it.tableNameMap = it.tableNameMap || {};
                if (!it.tableNameMap[sheetName]) it.tableNameMap[sheetName] = mkSqliteTableNameFromFileSheet(it.filePath, sheetName);
                it.tableAliasMap = it.tableAliasMap || {};
                if (!it.tableAliasMap[sheetName]) it.tableAliasMap[sheetName] = it.tableNameMap[sheetName];
            } catch (_) { }
            window.__fileWizardMain = { sourceId, filePath: it.filePath, sheetName };
            ensureMainExists();
            renderSourceFiles();
            refreshSqliteMainTableSelect();
            syncMainTableUiAndHost();
        }

        function ensureMainExists() {
            if (window.__fileWizardMain && window.__fileWizardMain.filePath && window.__fileWizardMain.sheetName) return;
            const files = window.__sourceFiles || [];
            for (const f of files) {
                const sel = Array.isArray(f.selected) ? f.selected : [];
                if (f.filePath && sel.length) {
                    window.__fileWizardMain = { sourceId: f.id, filePath: f.filePath, sheetName: sel[0] };
                    return;
                }
            }
        }

        function renderSourceFiles() {
            const container = document.getElementById('sourceFilesContainer');
            if (!container) return;
            ensureMainExists();
            container.innerHTML = '';

            (window.__sourceFiles || []).forEach((f, idx) => {
                const div = document.createElement('div');
                div.className = 'source-file-item';
                div.style.cssText = 'border:1px solid #e9ecef;border-radius:6px;padding:10px;margin-bottom:10px;background:#f8f9fa;';

                const fileName = (f.filePath || '').split('\\').pop().split('/').pop();
                const title = `源文件${idx + 1}: ${fileName || '（未选择）'}`;
                const reimportLabel = (window.__activeSchemeId ? '重导数据库' : '保存数据库');
                div.innerHTML = `
                    <div style="display:flex; align-items:center; gap:8px; margin-bottom:8px;">
                        <span style="min-width: 90px; font-weight: normal;">${title}</span>
                        <input type="text" class="form-control" value="${escapeHtml(f.filePath || '')}" placeholder="选择Excel文件" style="flex:1;" readonly>
                        <button class="btn btn-secondary" onclick="browseSourceFile('${f.id}')">选择文件...</button>
                        <button class="btn btn-warning" onclick="reimportSourceFile('${f.id}')" ${!f.filePath ? 'disabled' : ''} title="将该源文件当前勾选的工作表导入到项目数据库（会先删除对应表再重新导入）；并同步保存源文件关系到项目配置。">${reimportLabel}</button>
                        <button class="btn btn-danger" onclick="removeSourceFile('${f.id}')" ${window.__sourceFiles.length <= 1 ? 'disabled' : ''}>移除</button>
                    </div>
                    <div style="font-size:9pt;color:#495057;margin-bottom:6px;">工作表（勾选=导入；点击“设为主表”=指定当前主表）</div>
                    <div id="sheetBox_${f.id}" style="display:flex; gap:8px; flex-wrap:wrap;"></div>
                `;
                container.appendChild(div);

                const box = div.querySelector(`#sheetBox_${f.id}`);
                const sheets = Array.isArray(f.worksheets) ? f.worksheets : [];
                const selected = Array.isArray(f.selected) ? f.selected : [];
                if (!sheets.length) {
                    if (box) box.innerHTML = `<span style="color:#6c757d;">请先选择文件以加载工作表列表</span>`;
                } else {
                    sheets.forEach(s => {
                        const chip = document.createElement('div');
                        const isSel = selected.includes(s);
                        const isMain = !!(window.__fileWizardMain && window.__fileWizardMain.sourceId === f.id && window.__fileWizardMain.sheetName === s);
                        const defaultTn = mkSqliteTableNameFromFileSheet(f.filePath, s);
                        const tn = (f.tableNameMap && f.tableNameMap[s]) ? String(f.tableNameMap[s]) : defaultTn;
                        const alias = (f.tableAliasMap && f.tableAliasMap[s]) ? String(f.tableAliasMap[s]) : tn;
                        const tables = Array.isArray(window.__sqliteTables) ? window.__sqliteTables : [];
                        const locked = tables.includes(tn); // 已导入：锁定（避免改名破坏引用）
                        chip.style.cssText = `display:inline-flex; align-items:center; gap:6px; padding:6px 8px; border-radius:6px; border:1px solid ${isMain ? '#0078d4' : '#dee2e6'}; background:${isSel ? '#ffffff' : '#f3f4f6'};`;
                        chip.innerHTML = `
                            <label style="display:inline-flex;align-items:center;gap:6px;cursor:pointer;font-weight:normal;">
                                <input type="checkbox" ${isSel ? 'checked' : ''} onchange="toggleWorksheetSelected('${f.id}','${escapeHtml(s)}',this.checked)">
                                <span>${escapeHtml(s)}</span>
                            </label>
                            <button class="btn btn-secondary" style="padding:2px 8px; font-size:9pt;" onclick="setMainWorksheet('${f.id}','${escapeHtml(s)}')">${isMain ? '主表✓' : '设为主表'}</button>
                            ${isSel ? `<span style="font-size:8pt; color:#6c757d;">表名:</span>
                              <input class="form-control" style="width:180px; font-size:9pt; height:26px;" value="${escapeHtml(tn)}" ${locked ? 'disabled title="已导入后不允许改名（可重建/重导来变更）"' : ''} onchange="setCustomTableName('${f.id}','${escapeHtml(s)}', this.value)">
                              <span style="font-size:8pt; color:#6c757d; margin-left:6px;">显示名:</span>
                              <input class="form-control" style="width:140px; font-size:9pt; height:26px;" value="${escapeHtml(alias)}" onchange="setCustomTableAlias('${f.id}','${escapeHtml(s)}', this.value)" title="显示名不会影响物理表名，可随时改（不破坏关联/视图/模板）">
                            ` : ``}
                        `;
                        box.appendChild(chip);
                    });
                }
            });
        }
        
        // 保存文件设置
        function saveFileSettings() {
            ensureMainExists();
            const main = window.__fileWizardMain || null;
            const mainFile = main ? (main.filePath || '') : '';
            const mainSheet = main ? (main.sheetName || '') : '';
            if (!mainFile || !mainSheet) { alert('请先选择至少一个源文件，并勾选至少一个工作表，再设定主表。'); return; }
            
            // 更新顶部文件信息栏
            try {
                const fileEl = document.getElementById('selectedFile');
                if (fileEl) {
                    fileEl.textContent = mainFile.split('\\').pop().split('/').pop();
                    fileEl.setAttribute('data-empty', 'false');
                }
            } catch (_) { }
            window.__currentSheetName = mainSheet;
            
            // 更新所有向导中的当前主表显示
            try { const el = document.getElementById('stqCurrentSheet'); if (el) el.textContent = mainSheet; } catch (_) { }
            try { const el = document.getElementById('stqFilterCurrentSheet'); if (el) el.textContent = mainSheet; } catch (_) { }
            try { const el = document.getElementById('mtqCurrentSheet'); if (el) el.textContent = mainSheet; } catch (_) { }
            // 分拆向导：同步当前主表提示（避免一直显示“请先导入”）
            try { const el = document.getElementById('stsptCurrentSheet'); if (el) el.textContent = mainSheet; } catch (_) { }
            try { const el = document.getElementById('stsptOutputCurrentSheet'); if (el) el.textContent = mainSheet; } catch (_) { }
            try { const el = document.getElementById('mtsptCurrentSheet'); if (el) el.textContent = mainSheet; } catch (_) { }
            // 兼容：旧“全局搜索”页可能存在当前文件提示；若元素不存在则忽略
            try {
                const el = document.getElementById('gsCurrentFile');
                if (el) el.textContent = mainFile.split('\\').pop().split('/').pop();
            } catch (_) { }
            // 同步保存“文件打开”模块设置（同目录保存 + localStorage 兜底）
            try { saveSettings('fileWizard', collectFileWizardSettings()); } catch (_) { }
            setStatusMessage('已保存文件设置（尚未导入 SQLite）');
            alert('文件设置已保存。\n如需查询/多表关联，请点击【加载到SQLite数据库】完成导入。');
        }

        // 明确动作：加载到 SQLite 数据库（比“保存设置”更直观）
        function loadToSqlite() {
            ensureMainExists();
            const main = window.__fileWizardMain || null;
            const mainFile = main ? (main.filePath || '') : '';
            const mainSheet = main ? (main.sheetName || '') : '';
            if (!mainFile || !mainSheet) { alert('请先选择至少一个源文件，并勾选至少一个工作表，再设定主表。'); return; }

            // 先保存界面状态（文件/工作表/文件分析列表同步；不触发导入）
            try { saveFileSettings(); } catch (e) { console.error(e); }

            const clearBefore = !!document.getElementById('chkClearSqliteBeforeImport')?.checked;
            const writeMode = (window.__importWriteMode || (document.querySelector('input[name="importWriteMode"]:checked')?.value) || 'overwrite');
            window.__importWriteMode = writeMode;
            window.__appendStrategy = (document.getElementById('appendStrategySelect')?.value || window.__appendStrategy || 'append');
            window.__appendKeyColumns = (document.getElementById('appendKeyColumnsInput')?.value || window.__appendKeyColumns || '');
            setDataSourceStatus('准备导入 0%');
            setStatusMessage(clearBefore ? '准备清空并导入 SQLite（主表+副表）...' : '准备导入 SQLite（主表+副表）...');

            // ========= 多表导入（主表 + 副表） =========
            window.__importQueue = [];
            window.__importInProgress = false;
            window.__importCurrent = null;
            window.__sqliteMainTableName = ''; // 重新导入时会刷新

            const mkTableName = (filePath, sheetName) => {
                const base = (filePath || '').split('\\').pop().split('/').pop().replace(/\.[^.]+$/, '');
                return `${base}|${sheetName}`;
            };

            const mainTableName = getCustomTableName(main.sourceId, mainSheet) || mkTableName(mainFile, mainSheet);

            // 1) 先把“主表”放到队列头（确保 _currentMainTableName/字段等按主表建立）
            window.__importQueue.push({
                role: 'main',
                filePath: mainFile,
                worksheetName: mainSheet,
                tableName: mainTableName,
                resetDb: clearBefore,
                append: (!clearBefore && writeMode === 'append'),
                appendMode: window.__appendStrategy || 'append',
                keyColumns: window.__appendKeyColumns || ''
            });

            // 2) 其余所有“已勾选工作表”逐个导入（同文件可选多个工作表）
            (window.__sourceFiles || []).forEach(sf => {
                const fp = sf.filePath || '';
                const selected = Array.isArray(sf.selected) ? sf.selected : [];
                selected.forEach(sheet => {
                    if (!fp || !sheet) return;
                    // 已作为主表的那张跳过（避免重复导入）
                    if (fp === mainFile && sheet === mainSheet) return;
                    const tn = getCustomTableName(sf.id, sheet) || mkTableName(fp, sheet);
                    window.__importQueue.push({
                        role: 'sub',
                        filePath: fp,
                        worksheetName: sheet,
                        tableName: tn,
                        resetDb: false,
                        append: (writeMode === 'append'),
                        appendMode: window.__appendStrategy || 'append',
                        keyColumns: window.__appendKeyColumns || ''
                    });
                });
            });
            // 记录本次导入涉及的表名（用于 Merge 合并生成表）
            try { window.__lastImportTables = window.__importQueue.map(x => x.tableName); } catch (_) { window.__lastImportTables = []; }

            // 导入批次（用于项目中心展示/审计）
            window.__importBatchId = `imp-${new Date().toISOString().replace(/[-:]/g,'').slice(0,15)}`;
            window.__importBatchStart = Date.now();
            window.__importBatchTotal = window.__importQueue.length;
            window.__importBatchImported = 0;

            // 导入前修订点（可选）
            const needRev = !!document.getElementById('chkRevisionPointBeforeImport')?.checked;
            if (needRev && window.__activeSchemeId) {
                window.__pendingImportStart = true;
                try {
                    window.chrome.webview.postMessage({
                        action: 'createRevisionPoint',
                        type: 'import',
                        note: `导入前自动备份（${window.__importBatchId}）`,
                        enableBackup: true
                    });
                    setStatusMessage('正在创建修订点（备份库）...');
                } catch (_) {
                    window.__pendingImportStart = false;
                    startNextImport();
                }
            } else {
                // 启动队列
                startNextImport();
            }

            alert(`已开始加载到 SQLite...\n主表: ${mainSheet}\n副表: ${Math.max(0, window.__importQueue.length - 1)} 张\n导入前清空: ${clearBefore ? '是' : '否'}`);
        }

        // 项目管理：重导单个源文件（只重导该文件已勾选工作表；不清空整个项目库）
        function reimportSourceFile(sourceId) {
            const it = (window.__sourceFiles || []).find(x => x.id === sourceId);
            if (!it || !it.filePath) { alert('请先选择文件'); return; }
            const selected = Array.isArray(it.selected) ? it.selected : [];
            if (!selected.length) { alert('请先勾选至少一个工作表'); return; }
            const isFirst = !(window.__activeSchemeId || '').trim();
            const label = isFirst ? '保存数据库' : '重导数据库';
            if (!confirm(`${label}：将把该源文件已勾选的工作表导入到项目数据库（会先删除对应表再重新导入）。\n并同步保存“源文件关系/主表/显示名”等配置。\n\n是否继续？`)) return;

            (async () => {
                // 关键：确保关系/配置落盘（首次会创建项目并绑定到文件库）
                const ok = await ensureProjectSavedNow('reimport');
                if (!ok) { alert('保存项目失败，已取消导入。'); return; }

                const importMode = window.__globalImportMode || 'text';
                selected.forEach(sheetName => {
                    const tn = (it.tableNameMap && it.tableNameMap[sheetName]) ? String(it.tableNameMap[sheetName]) : mkSqliteTableNameFromFileSheet(it.filePath, sheetName);
                    const isMain = !!(window.__fileWizardMain && window.__fileWizardMain.sourceId === sourceId && window.__fileWizardMain.sheetName === sheetName);
                    window.chrome.webview.postMessage({
                        action: 'importWorksheet',
                        filePath: it.filePath,
                        worksheetName: sheetName,
                        tableName: tn,
                        role: isMain ? 'main' : 'sub',
                        resetDb: false,
                        importMode: importMode,
                        dropExisting: true
                    });
                });
                setStatusMessage('正在导入/重导所选工作表...');
                try { requestProjectList(); } catch (_) { }
            })();
        }

        // 多表导入队列：逐表导入（主表+副表），避免宿主一次性长任务难以跟踪
        function startNextImport() {
            if (!window.chrome || !window.chrome.webview || !window.chrome.webview.postMessage) return;
            window.__importQueue = window.__importQueue || [];
            if (!window.__importQueue.length) {
                window.__importInProgress = false;
                window.__importCurrent = null;
                setStatusMessage('SQLite 导入队列已完成');
                requestActiveFields();
                // 记录导入批次到 Project Meta（用于项目中心概况/详单）
                try {
                    if (window.__activeSchemeId && window.__importBatchId) {
                        window.chrome.webview.postMessage({
                            action: 'recordImportBatch',
                            batchId: window.__importBatchId,
                            importMode: (window.__globalImportMode || 'text'),
                            clearedBeforeImport: !!document.getElementById('chkClearSqliteBeforeImport')?.checked,
                            importedTables: Number(window.__importBatchTotal || 0)
                        });
                    }
                } catch (_) { }
                return;
            }
            window.__importInProgress = true;
            const task = window.__importQueue.shift();
            window.__importCurrent = task;
            setDataSourceStatus(`准备导入 0%`);
            setStatusMessage(`正在导入：${task.tableName}`);
            window.chrome.webview.postMessage({
                action: 'importWorksheet',
                filePath: task.filePath,
                worksheetName: task.worksheetName,
                tableName: task.tableName,
                role: task.role,
                importMode: window.__globalImportMode || 'text',
                resetDb: !!task.resetDb,
                append: !!task.append,
                appendMode: task.appendMode || (window.__appendStrategy || 'append'),
                keyColumns: task.keyColumns || (window.__appendKeyColumns || '')
            });
        }

        function mergeImportedTables() {
            const dest = (document.getElementById('mergeDestTableName')?.value || '').trim();
            if (!dest) { alert('请输入合并输出表名'); return; }
            const src = Array.isArray(window.__lastImportTables) ? window.__lastImportTables.filter(Boolean) : [];
            if (!src.length) { alert('暂无可合并的来源表（请先完成一次导入）'); return; }
            if (!confirm(`确认合并以下 ${src.length} 张表到【${dest}】？\\n\\n${src.slice(0,15).join('\\n')}${src.length>15?'\\n...':''}`)) return;
            try {
                window.chrome?.webview?.postMessage?.({ action: 'mergeTables', destTable: dest, sourceTables: src, overwrite: true });
                setStatusMessage('正在合并生成表...');
            } catch (_) { }
        }

        // 项目管理导入区：TAB 分层（基础/追加/合并关联）
        function fwIngestTab(key) {
            window.__fwIngestTab = key || 'base';
            ['base','append','merge'].forEach(k => {
                const p = document.getElementById(`fwIngestTab_${k}`);
                if (p) p.style.display = (k === window.__fwIngestTab) ? 'flex' : 'none';
                if (k === 'base' && p) p.style.display = (k === window.__fwIngestTab) ? 'block' : 'none';
                const b = document.getElementById(`fwIngestTabBtn_${k}`);
                if (b) {
                    b.style.background = (k === window.__fwIngestTab) ? 'linear-gradient(180deg,#e7f3ff 0%,#cfe8ff 100%)' : '';
                    b.style.borderColor = (k === window.__fwIngestTab) ? '#69c0ff' : '';
                }
            });
        }

        // 项目管理页：TAB 分页（源文件清单 / 导入操作）
        function fwPage(key) {
            const k = (key === 'import') ? 'import' : 'sources';
            window.__fwPage = k;
            try { localStorage.setItem('fwPage', k); } catch (_) { }
            const p1 = document.getElementById('fwPage_sources');
            const p2 = document.getElementById('fwPage_import');
            if (p1) p1.style.display = (k === 'sources') ? 'block' : 'none';
            if (p2) p2.style.display = (k === 'import') ? 'block' : 'none';
            const b1 = document.getElementById('fwPageBtn_sources');
            const b2 = document.getElementById('fwPageBtn_import');
            if (b1) { b1.style.background = (k === 'sources') ? 'linear-gradient(180deg,#e7f3ff 0%,#cfe8ff 100%)' : ''; b1.style.borderColor = (k === 'sources') ? '#69c0ff' : ''; }
            if (b2) { b2.style.background = (k === 'import') ? 'linear-gradient(180deg,#e7f3ff 0%,#cfe8ff 100%)' : ''; b2.style.borderColor = (k === 'import') ? '#69c0ff' : ''; }
        }
        
        // 全局搜索：保存设置
        function saveGlobalSearchSettings() {
            const keyword = document.getElementById('searchKeyword').value;
            const searchAllSheets = document.getElementById('searchAllSheets').checked;
            const searchFieldNames = document.getElementById('searchFieldNames').checked;
            const searchDataContent = document.getElementById('searchDataContent').checked;
            const searchExactMatch = document.getElementById('searchExactMatch').checked;
            const searchOption = document.getElementById('searchOption').value;
            
            // 保存到 localStorage 或发送到后端
            const settings = {
                keyword: keyword,
                searchAllSheets: searchAllSheets,
                searchFieldNames: searchFieldNames,
                searchDataContent: searchDataContent,
                searchExactMatch: searchExactMatch,
                searchOption: searchOption
            };
            
            localStorage.setItem('globalSearchSettings', JSON.stringify(settings));
            alert('全局搜索设置已保存！');
        }
        
        // 全局搜索：执行搜索
        function executeGlobalSearch() {
            if (!ensureSqliteMode('全局搜索')) return;
            const keyword = document.getElementById('searchKeyword').value;
            if (!keyword.trim()) {
                alert('请输入搜索关键词');
                return;
            }
            
            const searchAllSheets = document.getElementById('searchAllSheets').checked;
            const searchFieldNames = document.getElementById('searchFieldNames').checked;
            const searchDataContent = document.getElementById('searchDataContent').checked;
            const searchExactMatch = document.getElementById('searchExactMatch').checked;
            const searchOption = document.getElementById('searchOption').value;
            
            window.chrome.webview.postMessage({
                action: 'executeGlobalSearch',
                keyword: keyword,
                searchAllSheets: searchAllSheets,
                searchFieldNames: searchFieldNames,
                searchDataContent: searchDataContent,
                searchExactMatch: searchExactMatch,
                searchOption: searchOption
            });
        }
        
        // 全局搜索：显示搜索结果
        function showGlobalSearchResults(results) {
            document.getElementById('searchResultCard').style.display = 'block';
            document.getElementById('searchKeywordResult').textContent = results.keyword;
            document.getElementById('searchResultCount').textContent = results.count.toLocaleString();
            
            const tbody = document.getElementById('searchResultBody');
            tbody.innerHTML = '';
            
            if (results.items && results.items.length > 0) {
                results.items.forEach(item => {
                    const tr = document.createElement('tr');
                    tr.innerHTML = `
                        <td>${item.sheetName}</td>
                        <td>${item.fieldName}</td>
                        <td>${item.matchContent}</td>
                        <td>${item.rowNumber}</td>
                        <td>
                            <button class="btn btn-secondary" style="padding: 2px 8px;" onclick="viewSearchResult(${JSON.stringify(item).replace(/"/g, '&quot;')})">查看</button>
                        </td>
                    `;
                    tbody.appendChild(tr);
                });
            } else {
                const tr = document.createElement('tr');
                tr.innerHTML = '<td colspan="5" style="text-align: center; color: #666;">未找到匹配的记录</td>';
                tbody.appendChild(tr);
            }
        }
        
        // 全局搜索：查看搜索结果
        function viewSearchResult(item) {
            alert(`查看详情：\n工作表: ${item.sheetName}\n字段: ${item.fieldName}\n内容: ${item.matchContent}\n行号: ${item.rowNumber}`);
        }
        
        // 初始化
        document.addEventListener('DOMContentLoaded', function() {
            // 项目自动保存：默认开启，可在“项目管理-导入操作”处关闭
            try { initAutoSaveProject(); } catch (_) { }
            // 采样策略：统一默认值，并应用到各模块输入框
            try { initSamplingSettings(); } catch (_) { }
            try { setStatusCurrentOutputMode(window.__outputMode || 'raw'); } catch (_) { }
            try { loadSqlHistoryFromStorage(); updateSqlHistoryList(); } catch (_) { }
            try { loadSqlTemplatesFromStorage(); } catch (_) { }
            // SQL实验室：专家模式开关（本地记忆）
            try {
                const v = localStorage.getItem('sqlLabExpertMode') || '0';
                window.__sqlLabExpertMode = (v === '1');
                window.__sqlLabTxnOpen = false;
                const v2 = localStorage.getItem('sqlLabAllowDangerDdl') || '0';
                window.__sqlLabAllowDangerDdl = (v2 === '1');
                const v3 = localStorage.getItem('sqlExecTimeoutSeconds') || '30';
                window.__sqlExecTimeoutSeconds = Number(v3);
                if (!Number.isFinite(window.__sqlExecTimeoutSeconds)) window.__sqlExecTimeoutSeconds = 30;
                // 重复执行策略
                const v4 = localStorage.getItem('sqlExecStrategy') || 'block';
                window.__sqlExecStrategy = (v4 === 'queue' || v4 === 'cancel_and_run') ? v4 : 'block';
                const chk = document.getElementById('sqlLabExpertMode');
                if (chk) chk.checked = !!window.__sqlLabExpertMode;
                const wrap = document.getElementById('sqlLabDangerDdlWrap');
                if (wrap) wrap.style.display = window.__sqlLabExpertMode ? 'flex' : 'none';
                const chk2 = document.getElementById('sqlLabAllowDangerDdl');
                if (chk2) chk2.checked = (!!window.__sqlLabAllowDangerDdl && !!window.__sqlLabExpertMode);
                const sel = document.getElementById('sqlExecTimeout');
                if (sel) sel.value = String(window.__sqlExecTimeoutSeconds);
                const sel2 = document.getElementById('sqlExecStrategy');
                if (sel2) sel2.value = String(window.__sqlExecStrategy || 'block');
                try { sqlLabUpdateExpertBanner(); } catch (_) { }
            } catch (_) { window.__sqlLabExpertMode = false; window.__sqlLabTxnOpen = false; }
            try { initSqlCodeEditor(); } catch (_) { }
            // UI 缩放：Ctrl + 鼠标滚轮，显示百分比
            try { initUiZoom(); } catch (_) { }
            try { sqlExecSetRunning(false, ''); } catch (_) { }
            try { switchSqlHistoryTab(localStorage.getItem('sqlHistoryTab') || 'history'); } catch (_) { }
            // 差异校验页：默认模式（Excel ↔ Main）
            try { compareApplyCheckMode('excel_vs_main'); } catch (_) { }
            // 透视表：拖拽初始化（字段加载后会自动刷新可用字段）
            try { pivotInitDnD(); } catch (_) { }
            const scanRadios = document.querySelectorAll('input[name="scanScope"]');
            scanRadios.forEach(radio => {
                radio.addEventListener('change', function() {
                    const folderGroup = document.getElementById('folderPathGroup');
                    try {
                        const t = (this.parentElement && this.parentElement.textContent || '').trim();
                        if (folderGroup) folderGroup.style.display = t.includes('指定文件夹') ? 'block' : 'none';
                    } catch (_) { if (folderGroup) folderGroup.style.display = 'none'; }
                });
            });
            
            // 初始化表别名（必须 try/catch：避免异常导致后续初始化中断）
            try { updateTableAliases(); } catch (e) { console.warn('updateTableAliases failed', e); }
            // 初始化“表/视图选择器”（双列下拉 + 搜索）
            try { updateAllTablePickers(); } catch (e) { console.warn('updateAllTablePickers failed', e); }
            // 用户模式：确保页面级别的专家入口也同步
            try { applyUserModeToPages(); } catch (_) { }
            try { refreshSearchDataSources(); } catch (_) { }

            // 初始化文件分析文件列表
            try {
                ensureFileAnalysisState();
                // 默认启动：清理“文件分析”页面的残留（图三：默认页不应出现上一次解析痕迹）
                window.__faFiles = [];
                window.__faQueue = [];
                window.__faAnalyzing = false;
                window.__faBatchMode = false;
                const stats = document.getElementById('fileAnalysisStats');
                const card = document.getElementById('analysisResultCard');
                const body = document.getElementById('sheetListBody');
                if (stats) stats.style.display = 'none';
                if (card) card.style.display = 'none';
                if (body) body.innerHTML = '';
                renderFileAnalysisFileList();
            } catch (e) {
                console.warn('init file-analysis list failed', e);
            }

            // 状态栏时钟
            const clock = document.getElementById('statusClock');
            if (clock) {
                const tick = () => {
                    const d = new Date();
                    const hh = String(d.getHours()).padStart(2, '0');
                    const mm = String(d.getMinutes()).padStart(2, '0');
                    const ss = String(d.getSeconds()).padStart(2, '0');
                    clock.textContent = `${hh}:${mm}:${ss}`;
                };
                tick();
                setInterval(tick, 1000);
            }

            // 点击空白处关闭搜索下载菜单
            document.addEventListener('click', () => {
                try { ['mst','sst','mtjs','gus'].forEach(p => hideSearchDownloadMenu(p)); } catch (_) { }
                try { wsHideQuerySqlMenu(); } catch (_) { }
            });

            // 侧边栏：恢复用户上次停留的模块（默认项目管理）
            try {
                const last = localStorage.getItem('lastSidebarTab') || 'file-wizard';
                if (document.getElementById(last)) switchTab(last);
            } catch (_) { }
        });

        // ===== UI 缩放（Ctrl + 滚轮）=====
        function initUiZoom() {
            // 读取历史缩放
            try {
                const raw = localStorage.getItem('uiZoomFactor') || '';
                const z = raw ? Number(raw) : 1;
                if (Number.isFinite(z) && z > 0.2 && z < 4) applyUiZoom(z, false);
            } catch (_) { }

            // Ctrl + 滚轮缩放
            document.addEventListener('wheel', (e) => {
                try {
                    if (!e.ctrlKey) return;
                    e.preventDefault();
                    const delta = e.deltaY || 0;
                    const cur = Number(window.__uiZoomFactor || 1);
                    const step = 0.1;
                    const next = clampZoom(cur + (delta < 0 ? step : -step));
                    applyUiZoom(next, true);
                } catch (_) { }
            }, { passive: false });
        }

        function clampZoom(z) {
            const v = Math.round(z * 10) / 10;
            return Math.min(2.0, Math.max(0.6, v));
        }

        function applyUiZoom(factor, showToast) {
            const z = clampZoom(Number(factor || 1));
            window.__uiZoomFactor = z;
            // Chrome/WebView2 支持 CSS zoom（比 transform 更稳）
            try { document.body.style.zoom = String(z); } catch (_) { }
            try { localStorage.setItem('uiZoomFactor', String(z)); } catch (_) { }
            // CodeMirror 缩放后需要 refresh
            try { window.__cmSqlEditor?.refresh?.(); } catch (_) { }
            try { Object.values(window.__cmWizardEditors || {}).forEach(cm => { try { cm.refresh(); } catch (_) { } }); } catch (_) { }
            if (showToast) showUiZoomToast(Math.round(z * 100));
        }

        function showUiZoomToast(pct) {
            let el = document.getElementById('uiZoomToast');
            if (!el) {
                el = document.createElement('div');
                el.id = 'uiZoomToast';
                el.style.cssText = 'position:fixed; right:16px; bottom:44px; padding:8px 10px; background:rgba(17,24,39,0.92); color:#fff; border-radius:8px; font-size:9pt; z-index:5000; box-shadow:0 10px 24px rgba(0,0,0,0.25); display:none;';
                document.body.appendChild(el);
            }
            el.textContent = `缩放：${pct}%`;
            el.style.display = 'block';
            try { if (window.__uiZoomToastTimer) clearTimeout(window.__uiZoomToastTimer); } catch (_) { }
            window.__uiZoomToastTimer = setTimeout(() => { try { el.style.display = 'none'; } catch (_) { } }, 800);
        }

        function initAutoSaveProject() {
            const v = (() => { try { return localStorage.getItem('autoSaveProject') || ''; } catch (_) { return ''; } })();
            // 默认：开启
            window.__autoSaveProject = (v === '' || v === '1' || v.toLowerCase() === 'true');
            const chk = document.getElementById('chkAutoSaveProject');
            if (chk) chk.checked = !!window.__autoSaveProject;
        }

        function toggleAutoSaveProject(enabled) {
            window.__autoSaveProject = !!enabled;
            try { localStorage.setItem('autoSaveProject', window.__autoSaveProject ? '1' : '0'); } catch (_) { }
            try { setStatusMessage(window.__autoSaveProject ? '已开启：项目自动保存' : '已关闭：项目自动保存'); } catch (_) { }
        }

        function initSamplingSettings() {
            const defaults = { sampleRows: 50000, maxEnumValues: 200, relMaxPairs: 80, sqliteMetaSampleRowsPerField: 1000 };
            let v = null;
            try { v = localStorage.getItem('samplingSettings') || ''; } catch (_) { v = ''; }
            let obj = null;
            try { obj = v ? JSON.parse(v) : null; } catch (_) { obj = null; }
            window.__samplingSettings = Object.assign({}, defaults, (obj || {}));
            applySamplingSettingsToUi();
        }

        function applySamplingSettingsToUi() {
            const s = window.__samplingSettings || {};
            try { const el = document.getElementById('enumReaderSampleRows'); if (el) el.value = String(s.sampleRows ?? 50000); } catch (_) { }
            try { const el = document.getElementById('enumReaderMaxValues'); if (el) el.value = String(s.maxEnumValues ?? 200); } catch (_) { }
            try { const el = document.getElementById('relSampleRows'); if (el) el.value = String(s.sampleRows ?? 50000); } catch (_) { }
            try { const el = document.getElementById('relMaxPairs'); if (el) el.value = String(s.relMaxPairs ?? 80); } catch (_) { }
        }

        function saveSamplingSettings(newSettings) {
            const defaults = { sampleRows: 50000, maxEnumValues: 200, relMaxPairs: 80, sqliteMetaSampleRowsPerField: 1000 };
            window.__samplingSettings = Object.assign({}, defaults, (newSettings || {}));
            try { localStorage.setItem('samplingSettings', JSON.stringify(window.__samplingSettings)); } catch (_) { }
            applySamplingSettingsToUi();
            try { setStatusMessage('采样设置已保存'); } catch (_) { }
        }

